-- Poems batch 230
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bea14bde-5fe0-4134-88bd-a7b5687c2c8d','普化贊','釋了惠','宋','宋诗','song-poetry','','[]','鐸掩洪鐘，機如掣電。',32,'全唐诗/poet.song.210000.json','["鐸掩洪鐘，機如掣電。", "明頭暗頭，四方八面。", "一著得人憎，走入大悲院。"]'),
('0c9ab671-9900-4ad3-aa39-ebf916f6d2a9','蜆子和尚贊','釋了惠','宋','宋诗','song-poetry','','[]','得恁麽自在，得恁麽快活。',32,'全唐诗/poet.song.210000.json','["得恁麽自在，得恁麽快活。", "古廟當叢林，撈波作衣鉢。", "脚頭到處江天闊。"]'),
('f7b1ddc3-6d16-4f4d-86d7-703a1edf025e','又','釋了惠','宋','宋诗','song-poetry','','[]','赤手立生涯，都盧一箇蝦。',24,'全唐诗/poet.song.210000.json','["赤手立生涯，都盧一箇蝦。", "不從江裏得，樹上摝將來。"]'),
('ddc926a2-12a1-4d72-a0c0-e6507917af70','鄧隠峰贊','釋了惠','宋','宋诗','song-poetry','','[]','金錫一震，虛空退聽。',34,'全唐诗/poet.song.210000.json','["金錫一震，虛空退聽。", "百萬雄兵，難破此陣。", "一時游戲神通，未免旁觀者哂。"]'),
('4e95055f-0f27-4b62-8b6b-f120e7f13e05','五祖送六祖渡江并船子接夾山贊','釋了惠','宋','宋诗','song-poetry','','[]','一葉舟離港口，一橈外無可有。',58,'全唐诗/poet.song.210000.json','["一葉舟離港口，一橈外無可有。", "子不知羞，父不覺醜。", "醜惡羞慚，萬年不杇。", "豈不見黄梅路上數株松，带雨含煙，一似朱涇堤畔柳。"]'),
('4e67dd49-818a-48aa-b5b3-7fe47f323886','五祖栽松六祖擔柴贊  其一','釋了惠','宋','宋诗','song-poetry','','[]','恨殺老頭陀，山移恨不磨。',24,'全唐诗/poet.song.210000.json','["恨殺老頭陀，山移恨不磨。", "吾今擔頭重，爲汝種松多。"]'),
('904c15df-7b2f-4481-b9e4-904de0d0740a','五祖栽松六祖擔柴贊  其二','釋了惠','宋','宋诗','song-poetry','','[]','無柄鋤頭，無根松樹。',28,'全唐诗/poet.song.210000.json','["無柄鋤頭，無根松樹。", "萬古風規，一肩荷負。", "至今夜夜黄梅雨。"]'),
('c8ea03fc-2f67-43c2-b6f6-5af7d9656f85','五祖栽松六祖擔柴贊  其三','釋了惠','宋','宋诗','song-poetry','','[]','夯擔不擔柴，通經不識字。',32,'全唐诗/poet.song.210000.json','["夯擔不擔柴，通經不識字。", "新州路上人，中書堂裏事。", "三更月照東禪寺。"]'),
('17e5431a-19e2-4f1d-8c5c-b759fac243ba','船子夾山贊','釋了惠','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一棹綠楊灣，金鱗得處難。',24,'全唐诗/poet.song.210000.json','["一棹綠楊灣，金鱗得處難。", "長江深有恨，不合蹈船翻。"]'),
('2aa9db50-c870-40ec-8f10-0a604830d440','謝三郎贊','釋了惠','宋','宋诗','song-poetry','','[]','笠雨濕蓑烟，頭陀行已圓。',24,'全唐诗/poet.song.210000.json','["笠雨濕蓑烟，頭陀行已圓。", "一橈橫到底，不踏浙江船。"]'),
('4cc6f296-79d0-44ba-89e6-e686e60cb8b4','又','釋了惠','宋','宋诗','song-poetry','','[]','箬笠蓑衣，短篷孤艇。',28,'全唐诗/poet.song.210000.json','["箬笠蓑衣，短篷孤艇。", "四海一鉤，千江隻影。", "不知月在飛猿嶺。"]'),
('04612a08-7e74-4c73-ab3c-e2ecd2490d6f','普化泉大道贊','釋了惠','宋','宋诗','song-poetry','','[]','酒肆屠門，街頭市尾。',60,'全唐诗/poet.song.210000.json','["酒肆屠門，街頭市尾。", "摇破木鐸，無宮商而暗合宮商。", "挑大道漿，雖不醉人而人自醉。", "是則是，我問你，不知郴州城中，何似大悲院裏。"]'),
('8780d6fc-3da2-475a-bfa6-7ae5b4c6d218','靈照女贊  其一','釋了惠','宋','宋诗','song-poetry','','[]','無底籃兒，無柄笊籬。',36,'全唐诗/poet.song.210000.json','["無底籃兒，無柄笊籬。", "閑家潑具，賣與阿誰。", "自對丹霞呈醜拙，至今羞澀畫蛾眉。"]'),
('66b59aee-f7c6-4c0f-aad5-99a1c158ce28','靈照女贊  其二','釋了惠','宋','宋诗','song-poetry','','[]','指點誰家子，將呈潑笊籬。',24,'全唐诗/poet.song.210000.json','["指點誰家子，將呈潑笊籬。", "物輕情意重，不使老爺知。"]'),
('a473bf7f-5aad-4291-8b21-c9ca1cc7c871','四宗風贊','釋了惠','宋','宋诗','song-poetry','','[]','松根石上柳陰邊，三箇癡頑一箇顛。',32,'全唐诗/poet.song.210000.json','["松根石上柳陰邊，三箇癡頑一箇顛。", "總道繫蛇如伏虎，不知跨犢似乘船。"]'),
('70d215e7-ce4a-45d1-b6e9-26d44c039b6e','四宗風贊','釋了惠','宋','宋诗','song-poetry','','[]','白鷺股邊供大嚼，一蹄涔裏鼓波聲。',32,'全唐诗/poet.song.210000.json','["白鷺股邊供大嚼，一蹄涔裏鼓波聲。", "三生更待三生後，未許平田路上行。"]'),
('ff0cf062-7154-483d-b1ca-2b93a2fa8c18','五祖再來贊','釋了惠','宋','宋诗','song-poetry','','[]','前身後身，坐底立底。',36,'全唐诗/poet.song.210000.json','["前身後身，坐底立底。", "半假半真，全非全是。", "只因擡手肆乖張，萬古黄梅如鼎沸。"]'),
('2ed50d20-b0d0-4e71-8a05-0a70e662a8c2','六祖贊','釋了惠','宋','宋诗','song-poetry','','[]','不作樵夫作碓夫，只將脚力驗精粗。',32,'全唐诗/poet.song.210000.json','["不作樵夫作碓夫，只將脚力驗精粗。", "知佗踏著踏不著，和米和糠到鉢盂。"]'),
('d814c09f-0826-4f58-8f69-4174ea318af7','臨濟贊','釋了惠','宋','宋诗','song-poetry','','[]','三玄非玄，三要非要。',38,'全唐诗/poet.song.210000.json','["三玄非玄，三要非要。", "平地起戈矛，虛空剜孔竅。", "誰知未到黄檗山，盡大地人著賊了。"]'),
('51e2f90b-a51a-4a42-a5e5-3440cfff48e7','大慧宏智揖讓圖贊','釋了惠','宋','宋诗','song-poetry','','[]','既不以爵，又不敘齒。',41,'全唐诗/poet.song.210000.json','["既不以爵，又不敘齒。", "何得過謙，讓之不已。", "若謂是臨濟家風，洞上宗旨，笑倒磨光黑交椅。"]'),
('794b9797-167e-4dbb-af62-62ded9a08c6d','佛鑑和尚','釋了惠','宋','宋诗','song-poetry','','[]','靈而不靈，不靈而靈。',52,'全唐诗/poet.song.210000.json','["靈而不靈，不靈而靈。", "鬼不是鬼，神不是神。", "訕謗祖宗之魔孽，惑亂男女之妖精。", "天童一見便生嗔，未必靈巖肯卜鄰。"]'),
('85a54abd-f047-4427-93e2-a62b6de90ea4','捨錢建閣深都寺','釋了惠','宋','宋诗','song-poetry','','[]','非愚非賢，非親非冤。',54,'全唐诗/poet.song.210000.json','["非愚非賢，非親非冤。", "渠不在後，我不在先。", "共行難行道路，欲了未了因緣。", "以松爲誓，後五百年。", "咄，再來不直半文錢。"]'),
('f781bca7-cd70-4021-9e35-f8a2a1b0a002','小師智潮請贊','釋了惠','宋','宋诗','song-poetry','','[]','㑃無討處，强無討處。',43,'全唐诗/poet.song.210000.json','["㑃無討處，强無討處。", "剛道太虛空，純是生鐵鑄。", "人言養子不及父，殊不知揚子江心有箇郭璞墓。"]'),
('075088b3-2e94-4808-bb9e-2c8fafd483d7','小師智廣請贊','釋了惠','宋','宋诗','song-poetry','','[]','澤廣藏山，理能伏豹。',36,'全唐诗/poet.song.210000.json','["澤廣藏山，理能伏豹。", "父既不慈，子亦不孝。", "吉凶影象自分明，不用燒香求卦兆。"]'),
('4c892b0d-d889-4ae8-83e6-a463f5dd6bd6','行堂請贊','釋了惠','宋','宋诗','song-poetry','','[]','髮鬅鬙，貌稜層。',56,'全唐诗/poet.song.210000.json','["髮鬅鬙，貌稜層。", "沒些火種，剛要傳燈。", "破無準之有準，起南能之不能。", "有不會佛法者，許伊是箇師僧。", "恐人無信，立此爲憑。"]'),
('307b980d-6076-4ac4-9531-5939788e1107','山行贊','釋了惠','宋','宋诗','song-poetry','','[]','入火不燎眉，溺水不濕衣。',34,'全唐诗/poet.song.210000.json','["入火不燎眉，溺水不濕衣。", "目前巇嶮，脚下平夷。", "縱移千百步，此節不曾移。"]'),
('4e748ad1-b57c-43ea-8553-cfeed81d15b9','靈峰雪崖長老請贊','釋了惠','宋','宋诗','song-poetry','','[]','老骨檛，惡冤家。',44,'全唐诗/poet.song.210000.json','["老骨檛，惡冤家。", "無面目不聽別人處分，得人憎不堪師位安排。", "衲僧要識渠端的，雪瀑千尋瀉斷崖。"]'),
('f8235814-b627-42ee-ba7c-4af0db2609f2','僊巖海山長老請贊','釋了惠','宋','宋诗','song-poetry','','[]','百煉金色不變，有人要見不得見，有底不願見他面。',51,'全唐诗/poet.song.210000.json','["百煉金色不變，有人要見不得見，有底不願見他面。", "不識腕頭力，多於弦上辨。", "射透海山千萬重，都來一隻蓬蒿箭。"]'),
('37a9b79b-f1cc-4a6c-99a3-963e3fd9ad7b','頌古','釋了惠','宋','宋诗','song-poetry','','[]','雪峯踏者僧不殺，長生扶者僧不起。',32,'全唐诗/poet.song.210000.json','["雪峯踏者僧不殺，長生扶者僧不起。", "可憐一束爛枯藤，狼藉至今愁滿地。"]'),
('eaeb48f9-2bce-43f0-9442-514981a16bc9','句','余玠','宋','宋诗','song-poetry','','[]','老子也曾來伺候，諸公聊復忍須臾。',16,'全唐诗/poet.song.210000.json','["老子也曾來伺候，諸公聊復忍須臾。"]'),
('6ac1377b-558b-4b22-b45d-49f01db55b6b','山行','湯志道','宋','宋诗','song-poetry','','[]','攀藤緣絕壑，野鹿場邊去。',24,'全唐诗/poet.song.210000.json','["攀藤緣絕壑，野鹿場邊去。", "鳥銜山果來，落在鹿眠處。"]'),
('6f513798-dad0-429b-ba72-4e7832f15fd1','梅花  其一','江萬里','宋','宋诗','song-poetry','','[]','草際春回殘雪消，强扶衰病傍溪橋。',32,'全唐诗/poet.song.210000.json','["草際春回殘雪消，强扶衰病傍溪橋。", "東風不管梅花落，自釀新黄染柳條。"]'),
('a667ebac-a1f5-44d5-819a-6c64f9a9ebb9','梅花  其二','江萬里','宋','宋诗','song-poetry','','[]','牀頭周易用心來，舊卷經年病不開。',32,'全唐诗/poet.song.210000.json','["牀頭周易用心來，舊卷經年病不開。", "到得初冬夢顔子，欠伸俄健起尋梅。"]'),
('12a115e1-e433-4fc8-8459-6d3c44d75c08','荷花','江萬里','宋','宋诗','song-poetry','','[]','結亭臨水似舟中，夜雨瀟瀟亂打篷。',32,'全唐诗/poet.song.210000.json','["結亭臨水似舟中，夜雨瀟瀟亂打篷。", "荷葉曉看元不濕，却疑誤聽五更風。"]'),
('fd29b495-ea95-415e-bf42-387cb955c28f','詩退風濤','江萬里','宋','宋诗','song-poetry','','[]','萬里爲官徹底清，舟中行止甚分明。',32,'全唐诗/poet.song.210000.json','["萬里爲官徹底清，舟中行止甚分明。", "如今若有虧心事，一任碧波深處沉。"]'),
('25a8e89e-3d79-42c1-8f41-70dd019a0ad9','道番昜登龍虎','江萬里','宋','宋诗','song-poetry','','[]','瞻彼高山，蒼蒼相繆。',50,'全唐诗/poet.song.210000.json','["瞻彼高山，蒼蒼相繆。", "雲舒霞張，谿谷險幽。", "鳴鶴在樹，猿猱啾啾。", "青松多風，白露已秋。", "仙乎曷去，胡不少留。"]'),
('63edbf70-0a37-48a5-9332-5b70d081fb5d','勸農','江萬里','宋','宋诗','song-poetry','','[]','農豈猶需我勸農，且從人意卜年豐。',64,'全唐诗/poet.song.210000.json','["農豈猶需我勸農，且從人意卜年豐。", "喜聞布穀聲聲急，莫爲催科處處窮。", "父老來前吾語汝，官民相近古遺風。", "欲知太守樂其樂，樂在田家歡笑中。"]'),
('c559ea8f-69f9-4c66-935b-bfb1cd74d626','鍾陵歸舟即事','江萬里','宋','宋诗','song-poetry','','[]','昨日北風今日强，歸船又過斫柴江。',32,'全唐诗/poet.song.210000.json','["昨日北風今日强，歸船又過斫柴江。", "浮槎却被春流誤，挂在沙頭古柳樁。"]'),
('6f8c13cb-afb8-4b4e-9dc1-19f8bf50bb56','龍虎山','江萬里','宋','宋诗','song-poetry','','[]','鑿開風月長生地，占却烟霞不老身。',32,'全唐诗/poet.song.210000.json','["鑿開風月長生地，占却烟霞不老身。", "虛靖當年仙去後，未知丹訣付何人。"]'),
('b84e72cc-f449-43bb-8293-88b7f7ba9238','和瑞雪','江萬里','宋','宋诗','song-poetry','','[]','與天通處在人和，未有人和天薦瘥。',64,'全唐诗/poet.song.210000.json','["與天通處在人和，未有人和天薦瘥。", "消息連朝來玉闕，川原滿眼盡銀河。", "坡書已得歐公體，力士宜尊太白靴。", "人物于今如越雪，欲令慣見不嫌多。"]'),
('8c5b3dff-dfcc-4e9d-8f73-3b410bc68970','辟妖禽吟','江萬里','宋','宋诗','song-poetry','','[]','去國離家路八千，平生不愛半文錢。',32,'全唐诗/poet.song.210000.json','["去國離家路八千，平生不愛半文錢。", "蒼天鑒我無私意，莫使妖禽夜叫冤。"]'),
('e232ae0b-49ca-4712-8458-6f9be91aca04','嘲元宰相','江萬里','宋','宋诗','song-poetry','','[]','釣得金鰲休便休，何須垂上釣魚鈎。',32,'全唐诗/poet.song.210000.json','["釣得金鰲休便休，何須垂上釣魚鈎。", "昨宵試向江頭望，明月蘆花別是秋。"]'),
('c0709d93-1a25-4ef4-9855-87812d4dcf77','朝賀','江萬里','宋','宋诗','song-poetry','','[]','四海衣冠拜九重，聖君在位像飛龍。',32,'全唐诗/poet.song.210000.json','["四海衣冠拜九重，聖君在位像飛龍。", "遥瞻雉扇雙開處，萬歲齊呼瑞氣濃。"]'),
('661b417d-b5ac-4c98-983b-08613fae1c1e','題黄鶴樓','江萬里','宋','宋诗','song-poetry','','[]','黄鶴樓高倚半天，樓中黄鶴去千年。',64,'全唐诗/poet.song.210000.json','["黄鶴樓高倚半天，樓中黄鶴去千年。", "檐楹自是留真境，几席何妨得老仙。", "雲護山光秋駐馬，日籠江影晝停船。", "良工改寫歸圖畫，俯仰令人一慨然。"]'),
('6e8e90b5-7c8d-4675-8235-52b826f2f446','柯山圖','江萬里','宋','宋诗','song-poetry','','[]','柯山千仞鬰嶙峋，喜見丹青寫送人。',64,'全唐诗/poet.song.210000.json','["柯山千仞鬰嶙峋，喜見丹青寫送人。", "洞府無人留永日，神仙有路隔重雲。", "蒼松白石秋容凈，絕壁懸崖曉勢分。", "歸向公庭對真景，却疑人是畫中身。"]'),
('b397aeff-25b4-4366-bbec-697e487ac771','句','江萬里','宋','宋诗','song-poetry','','[]','不忍驟開還驟落，殷勤含蕊待君來。',16,'全唐诗/poet.song.210000.json','["不忍驟開還驟落，殷勤含蕊待君來。"]'),
('7243be80-ce83-4bd6-8fbb-6d2a0ca4bbd3','有所思','高吉','宋','宋诗','song-poetry','','[]','上山采芳桂，不盈一掬金。',48,'全唐诗/poet.song.210000.json','["上山采芳桂，不盈一掬金。", "金色容易變，零落傷我心。", "欲以遺所思，山遥水沈沈。", "微物豈足貴，但感歲月深。"]'),
('7809b9db-65b4-40d3-b750-7e54b03d9d9d','胡不歸二首  其一','高吉','宋','宋诗','song-poetry','','[]','客從暑中來，清風入我戶。',120,'全唐诗/poet.song.210000.json','["客從暑中來，清風入我戶。", "佩带楚蘭香，囊癭湘蘺句。", "一笑忘形骸，百年示肺腑。", "烹鯉喚麴生，勞苦竹深處。", "遠遊焉倀倀，歸夢應栩栩。", "回首白雲飛，下有白髮母。", "白髮不堪剪，兒去定何所。", "頻頻占鵲喜，嗷嗷待烏哺。", "去時萱始華，執手淚如雨。", "萱華幾飄風，月落啼杜宇。"]'),
('5dbc6896-d374-4240-8a64-2ec4082ee9e2','胡不歸二首  其二','高吉','宋','宋诗','song-poetry','','[]','煢煢蕩子妻，空房守幽獨。',48,'全唐诗/poet.song.210000.json','["煢煢蕩子妻，空房守幽獨。", "纏綿心緒長，吞聲忍夜哭。", "背燈耿孤影，香冷雲幕低。", "絕憐屋上烏，替人嗚嗚啼。"]'),
('e8bd9443-dbfb-4b5a-b44d-4b1a9c4c24b3','試長沙胡邦明墨','高吉','宋','宋诗','song-poetry','','[]','墨卿溯源流，甄陶何遠矣。',144,'全唐诗/poet.song.210000.json','["墨卿溯源流，甄陶何遠矣。", "系出五大夫，殺身成人美。", "策勳凌煙閣，繇此著姓氏。", "開國從膠東，裂土封黑水。", "平生好太玄，握手忘汝爾。", "一笑吐奇芬，熏透詩人髓。", "磨礲去圭角，耐久堅莫比。", "朋來自遠方，陶泓管城子。", "傳文章心印，千古盡在是。", "我老久絕交，未忘抄錄耳。", "種樹書一編，養生論盈紙。", "煩卿爲記之，歲晚吾事已。"]'),
('996dcccc-59c1-4c4b-b770-4c721dc42331','秋窗雜興','高吉','宋','宋诗','song-poetry','','[]','月朗衆星稀，天高萬籟息。',48,'全唐诗/poet.song.210000.json','["月朗衆星稀，天高萬籟息。", "草露濕秋蟲，悲悽聲唧唧。", "隔窗聽鳴機，寒光曙猶織。", "微物固催人，尤爲貧女惜。"]'),
('68a929ce-575e-4143-bf0c-cb36e8787255','塞南','高吉','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','塞南月冷烏夜飛，茫茫曠野無枝棲。',104,'全唐诗/poet.song.210000.json','["塞南月冷烏夜飛，茫茫曠野無枝棲。", "防邊夜歌大風起，鐵衣如冰凍不死。", "功成那忍乞愛卿，叫閽已獻龜形綺。", "錢塘江邊烏欲棲，小卿醉軟紅玉肌。", "嚲雲溜簪困未醒，山頭赤烏啄金餠。", "春宵恨不長如年，無情銀漏何濺濺，起來一笑花嫣然。"]'),
('b3d518ae-717a-4a73-a76d-eff4708f0a20','快閣','高吉','宋','宋诗','song-poetry','','[]','不跨揚州鶴，來尋快閣鷗。',48,'全唐诗/poet.song.210000.json','["不跨揚州鶴，來尋快閣鷗。", "澄江依舊月，落木幾番秋。", "山色橫青眼，交情歎白頭。", "一聲何處笛，我欲理歸舟。"]'),
('e84b0d74-84db-4717-8171-8fc354fb0f8d','雨肥','高吉','宋','宋诗','song-poetry','','[]','雨肥蔬解甲，坡暖竹添丁。',48,'全唐诗/poet.song.210000.json','["雨肥蔬解甲，坡暖竹添丁。", "物態俱自得，人癡終不醒。", "獨行寧媿影，真懶遂忘形。", "巢燕歸何晚，柴門風爲扃。"]'),
('f13373ed-bcaf-471f-b3c2-f3f0c47027a6','送客之楚','高吉','宋','宋诗','song-poetry','','[]','嘶騎隨鞭尾，詩囊挂杖頭。',48,'全唐诗/poet.song.210000.json','["嘶騎隨鞭尾，詩囊挂杖頭。", "好風吹客去，落日啟予愁。", "涉水搴沅芷，邀春醉楚樓。", "故人如問訊，雲卧懶如鷗。"]'),
('a0b95536-46be-43e7-b024-814dd4481e04','憶瀟湘故人','高吉','宋','宋诗','song-poetry','','[]','竹好無多箇，江清不覺深。',48,'全唐诗/poet.song.210000.json','["竹好無多箇，江清不覺深。", "餘香隨去蝶，軟語愛幽禽。", "美景翻成恨，經年不寄音。", "長沙一樽酒，得共幾回斟。"]'),
('a59a4953-d52f-4c72-a6f1-36683491a323','覓桂花','高吉','宋','宋诗','song-poetry','','[]','金粟如來佛，拈花微笑時。',48,'全唐诗/poet.song.210000.json','["金粟如來佛，拈花微笑時。", "煩君修月斧，分我占秋枝。", "且約黄香住，莫令青女知。", "夜窗清不寐，剩讀幾篇詩。"]'),
('a7d1cd8b-72af-44bc-9671-117f46a0ee96','庾嶺  其一','高吉','宋','宋诗','song-poetry','','[]','庾公陳迹已悠悠，春到江南天盡頭。',32,'全唐诗/poet.song.210000.json','["庾公陳迹已悠悠，春到江南天盡頭。", "依舊冰花照行客，瘴煙原不犯清流。"]'),
('bdba8044-e45b-4cda-b281-ac3f9b3aa451','庾嶺  其二','高吉','宋','宋诗','song-poetry','','[]','江水悠悠去莫追，箇中造道有深機。',32,'全唐诗/poet.song.210000.json','["江水悠悠去莫追，箇中造道有深機。", "我來豈爲觀魚說，人笑無鈎釣傍磯。"]'),
('dec833e8-e10d-4656-bf40-a7c7cb2d7095','讀淵明傳','高吉','宋','宋诗','song-poetry','','[]','誰爲栖栖魯孔丘，轍環天下果何求。',32,'全唐诗/poet.song.210000.json','["誰爲栖栖魯孔丘，轍環天下果何求。", "愛人學道行吾志，束带何傷見督郵。"]'),
('82248dcd-26e2-44b1-aab6-a547ad9ca168','巫山秀麗爲四川之奇觀其一晴','高吉','宋','宋诗','song-poetry','','[]','巫峽秋深景最幽，山嵐潑翠淡烟浮。',32,'全唐诗/poet.song.210000.json','["巫峽秋深景最幽，山嵐潑翠淡烟浮。", "看來不復成雲雨，空鎖襄王舊日愁。"]'),
('6c42ca73-d019-4b36-80ab-6c6cdeb7f930','墨梅','高吉','宋','宋诗','song-poetry','','[]','識破宮粧色是空，香魂分付與東風。',32,'全唐诗/poet.song.210000.json','["識破宮粧色是空，香魂分付與東風。", "黑雲潑眼催詩急，著我江頭春暗中。"]'),
('b8076e4a-2591-4973-8866-6204bb4b2b26','倦遊','高吉','宋','宋诗','song-poetry','','[]','參透諸方向上機，瘦藤靠壁倦遊時。',32,'全唐诗/poet.song.210000.json','["參透諸方向上機，瘦藤靠壁倦遊時。", "充然有得機之外，口不能言心自知。"]'),
('f06a07b3-d260-42b1-af68-a0961c098b56','題夢筆山','黄從龍','宋','宋诗','song-poetry','','[]','芙蓉幻出畫難成，文藻由來屬俊英。',64,'全唐诗/poet.song.210000.json','["芙蓉幻出畫難成，文藻由來屬俊英。", "五采曾遺當日夢，百年猶有故山名。", "歲寒寥落松筠秀，月夜悲凉猿鶴驚。", "惆悵江淹人去遠，載瞻南浦暮雲橫。"]'),
('af5d663c-ec12-4cfd-83d2-993f79b993db','景靈舊鐘','李知退','宋','宋诗','song-poetry','','[]','思昔祥符日，先皇建景靈。',48,'全唐诗/poet.song.210000.json','["思昔祥符日，先皇建景靈。", "六飛親奠幣，萬國盡來庭。", "睹物知全盛，聞聲識典刑。", "孤臣腸九折，不忍視斯銘。"]'),
('4f59ca8f-82b4-44f1-b69f-ef752535c123','洞霄宮二首  其一','李知退','宋','宋诗','song-poetry','','[]','霽色橫空碧，凉飈透客襟。',48,'全唐诗/poet.song.210000.json','["霽色橫空碧，凉飈透客襟。", "縈迴山九鎖，嶄絕石千尋。", "愛景心雖切，懷賢意更深。", "摩挲舊詩刻，擁鼻獨行吟。"]'),
('caa0ad14-668d-4ecb-9975-5e3adc5da57b','洞霄宮二首  其二','李知退','宋','宋诗','song-poetry','','[]','早已飛昇去，人間不記年。',48,'全唐诗/poet.song.210000.json','["早已飛昇去，人間不記年。", "潛龍猶守衛，飛鼠尚蹁躚。", "烟鎖棲真洞，雲橫撫掌泉。", "徘徊空竟日，令我憶坡仙。"]'),
('1772841a-3b97-4ced-b51a-24fee8569841','昊天道院','李知退','宋','宋诗','song-poetry','','[]','脫屣繁機後，騎鯨到此山。',48,'全唐诗/poet.song.210000.json','["脫屣繁機後，騎鯨到此山。", "一編藏玉笈，千古鎮雪關。", "仙仗今雖遠，龍鱗尚欲攀。", "凝塵橫御榻，拜起涕應潸。"]'),
('3c30e093-8a27-4702-9752-699bdcc4aefb','龍泉山','孟點','宋','宋诗','song-poetry','','[]','汙瀆橫鱣鯨，螻蟻得而制。',264,'全唐诗/poet.song.210000.json','["汙瀆橫鱣鯨，螻蟻得而制。", "所據非所容，悲歎生賈誼。", "吾疑洛陽叟，所見未超詣。", "卷之不能伸，無乃爲形累。", "朅來姚江濱，稽首龍山寺。", "泓澄尺餘水，龍乃于此憇。", "飲之還可小，泥蟠縱兀肆。", "乘時大其用，雲行復雨施。", "出無而入有，莫得窺其際。", "茲龍之爲龍，所以超萬類。", "彼哉橫江鯨，舟楫詫吞噬。", "莫知屈伸理，已大不可細。", "滄溟有時竭，鬐鬛何足恃。", "惟龍神以天，不足以跡泥。", "洪濤再翻播，勺水或游戲。", "江河固所便，岩穴亦可寄。", "深潛若終隠，奮迅倏已逝。", "小大無定名，變化莫擬議。", "吾聞黄面老，法門傳不二。", "細能入無閒，大可周天地。", "芥子納須彌，妙語言下契。", "蟄龍徘徊久，其亦悟此意。"]'),
('bfcfae3a-97a3-4e9a-98ac-c4835682e46c','勸農即事','孟點','宋','宋诗','song-poetry','','[]','阡陌躬行謹邵農，平郊快馬蹴東風。',64,'全唐诗/poet.song.210000.json','["阡陌躬行謹邵農，平郊快馬蹴東風。", "土膏流潤雨初足，花錦暄晴春正中。", "旗陣折旋知路曲，樂聲遞響覺山空。", "長官元是扶犁手，樂與耕夫笑語同。"]'),
('c3f119a8-610b-4178-8bca-8311ff309b6e','題蘇端明書乳泉賦後','尤煓','宋','宋诗','song-poetry','','[]','萬籟既寂，一氣孔神。',40,'全唐诗/poet.song.210000.json','["萬籟既寂，一氣孔神。", "吸彼沆瀣，沃此肺膺。", "至陽之精，天一所生。", "欽哉此詞，展也大成。"]'),
('f3606095-3a62-4d10-b73b-766a2900790d','北山訪僧晚歸','王琮','宋','宋诗','song-poetry','','[]','吟僧山北住，又買過湖船。',48,'全唐诗/poet.song.210000.json','["吟僧山北住，又買過湖船。", "半日得閑話，一生無此緣。", "波光□酒興，竹色带茶烟。", "歸路斜陽裏，徐行聽亂蟬。"]'),
('db9bff1b-4cc8-44d4-8877-1dc437797de3','蓬萊','王琮','宋','宋诗','song-poetry','','[]','一棹三萬里，何修入窈深。',48,'全唐诗/poet.song.210000.json','["一棹三萬里，何修入窈深。", "水痕涵雨意，巖影带秋陰。", "雖愧無仙骨，終能長道心。", "古人殊錯計，空向海中尋。"]'),
('1ab11adb-c657-4dd6-b889-3e4892e74864','讀書樓作','王琮','宋','宋诗','song-poetry','','[]','近來閑過日，幽事頗相關。',48,'全唐诗/poet.song.210000.json','["近來閑過日，幽事頗相關。", "遠樹開晴晝，歸雲當晚山。", "宦情隨處薄，詩稿逐時刪。", "骨若無仙分，何因住此間。"]'),
('d9296083-b151-402a-9e18-4b2fc134970e','哭潘令','王琮','宋','宋诗','song-poetry','','[]','河陽桃李樹，惆悵不逢春。',48,'全唐诗/poet.song.210000.json','["河陽桃李樹，惆悵不逢春。", "官爲吟詩折，家因好客貧。", "故山歸去遠，遺像挂來真。", "誰向江頭哭，共鄉三數人。"]'),
('e00b36cd-6ce1-481c-bad9-0d189230041c','三巖','王琮','宋','宋诗','song-poetry','','[]','閑携一壺酒，來對雪巖斟。',48,'全唐诗/poet.song.210000.json','["閑携一壺酒，來對雪巖斟。", "秋老瀑飛瘦，石寒雲宿深。", "坐無僧共話，行有鶴隨琴。", "此處儘不俗，令人生隠心。"]'),
('27128583-9de6-444b-b0c5-61e6b6954333','題獨醒小亭','王琮','宋','宋诗','song-poetry','','[]','退食多留此，翛然一散襟。',48,'全唐诗/poet.song.210000.json','["退食多留此，翛然一散襟。", "凉從曉來覺，秋向雨中深。", "牆竹侵山色，簷茅雜柳陰。", "有誰能載酒，過我共幽尋。"]'),
('c2f68d17-a022-4ed2-9dc6-c264cc03b03f','挽何耐軒','王琮','宋','宋诗','song-poetry','','[]','調度如儒素，相門中所難。',48,'全唐诗/poet.song.210000.json','["調度如儒素，相門中所難。", "一心唯好佛，半世懶求官。", "星近緹屏落，墳依宰木寒。", "遺恩滿溪麓，魚鳥亦辛酸。"]'),
('12db5146-54f1-4a61-9680-b33d6cc826cf','客裏有懷徐太古','王琮','宋','宋诗','song-poetry','','[]','近來真倦客，怕蹋軟塵紅。',48,'全唐诗/poet.song.210000.json','["近來真倦客，怕蹋軟塵紅。", "獨向一樓坐，靜觀諸境空。", "官河添夜雨，宮樹带秋風。", "還憶能吟者，襟期何日同。"]'),
('929e7df8-2a5a-4827-87e4-17163721016e','與劉天游伯仲夜話霅中戲贈','王琮','宋','宋诗','song-poetry','','[]','水亭新得月，坐對白蘋洲。',48,'全唐诗/poet.song.210000.json','["水亭新得月，坐對白蘋洲。", "共說一夜話，惜無多日留。", "手抄詩許借，口誦呪如流。", "最羨同吟處，對床風雨秋。"]'),
('4643ac76-82e4-430c-858d-befde5959a8c','秋夜有懷醉書十韻','王琮','宋','宋诗','song-poetry','','[]','秋風從何來，颯颯入窗牖。',120,'全唐诗/poet.song.210000.json','["秋風從何來，颯颯入窗牖。", "殘鐙耿不寐，照我客顔厚。", "故園豈不佳，亦頗興懷否。", "黄金桂百樹，碧玉池十畝。", "猿鶴響空山，亭臺映疏柳。", "觥籌雜野蔌，筆硯得佳友。", "愁無彈鵲句，雋有持螯手。", "人生行樂耳，功名有時有。", "點檢屐幾兩，土苴米五斗。", "浩然歸去來，萬事不如酒。"]'),
('8f5d65e0-7b2b-467a-8211-2dc035bfa965','城西即事','王琮','宋','宋诗','song-poetry','','[]','清曉離家去路遥，絕憐寒景太蕭條。',64,'全唐诗/poet.song.210000.json','["清曉離家去路遥，絕憐寒景太蕭條。", "松深漸覺風聲緊，雲動還知雪意銷。", "沙嘴客擔魚種賣，山頭人拾樹枝燒。", "梅華多處誰家酒，斜舞青帘隔小橋。"]'),
('6a0b3494-69f8-4e7b-af18-db3c603a1f36','次韻項君玉','王琮','宋','宋诗','song-poetry','','[]','惠然乘興訪幽棲，細雨冥冥濕杖藜。',64,'全唐诗/poet.song.210000.json','["惠然乘興訪幽棲，細雨冥冥濕杖藜。", "七尺身强於鶴瘦，一生心不向人低。", "日尋靈藥行寒麓，時有新詩付小奚。", "欲解貂金同一醉，酒壚聞只在前溪。"]'),
('00bfc9eb-a421-4687-aac0-9b8298187260','答友人','王琮','宋','宋诗','song-poetry','','[]','秋山曾是共登臨，感慨蘭亭後視今。',64,'全唐诗/poet.song.210000.json','["秋山曾是共登臨，感慨蘭亭後視今。", "炎熱不過能炙手，笑談未必到知心。", "前言衮衮風波去，後約寥寥歲月深。", "室邇豈應人自遠，酒盟詩社要重尋。"]'),
('1f49794f-89fa-4827-aa3a-ac335ecc12c4','京華病中','王琮','宋','宋诗','song-poetry','','[]','自移藥鼎在床頭，桂玉令人分外愁。',64,'全唐诗/poet.song.210000.json','["自移藥鼎在床頭，桂玉令人分外愁。", "因病始知歸計好，雖貧不向俗人謀。", "僧曾带雨來看脈，僕爲傷風懶上樓。", "頼有壁間新買畫，寒燈相對兩山秋。"]'),
('c3f2ae17-3f06-4b06-a9ce-76f6cbcbbc1b','客南徐一首','王琮','宋','宋诗','song-poetry','','[]','秋來客裏幾蹉跎，醉鋏唯堪浩浩歌。',64,'全唐诗/poet.song.210000.json','["秋來客裏幾蹉跎，醉鋏唯堪浩浩歌。", "盛世未應知己少，諸公自是閲人多。", "潮生瓜步風猶急，苔滿浯溪石欠磨。", "憶昔祖生忠憤後，更無一楫是如何。"]'),
('3a39d114-e44b-46f5-8bb2-8a5bc1b9973e','次韻徐獻可兼別重巽','王琮','宋','宋诗','song-poetry','','[]','誰憐范叔戀袍寒，猶有徐卿二子看。',64,'全唐诗/poet.song.210000.json','["誰憐范叔戀袍寒，猶有徐卿二子看。", "大率率中多物忤，相知知到此心難。", "最憐風雪分吟筆，安得江山共倚欄。", "後夜小窗懷素帖，挑燈應憶我同觀。"]'),
('3a1d1b87-057d-40f7-abd4-4b5ad6de6962','代辟客送總卿歸吳','王琮','宋','宋诗','song-poetry','','[]','使星卿月照淮壖，百萬貔貅飽據鞍。',64,'全唐诗/poet.song.210000.json','["使星卿月照淮壖，百萬貔貅飽據鞍。", "出處豈無公論在，規模應有後人看。", "半年水驛衣猶濕，一紙天箋墨未乾。", "事與心違知已異，折梅花別歲之寒。"]'),
('4d2c04a3-b9a2-42dd-9c29-1ec5d6dc6881','鄴中書懷','王琮','宋','宋诗','song-poetry','','[]','苦無官況莫來休，羞見傍人說宦遊。',64,'全唐诗/poet.song.210000.json','["苦無官況莫來休，羞見傍人說宦遊。", "九十日秋蛩共語，兩三夜雨雁供愁。", "腐紅只有虛名在，堅白難將實意酬。", "驛路梅花歸正好，苦無官況莫來休。"]'),
('63341746-39a6-4651-8752-d98eae4031cc','喜趙居父赴班','王琮','宋','宋诗','song-poetry','','[]','西臺自是舊相知，來了爲山一簣虧。',64,'全唐诗/poet.song.210000.json','["西臺自是舊相知，來了爲山一簣虧。", "入幕雖無多日在，改官已是十年遲。", "金閨接武人爭羨，玉牒能文世所奇。", "此去錦鄉纔兩宿，仙茅綠景正堪詩。"]'),
('988e541d-9a66-4440-a21d-a033711cd850','題多景樓','王琮','宋','宋诗','song-poetry','','[]','秋滿闌干晚共憑，殘烟衰草最關情。',32,'全唐诗/poet.song.210000.json','["秋滿闌干晚共憑，殘烟衰草最關情。", "西風吹起江心浪，猶作當時擊楫聲。"]'),
('a638ad1d-4086-42b2-8690-3165195a1227','漢荆王墓','王琮','宋','宋诗','song-poetry','','[]','落落廟碑摹瘞鶴，陰陰宰木宿神鴉。',32,'全唐诗/poet.song.210000.json','["落落廟碑摹瘞鶴，陰陰宰木宿神鴉。", "可憐寶劍凌雲氣，散作金燈滿地花。"]'),
('fab22fd5-7333-4e15-a337-a720306b7922','獨醒午坐','王琮','宋','宋诗','song-poetry','','[]','小槽停溜務廳閑，幕府文書省却難。',32,'全唐诗/poet.song.210000.json','["小槽停溜務廳閑，幕府文書省却難。", "竟日裴回無俗意，祇因竹外有秋山。"]'),
('1c2623fe-8007-46b8-aa1c-c0a3f35be072','旅興','王琮','宋','宋诗','song-poetry','','[]','經年客食向京華，懶對春風祇憶家。',32,'全唐诗/poet.song.210000.json','["經年客食向京華，懶對春風祇憶家。", "覺道近來全俗了，略無一語及梅花。"]'),
('aeedcbd6-e39d-4f24-b06f-60fd7ed59b61','客中從厚祿故人乞米','王琮','宋','宋诗','song-poetry','','[]','范甑欲塵貧亦甚，陶腰未折計何如。',32,'全唐诗/poet.song.210000.json','["范甑欲塵貧亦甚，陶腰未折計何如。", "小窗獨對蕭蕭雨，臨得唐人乞米書。"]'),
('7f5b578f-7ce0-4893-a658-87b82e03e3dc','舟過孤山','王琮','宋','宋诗','song-poetry','','[]','寂寞梅花處士墳，竹圍巖脚一泉深。',32,'全唐诗/poet.song.210000.json','["寂寞梅花處士墳，竹圍巖脚一泉深。", "隃瞻翠輦曾遊處，水鑰年年護綠陰。"]'),
('9d3ef1a6-db85-4421-9e69-406720d2c492','秘省金魚池一首','王琮','宋','宋诗','song-poetry','','[]','落葉闌干小立時，諸公慨想到腰圍。',32,'全唐诗/poet.song.210000.json','["落葉闌干小立時，諸公慨想到腰圍。", "但知官餠堪爲餌，不識人間有釣磯。"]'),
('681fb379-fb61-4538-a3f8-8afaab070b4b','觀潮','王琮','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','旗彩斜飛一命輕，舟人却立萬舟迎。',32,'全唐诗/poet.song.210000.json','["旗彩斜飛一命輕，舟人却立萬舟迎。", "不應當日將軍事，猶到如今氣未平。"]'),
('67d8180e-fb57-487b-833c-70e2fad8d0e8','獻可約遊北山阻雨','王琮','宋','宋诗','song-poetry','','[]','共約湖邊喚短蓬，曉來何事雨兼風。',32,'全唐诗/poet.song.210000.json','["共約湖邊喚短蓬，曉來何事雨兼風。", "山林只合閑人到，不入時官眼界中。"]'),
('1db6d2e6-7e41-445a-80d8-a773b7d01846','立春有懷','王琮','宋','宋诗','song-poetry','','[]','十千呼酒醉長安，猶記年時客裏歡。',32,'全唐诗/poet.song.210000.json','["十千呼酒醉長安，猶記年時客裏歡。", "有約南山南畔去，只挑野菜當春槃。"]'),
('d34a9355-4f55-42da-bc6d-64f0f10dfdfe','京城元夕','王同祖','宋','宋诗','song-poetry','','[]','鼓吹喧喧月色新，天街燈火夜通晨。',32,'全唐诗/poet.song.210000.json','["鼓吹喧喧月色新，天街燈火夜通晨。", "玉皇不賜傳柑宴，散與千門萬戶春。"]'),
('3d1c6d91-b280-4ae7-831b-27b6e74ec44b','湖上  其一','王同祖','宋','宋诗','song-poetry','','[]','長安三月又三日，繡轂狨鞍富貴家。',32,'全唐诗/poet.song.210000.json','["長安三月又三日，繡轂狨鞍富貴家。", "笙鼓喧天蘭棹穩，賣花聲裏夕陽斜。"]'),
('353607f6-4781-469e-bae7-95624fe86c40','湖上  其二','王同祖','宋','宋诗','song-poetry','','[]','偶出城來日未西，百花叢底草萋萋。',32,'全唐诗/poet.song.210000.json','["偶出城來日未西，百花叢底草萋萋。", "游人過盡歸來晚，行遍蘇公十里堤。"]'),
('4933bd79-0878-4407-9fb0-380243d8b6cd','送客','王同祖','宋','宋诗','song-poetry','','[]','千金難買是心知，誰遣相親又語違。',32,'全唐诗/poet.song.210000.json','["千金難買是心知，誰遣相親又語違。", "楊柳若知行客恨，不教飛絮撲春衣。"]'),
('9b44ee54-201c-4103-bc3a-c91d133674db','太乙宮即事  其一','王同祖','宋','宋诗','song-poetry','','[]','金殿重重晝不開，盤窠蒼柏兩行栽。',32,'全唐诗/poet.song.210000.json','["金殿重重晝不開，盤窠蒼柏兩行栽。", "角門東畔瞻宸几，仙仗曾迎翠輦來。"]'),
('0face657-feeb-4abd-85b7-3077634d4300','太乙宮即事  其二','王同祖','宋','宋诗','song-poetry','','[]','綠陰密處著危亭，佳氣葱葱王武林。',32,'全唐诗/poet.song.210000.json','["綠陰密處著危亭，佳氣葱葱王武林。", "一片紅塵飛不入，杜鵑啼處白雲深。"]'),
('ed7a066b-cc93-46fe-82c6-b24ac41f1128','夜步內門','王同祖','宋','宋诗','song-poetry','','[]','靜夜孤燈人未眠，等閑行過內門前。',32,'全唐诗/poet.song.210000.json','["靜夜孤燈人未眠，等閑行過內門前。", "一聲唱徹連珠喏，碧月朱欄綠柳邊。"]'),
('3df238b2-d8dc-49a2-bb3c-7eb1d275f4de','時事感懷  其一','王同祖','宋','宋诗','song-poetry','','[]','壯心如鐵氣填膺，萬里中原尚虜塵。',32,'全唐诗/poet.song.210000.json','["壯心如鐵氣填膺，萬里中原尚虜塵。", "一枕西風兩行淚，封疆誰是死綏人。"]'),
('08e6b1cb-0eb2-449b-9699-916bbf5ece27','時事感懷  其二','王同祖','宋','宋诗','song-poetry','','[]','羽書昨夜下長安，胡騎駸駸犯蜀關。',32,'全唐诗/poet.song.210000.json','["羽書昨夜下長安，胡騎駸駸犯蜀關。", "愁殺閨中年少婦，朝朝空望戍夫還。"]'),
('021c0d5a-b844-4f36-9882-d5077183fd30','時事感懷  其三','王同祖','宋','宋诗','song-poetry','','[]','襄州蹀血荆州亂，千里金湯狐兔憑。',32,'全唐诗/poet.song.210000.json','["襄州蹀血荆州亂，千里金湯狐兔憑。", "未定樊城關羽死，漢民何日見中興。"]'),
('0f8317c7-c95c-4b4e-b10a-03f57dfaed24','時事感懷  其四','王同祖','宋','宋诗','song-poetry','','[]','蜀又交侵淮又危，江湖風浪沸潢池。',32,'全唐诗/poet.song.210000.json','["蜀又交侵淮又危，江湖風浪沸潢池。", "連朝雲氣濃於墨，想是英雄血戰時。"]'),
('5e4eb46f-54c3-4932-9d4b-f5b072e3a030','晚秋','王同祖','宋','宋诗','song-poetry','','[]','世變無窮客恨長，欄干遍倚怕斜陽。',32,'全唐诗/poet.song.210000.json','["世變無窮客恨長，欄干遍倚怕斜陽。", "滿籬黄菊無心看，付與游蜂自在忙。"]'),
('78577f3a-b205-496c-9cae-c67c4e03abd9','明堂觀禮雜詠十三首 尚書省觀涖誓','王同祖','宋','宋诗','song-poetry','','[]','中辛㫝吉建齋壇，宰相前期誓百官。',32,'全唐诗/poet.song.210000.json','["中辛㫝吉建齋壇，宰相前期誓百官。", "尊祖敬宗天子孝，儀文莫作等閑看。"]'),
('2bd0b01b-754d-4bbe-9bb8-01b8bb7248dd','明堂觀禮雜詠十三首 端門觀習肆赦儀 其一','王同祖','宋','宋诗','song-poetry','','[]','百官常服拱端門，丹鳳銜書下九閽。',32,'全唐诗/poet.song.210000.json','["百官常服拱端門，丹鳳銜書下九閽。", "宰相近前宣授了，齊班舞蹈謝君恩。"]'),
('35b51985-99e2-4330-b1b5-5e9f4cfaf975','明堂觀禮雜詠十三首 端門觀習肆赦儀 其二','王同祖','宋','宋诗','song-poetry','','[]','兩邊黄幕護朱簷，中貴當頭候捲簾。',32,'全唐诗/poet.song.210000.json','["兩邊黄幕護朱簷，中貴當頭候捲簾。", "扶起金雞爭搶取，要教天表庶民瞻。"]'),
('d42b5f1f-9d82-46b3-bedb-834e0ba8ecb5','明堂觀禮雜詠十三首 車駕宿太廟','王同祖','宋','宋诗','song-poetry','','[]','金甲重矛兩內臣，階前對立氣英英。',32,'全唐诗/poet.song.210000.json','["金甲重矛兩內臣，階前對立氣英英。", "巡更場內知誰問，聽得傳呼宰相名。"]'),
('a3cde1b4-df59-413d-8fdb-c2668cbdabea','明堂觀禮雜詠十三首 車駕回太廟','王同祖','宋','宋诗','song-poetry','','[]','瑞靄祥雲傍曉開，九重法駕太宮迴。',32,'全唐诗/poet.song.210000.json','["瑞靄祥雲傍曉開，九重法駕太宮迴。", "一聲靜蹕千官肅，衛士傳呼御座來。"]'),
('2c1c74e5-c10b-4262-a908-3de078af5ed0','明堂觀禮雜詠十三首 天街夜步','王同祖','宋','宋诗','song-poetry','','[]','風不停雲月更清，千門繡幕笑歌聲。',32,'全唐诗/poet.song.210000.json','["風不停雲月更清，千門繡幕笑歌聲。", "御營巡檢無拘束，走馬天街夜達明。"]'),
('e8c58779-30c4-4203-ade6-2ecf44449c59','明堂觀禮雜詠十三首 內前','王同祖','宋','宋诗','song-poetry','','[]','青帷朱簴柳陰旁，玉磬金鍾列兩行。',32,'全唐诗/poet.song.210000.json','["青帷朱簴柳陰旁，玉磬金鍾列兩行。", "輦路旋添泥細細，雞竿揭處瑞雲黄。"]'),
('32c2caa6-5c43-4ba1-8d16-1b092b26a1c6','明堂觀禮雜詠十三首 和寧門觀駕','王同祖','宋','宋诗','song-poetry','','[]','星斗中天夜向晨，寸雲不點月華明。',32,'全唐诗/poet.song.210000.json','["星斗中天夜向晨，寸雲不點月華明。", "六飛過盡燈如晝，宮漏遲遲報五更。"]'),
('9b4d4885-b89b-46ab-aba4-a3ebb14efb87','明堂觀禮雜詠十三首 肆赦','王同祖','宋','宋诗','song-poetry','','[]','九重夙夜畏天威，何事晴明一夕非。',32,'全唐诗/poet.song.210000.json','["九重夙夜畏天威，何事晴明一夕非。", "不放明堂大朝賀，盡拋坊樂獨行歸。"]'),
('b9f4343f-eb31-464f-86e4-37865cc3cac1','明堂觀禮雜詠十三首 觀景靈宮恭謝 其一','王同祖','宋','宋诗','song-poetry','','[]','聖皇宗祀懷多福，恭謝回來看带花。',32,'全唐诗/poet.song.210000.json','["聖皇宗祀懷多福，恭謝回來看带花。", "柷敔笙鏞齊合奏，舉頭更見日光華。"]'),
('def8419b-d9a1-42f1-bdb1-a4ca0c446f31','明堂觀禮雜詠十三首 觀景靈宮恭謝 其二','王同祖','宋','宋诗','song-poetry','','[]','膳羞進徹靜無譁，宰執齋宮坐賜茶。',32,'全唐诗/poet.song.210000.json','["膳羞進徹靜無譁，宰執齋宮坐賜茶。", "不比常朝添覆奏，報來除目十餘家。"]'),
('c6a485e6-3820-44c9-b186-67d89a69e6b6','明堂觀禮雜詠十三首 回龍橋望駕 其一','王同祖','宋','宋诗','song-poetry','','[]','回龍橋上望龍顔，毅采英英仰視難。',32,'全唐诗/poet.song.210000.json','["回龍橋上望龍顔，毅采英英仰視難。", "須信吾皇自神武，何憂中國不尊安。"]'),
('4347f655-7ba0-400b-a69e-239b960fb32a','明堂觀禮雜詠十三首 回龍橋望駕 其二','王同祖','宋','宋诗','song-poetry','','[]','兩行衛士錦宮袍，萬歲聲長徹九臯。',32,'全唐诗/poet.song.210000.json','["兩行衛士錦宮袍，萬歲聲長徹九臯。", "過盡羽旄風細細，彩雲不動御爐高。"]'),
('03d22e5b-5ca0-46ed-af03-667a31f800a8','晚秋登樓  其一','王同祖','宋','宋诗','song-poetry','','[]','獨上危樓望落暉，昏鴉歸處遠烟微。',32,'全唐诗/poet.song.210000.json','["獨上危樓望落暉，昏鴉歸處遠烟微。", "湖光洗得秋容凈，爭奈江南雁又飛。"]'),
('8352404f-bc0e-49e8-8302-0e272557106c','晚秋登樓  其二','王同祖','宋','宋诗','song-poetry','','[]','讀罷黄庭倦倚樓，亂雲挾雨過湖頭。',32,'全唐诗/poet.song.210000.json','["讀罷黄庭倦倚樓，亂雲挾雨過湖頭。", "年來無復登臨思，閑撚黄花送暮秋。"]'),
('d25adb22-dd86-4ee8-97fd-a33fac3f761b','觀雨','王同祖','宋','宋诗','song-poetry','','[]','蕭蕭疏雨逐斜風，三兩歸鴉暮靄中。',32,'全唐诗/poet.song.210000.json','["蕭蕭疏雨逐斜風，三兩歸鴉暮靄中。", "看到菊花無可看，一年秋事又成空。"]'),
('3d6b5e8f-7fb4-4c3e-bb32-2fe4054973bd','送劉方石歸旴江  其一','王同祖','宋','宋诗','song-poetry','','[]','歲云暮矣始成行，珍重劉公半月程。',32,'全唐诗/poet.song.210000.json','["歲云暮矣始成行，珍重劉公半月程。", "四海干戈風物改，亂離時節別離輕。"]'),
('9adcea7c-d08d-49da-a128-07efea296e20','送劉方石歸旴江  其二','王同祖','宋','宋诗','song-poetry','','[]','昨日新聞未忍聽，憂時贏得鬢毛星。',32,'全唐诗/poet.song.210000.json','["昨日新聞未忍聽，憂時贏得鬢毛星。", "歸休高卧西江上，祗恐川原草木腥。"]'),
