('b94666cf-e793-4762-84e8-514d57f9f014','與月船周君話別  其二','王同祖','宋','宋诗','song-poetry','','[]','鴨爐烟冷夜窗寒，著盡冬衣尚怯單。',32,'全唐诗/poet.song.210000.json','["鴨爐烟冷夜窗寒，著盡冬衣尚怯單。", "忽憶故人千里別，雁賫芳恨度扶欄。"]'),
('3207bd76-93c7-435f-be21-eb0c6e4e8286','霜風','王同祖','宋','宋诗','song-poetry','','[]','一夜霜風動地寒，塞垣火未報平安。',32,'全唐诗/poet.song.210000.json','["一夜霜風動地寒，塞垣火未報平安。", "嫦娥亦带傷心色，爲照征人尚抱鞍。"]'),
('42f2d971-38db-4048-9015-ca8fa56e258b','夜坐  其一','王同祖','宋','宋诗','song-poetry','','[]','獨對寒燈客夢孤，數聲征雁下平蕪。',32,'全唐诗/poet.song.210000.json','["獨對寒燈客夢孤，數聲征雁下平蕪。", "古今多少難言事，笑指梅花解語無。"]'),
('88ba1d8f-655b-4c4f-879e-4d33e9352b94','夜坐  其二','王同祖','宋','宋诗','song-poetry','','[]','坐到中宵未忍眠，祗今身世兩茫然。',32,'全唐诗/poet.song.210000.json','["坐到中宵未忍眠，祗今身世兩茫然。", "悲歡轉眼俱陳迹，休對寒燈說舊年。"]'),
('718d4578-b1ae-4dbb-9683-9bac73eb779e','寒夜  其一','王同祖','宋','宋诗','song-poetry','','[]','匝地陰風黯淡天，怯寒時候只宜眠。',32,'全唐诗/poet.song.210000.json','["匝地陰風黯淡天，怯寒時候只宜眠。", "氈裘羔酒非吾事，自碾新茶和雪煎。"]'),
('b19a85b0-1c94-41d8-93b4-f834804f721b','寒夜  其二','王同祖','宋','宋诗','song-poetry','','[]','風收雲捲月當天，獨立中庭思悄然。',32,'全唐诗/poet.song.210000.json','["風收雲捲月當天，獨立中庭思悄然。", "市井不知邊塞事，嗚嗚鼓吹樂新年。"]'),
('88df81f5-8fc6-479a-bf0b-72a013f9c8f2','寄詩人  其一','王同祖','宋','宋诗','song-poetry','','[]','憶君夜夜看燈花，暗數歸期未到家。',32,'全唐诗/poet.song.210000.json','["憶君夜夜看燈花，暗數歸期未到家。", "兒女團欒生計足，還知邊塞走胡沙。"]'),
('f5940a78-ab00-4f2f-b89f-21311f54631a','寄詩人  其二','王同祖','宋','宋诗','song-poetry','','[]','恰回午枕自華胥，忽得周郎一紙書。',32,'全唐诗/poet.song.210000.json','["恰回午枕自華胥，忽得周郎一紙書。", "江上春風能幾日，莫教門外柳蕭疏。"]'),
('d68d8308-c9ac-4370-b45b-ba7cbe404b40','觀錫宴宣勸','王同祖','宋','宋诗','song-poetry','','[]','中使傳宣內裏來，輔臣拜飲九霞杯。',32,'全唐诗/poet.song.210000.json','["中使傳宣內裏來，輔臣拜飲九霞杯。", "君王萬歲三邊靜，壽域先從塞北開。"]'),
('09d5faba-976b-4871-afcc-e63f7e9bd7b9','湖上早行','王同祖','宋','宋诗','song-poetry','','[]','錢塘門外買湖船，霧氣衝雲水接天。',32,'全唐诗/poet.song.210000.json','["錢塘門外買湖船，霧氣衝雲水接天。", "只有蘇堤金線柳，半籠早日半籠烟。"]'),
