('674f1ef8-7535-4832-a522-4e926cc10a8c','春日雜興  其三','王同祖','宋','宋诗','song-poetry','','[]','輕寒漠漠雨霏霏，春院人閑半掩扉。',32,'全唐诗/poet.song.210000.json','["輕寒漠漠雨霏霏，春院人閑半掩扉。", "風力不知多幾許，出門只見杏花飛。"]'),
('b1ebc6c3-f357-46ec-ba25-39d7e2408a99','春日雜興  其四','王同祖','宋','宋诗','song-poetry','','[]','百花時節燕鶯忙，晝日如年懶課香。',32,'全唐诗/poet.song.210000.json','["百花時節燕鶯忙，晝日如年懶課香。", "午枕夢回人悄悄，一聲啼鳥傍斜陽。"]'),
('5bd07185-b03a-47a2-97aa-4917d1e9e8e1','春日雜興  其五','王同祖','宋','宋诗','song-poetry','','[]','清明過了柳花飛，簾外萋萋草正肥。',32,'全唐诗/poet.song.210000.json','["清明過了柳花飛，簾外萋萋草正肥。", "喚起惜春情緒處，空山殘月杜鵑啼。"]'),
('5f6e0dd0-be46-4b9d-9afa-4883237fc5ce','嚴陵舟中','王同祖','宋','宋诗','song-poetry','','[]','萬水千山霽色新，臨風一葦捷於神。',32,'全唐诗/poet.song.210000.json','["萬水千山霽色新，臨風一葦捷於神。", "羊裘灘下休停棹，聞說狂奴解笑人。"]'),
('c6cca2e2-a09c-4757-a074-6aeffbdcb055','郊行  其一','王同祖','宋','宋诗','song-poetry','','[]','牧牛童子坐田頭，摘草簪花兩兩謳。',32,'全唐诗/poet.song.210000.json','["牧牛童子坐田頭，摘草簪花兩兩謳。", "路繞青山山繞澗，殘蟬夕照澹於秋。"]'),
('1ca3be78-e068-4008-84d1-e439a3c6a2ed','郊行  其二','王同祖','宋','宋诗','song-poetry','','[]','火雲散盡晚風凉，曲澗流空草自長。',32,'全唐诗/poet.song.210000.json','["火雲散盡晚風凉，曲澗流空草自長。", "蠶箔成絲秧貼水，數聲布穀爲誰忙。"]'),
('4b1a30b7-a5fa-4ae2-9fc5-d5d1450e7c42','午窗','王同祖','宋','宋诗','song-poetry','','[]','破午幽禽驚客夢，隔窗疏雨喚離愁。',32,'全唐诗/poet.song.210000.json','["破午幽禽驚客夢，隔窗疏雨喚離愁。", "浮雲得喪知何益，早悟莊周蝶夢休。"]'),
('0252fff2-699c-462d-a9e6-638bdcd4c79d','獨行','王同祖','宋','宋诗','song-poetry','','[]','終日長廊獨自行，幻身未信一絲輕。',32,'全唐诗/poet.song.210000.json','["終日長廊獨自行，幻身未信一絲輕。", "自家心緒忡忡急，枉恨鄰牆搗練聲。"]'),
('ec2fd2be-49ce-407e-be10-d2acabe13d92','初秋','王同祖','宋','宋诗','song-poetry','','[]','晚趁凉颸上小樓，忽看梧葉始驚秋。',32,'全唐诗/poet.song.210000.json','["晚趁凉颸上小樓，忽看梧葉始驚秋。", "悲懷無奈狂風雨，數盡歸鴉懶轉頭。"]'),
('0ca4ee21-12d8-4133-bba1-8ad8e38188e1','晚登層樓','王同祖','宋','宋诗','song-poetry','','[]','西風吹我上層樓，千載興亡逝水流。',32,'全唐诗/poet.song.210000.json','["西風吹我上層樓，千載興亡逝水流。", "數點鴉歸江浦晚，一聲雁過塞垣秋。"]'),
('94dab389-cfe2-4609-b069-9281716e7a07','天津橋','王同祖','宋','宋诗','song-poetry','','[]','行闕千重鎖暮烟，山如洛邑水如瀍。',32,'全唐诗/poet.song.210000.json','["行闕千重鎖暮烟，山如洛邑水如瀍。", "黄塵障斷中原路，忍立橋頭聽杜鵑。"]'),
