('5ea64833-02fd-4d03-bb49-5052624f4acd','京口','王同祖','宋','宋诗','song-poetry','','[]','晚風來候過淮舟，閑上南徐多景樓。',32,'全唐诗/poet.song.210000.json','["晚風來候過淮舟，閑上南徐多景樓。", "落日寒城伴荒草，江南人指是瓜洲。"]'),
('5e09ae94-b2eb-418d-a0a4-91e4f25a7e9f','道間晚景','王同祖','宋','宋诗','song-poetry','','[]','斷橋流水涵虛碧，遠岸空山鎖晚青。',32,'全唐诗/poet.song.210000.json','["斷橋流水涵虛碧，遠岸空山鎖晚青。", "勒馬爲看溪畔景，森森古木暗長汀。"]'),
('a6194d72-6d51-4a66-b55e-71aa4978ddbf','題鄭雲谷梅窗  其一','王同祖','宋','宋诗','song-poetry','','[]','匆匆歲月爲誰忙，靜倚梅窗到夕陽。',32,'全唐诗/poet.song.210000.json','["匆匆歲月爲誰忙，靜倚梅窗到夕陽。", "老菊不知秋已去，晚風時送短籬香。"]'),
('883fb829-3b95-458c-92f6-2a9d65df8de0','題鄭雲谷梅窗  其二','王同祖','宋','宋诗','song-poetry','','[]','愛梅來訪小春花，閑卧雲房避俗譁。',32,'全唐诗/poet.song.210000.json','["愛梅來訪小春花，閑卧雲房避俗譁。", "喚醒昏昏塵世夢，旋移石鼎煮新茶。"]'),
('29ac5c11-6f71-409c-abe8-f49f30585538','歲晚雜興  其一','王同祖','宋','宋诗','song-poetry','','[]','撥盡寒灰恨轉添，不知片雪點疏簾。',32,'全唐诗/poet.song.210000.json','["撥盡寒灰恨轉添，不知片雪點疏簾。", "梅花帳冷爐烟歇，架上黄庭信手拈。"]'),
('d1e0fc45-b952-4e33-a8a3-cf5cab0a2c18','歲晚雜興  其二','王同祖','宋','宋诗','song-poetry','','[]','時勢危棋局轉低，丈夫有志竟何爲。',32,'全唐诗/poet.song.210000.json','["時勢危棋局轉低，丈夫有志竟何爲。", "優游輸與田家樂，問著朝廷事不知。"]'),
('d51d6dc3-00a7-464d-9338-b1828255d6d1','歲晚雜興  其三','王同祖','宋','宋诗','song-poetry','','[]','雨雪霏霏歲又除，鯉庭目斷數行書。',32,'全唐诗/poet.song.210000.json','["雨雪霏霏歲又除，鯉庭目斷數行書。", "銷金帳下羊羔酒，便學粗人也不如。"]'),
('dc7967a9-a954-44b2-b4ba-099f69bc23e7','夏日金陵制幕即事  其一','王同祖','宋','宋诗','song-poetry','','[]','五更三點造轅門，了却文書日欲昏。',32,'全唐诗/poet.song.210000.json','["五更三點造轅門，了却文書日欲昏。", "出入戴星吾豈憚，要須一飯不忘恩。"]'),
('7f862b9e-3280-464a-bd22-3a8da397e260','夏日金陵制幕即事  其二','王同祖','宋','宋诗','song-poetry','','[]','早來留得氣清明，吏捧軍書課日程。',32,'全唐诗/poet.song.210000.json','["早來留得氣清明，吏捧軍書課日程。", "秉燭攙先書押了，閑欹凉枕數殘更。"]'),
('e209ce5a-f074-4f15-a1ac-5e30a19206ce','夏日金陵制幕即事  其三','王同祖','宋','宋诗','song-poetry','','[]','荷花池畔竹凉，一枕閑消夏日長。',31,'全唐诗/poet.song.210000.json','["荷花池畔竹凉，一枕閑消夏日長。", "燎過水沉天正午，旋移小艇採蓮房。"]'),
('91b1ef6f-7244-4159-b4bb-09909a410f13','夏日金陵制幕即事  其四','王同祖','宋','宋诗','song-poetry','','[]','幕府人才不在多，同寅難得是恭和。',32,'全唐诗/poet.song.210000.json','["幕府人才不在多，同寅難得是恭和。", "一堂賓主春風裏，剩有工夫到切磋。"]'),
('bcecb025-51fe-4258-8cbb-b6e56026eff6','夏日金陵制幕即事  其五','王同祖','宋','宋诗','song-poetry','','[]','入夏邊烽漸報安，不妨拄笏共觀山。',32,'全唐诗/poet.song.210000.json','["入夏邊烽漸報安，不妨拄笏共觀山。", "西風易把江濤湧，整暇規摹肯放閑。"]'),
('9061eea7-5bcf-4acb-9f8c-3453318e2927','郡圃觀白蓮  其一','王同祖','宋','宋诗','song-poetry','','[]','翠蓋亭亭映玉裳，臨風𢔄彴暗飄香。',32,'全唐诗/poet.song.210000.json','["翠蓋亭亭映玉裳，臨風𢔄彴暗飄香。", "六郎正被繁華困，不愛濃妝愛淡妝。"]'),
('f2d4699d-d2a7-44e9-b318-fcd058987194','郡圃觀白蓮  其二','王同祖','宋','宋诗','song-poetry','','[]','嬌羞處子臨妝後，淡浄佳人出浴時。',32,'全唐诗/poet.song.210000.json','["嬌羞處子臨妝後，淡浄佳人出浴時。", "無語倚欄如有恨，生嫌別岸污臙脂。"]'),
('fafb62da-2480-409f-a0d6-174621e23c3b','郡圃觀白蓮  其三','王同祖','宋','宋诗','song-poetry','','[]','掩晝嬌春歛恨濃，蓮包欲實又成空。',32,'全唐诗/poet.song.210000.json','["掩晝嬌春歛恨濃，蓮包欲實又成空。", "都緣不肯爲雲雨，開落非關一夜風。"]'),
('990aa886-f6b6-4d94-b000-bd6983ac6541','郡圃觀白蓮  其四','王同祖','宋','宋诗','song-poetry','','[]','採菱人散夕陽收，冷落西溪風露頭。',32,'全唐诗/poet.song.210000.json','["採菱人散夕陽收，冷落西溪風露頭。", "飛入白鷗花一色，暗香來處月如鈎。"]'),
('fa3aac89-8d31-40c5-85c1-e361784c209b','郡圃觀白蓮  其五','王同祖','宋','宋诗','song-poetry','','[]','泰華根株本一同，何分白白與紅紅。',32,'全唐诗/poet.song.210000.json','["泰華根株本一同，何分白白與紅紅。", "半池只怕霜風倒，輸與蒼顔百丈松。"]'),
('e127284f-e10c-4582-bdb9-54d35d5667cd','秋日金陵制幕書事  其一','王同祖','宋','宋诗','song-poetry','','[]','幕府秋來事更多，夜深猶自擬諸窠。',32,'全唐诗/poet.song.210000.json','["幕府秋來事更多，夜深猶自擬諸窠。", "平安號火新來急，虜騎連宵已渡河。"]'),
('3a807516-fd9e-4a39-9347-9b5697345db8','秋日金陵制幕書事  其二','王同祖','宋','宋诗','song-poetry','','[]','點盡官軍點到民，三千新遣殿司兵。',32,'全唐诗/poet.song.210000.json','["點盡官軍點到民，三千新遣殿司兵。", "流移更講關防策，預結强丁戍列營。"]'),
('b6d62407-0a44-464c-9d0b-261a931479de','秋日金陵制幕書事  其三','王同祖','宋','宋诗','song-poetry','','[]','哨馬紛紛一水間，渡頭分戍要防姦。',32,'全唐诗/poet.song.210000.json','["哨馬紛紛一水間，渡頭分戍要防姦。", "可憐生計漁舟者，官給旗牌禁往還。"]'),
('705f3e30-ac2a-42a9-b3ea-7677396fd43b','秋日金陵制幕書事  其四','王同祖','宋','宋诗','song-poetry','','[]','元帥謙謙盡下情，麟堂垂晚更延賓。',32,'全唐诗/poet.song.210000.json','["元帥謙謙盡下情，麟堂垂晚更延賓。", "遇風盡是同舟客，肯把秦人視越人。"]'),
('6e3f0612-37c6-45ac-a57a-29284b58ce70','秋日金陵制幕書事  其五','王同祖','宋','宋诗','song-poetry','','[]','明朝玉帳過江邊，騎卒行營一日先。',32,'全唐诗/poet.song.210000.json','["明朝玉帳過江邊，騎卒行營一日先。", "出得公庭天向夜，通宵又散起家錢。"]'),
('8eb2e64a-6732-4d8c-8bc2-79d1118948e3','秋閨  其一','王同祖','宋','宋诗','song-poetry','','[]','西風昨夜到庭梧，曉看窗前一葉無。',32,'全唐诗/poet.song.210000.json','["西風昨夜到庭梧，曉看窗前一葉無。", "秋月照人眠不得，等閑拈弄繡工夫。"]'),
('f0f70a08-6756-4eea-8c3b-85f968221103','秋閨  其二','王同祖','宋','宋诗','song-poetry','','[]','滿目凄凉只自知，閒將心事寄琴徽。',32,'全唐诗/poet.song.210000.json','["滿目凄凉只自知，閒將心事寄琴徽。", "無情梁上雙雙燕，带取秋光一半歸。"]'),
('a30ed948-773d-4af5-9fd8-4bc8beaac50c','秋閨  其三','王同祖','宋','宋诗','song-poetry','','[]','入秋情思可曾忺，深瑣朱扉怯捲簾。',32,'全唐诗/poet.song.210000.json','["入秋情思可曾忺，深瑣朱扉怯捲簾。", "書几無人塵不掃，一鈎蛛網掛牙籤。"]'),
('481c2232-2023-4b1c-8b8d-809ea0d8e86e','秋閨  其四','王同祖','宋','宋诗','song-poetry','','[]','江南賈客去忘歸，撲面邊塵自在飛。',32,'全唐诗/poet.song.210000.json','["江南賈客去忘歸，撲面邊塵自在飛。", "想得那邊寒較早，夜來密地翦征衣。"]'),
('52b10638-649c-4eb3-9837-0a54d2a5914f','秋閨  其五','王同祖','宋','宋诗','song-poetry','','[]','零露瀼瀼夜氣浮，嫩寒差力五更頭。',32,'全唐诗/poet.song.210000.json','["零露瀼瀼夜氣浮，嫩寒差力五更頭。", "鄰雞啼破交加夢，冷浸梧桐月一鈎。"]'),
('165dbfc2-a70a-4d2d-8077-f7df432a115e','冬日金陵制幕書事  其一','王同祖','宋','宋诗','song-poetry','','[]','督制堂堂兩重臣，駐師移府夾江濱。',32,'全唐诗/poet.song.210000.json','["督制堂堂兩重臣，駐師移府夾江濱。", "資糧屝屨多多辦，更有舟車乞與鄰。"]'),
('33f20196-b997-4d9e-8e76-39a8f22c1b07','冬日金陵制幕書事  其二','王同祖','宋','宋诗','song-poetry','','[]','官軍聞說定廬州，破虜功成一滴油。',32,'全唐诗/poet.song.210000.json','["官軍聞說定廬州，破虜功成一滴油。", "智勇功名付元凱，王三錫命到康侯。"]'),
('64ca866f-a768-4068-9e2f-d85b33f7c9bc','冬日金陵制幕書事  其三','王同祖','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','城中守將方投死，陣面將軍已賣降。',32,'全唐诗/poet.song.210000.json','["城中守將方投死，陣面將軍已賣降。", "版築紛紛成底事，那知靠後是長江。"]'),
('5f0c530f-755a-49c8-9e46-00d7aef4d881','冬日金陵制幕書事  其四','王同祖','宋','宋诗','song-poetry','','[]','薄晚官軍得勝歸，家家戶戶掛旌旗。',32,'全唐诗/poet.song.210000.json','["薄晚官軍得勝歸，家家戶戶掛旌旗。", "陣前紀律明於日，師入城來半不知。"]'),
('956d4b09-c282-42c8-8669-51313830837c','冬日金陵制幕書事  其五','王同祖','宋','宋诗','song-poetry','','[]','三五同寮出幕遲，公餘終日意怡怡。',32,'全唐诗/poet.song.210000.json','["三五同寮出幕遲，公餘終日意怡怡。", "歸來又被梅花惱，撥冗銅彝插數枝。"]'),
('883f348c-5aa8-4326-a94e-e4b077afae80','蛾眉亭','周月船','宋','宋诗','song-poetry','','[]','一片沙明萬古秋，半規月印兩眉頭。',32,'全唐诗/poet.song.210000.json','["一片沙明萬古秋，半規月印兩眉頭。", "無人不有關心事，各自看山各自愁。"]'),
('56ea05b7-2464-4181-ba10-948ebe1bbc0d','句','周月船','宋','宋诗','song-poetry','','[]','歸去門前栽柳樹，逢春先綠向陽枝。',16,'全唐诗/poet.song.210000.json','["歸去門前栽柳樹，逢春先綠向陽枝。"]'),
('c555ab1b-5a89-4b50-bb64-a61c406f9ca1','蝴蝶洞','王鐸','宋','宋诗','song-poetry','','[]','莊周已與蝶俱飛，說著遺衣事可疑。',32,'全唐诗/poet.song.210000.json','["莊周已與蝶俱飛，說著遺衣事可疑。", "只怪山中蝴蝶洞，仙家四季總春時。"]'),
('6dbf6dba-f757-41cc-8cca-d2114a9abfcc','自命','上官統','宋','宋诗','song-poetry','','[]','官氏亙古至於今，歷派源流振家聲。',64,'全唐诗/poet.song.210000.json','["官氏亙古至於今，歷派源流振家聲。", "吾今生爾九兄弟，各在一方以安身。", "人人立志守豪富，個個撐持家業均。", "但今囑咐清明節，永世皆臨祭視親。"]'),
('211d10fc-9109-403a-a317-abfa8b92eb5a','題翠蛟亭','李斗南','宋','宋诗','song-poetry','','[]','壯士傳觀山石間，腰頭寶劍祥光吐。',32,'全唐诗/poet.song.210000.json','["壯士傳觀山石間，腰頭寶劍祥光吐。", "摩挲醉眼叱海神，嫌殺蛟龍作妖舞。"]'),
('7d3d36e1-daf6-4ad5-bab3-325583acb806','遊九鎖  其一','劉應子','宋','宋诗','song-poetry','','[]','大滌仙山不易尋，仙人樓閣倚林坰。',64,'全唐诗/poet.song.210000.json','["大滌仙山不易尋，仙人樓閣倚林坰。", "地環九鎖溪爲路，殿合諸峯石作屏。", "落日煙嵐呈紫翠，清秋木石寫丹青。", "我生素負元龍氣，東望滄溟醉眼醒。"]'),
('53b349f6-70bf-4c4b-97f1-d40f87dfa538','遊九鎖  其二','劉應子','宋','宋诗','song-poetry','','[]','憶昔夢中游，高懷悵冥邈。',228,'全唐诗/poet.song.210000.json','["憶昔夢中游，高懷悵冥邈。", "箯輿入山來，精爽欲飛躍。", "九鎖相迴環，羣峯俱卓犖。", "地勝幻蓬萊，天低眇嵩嶽。", "古道矗危亭，斷澗橫略彴。", "流泉翠蛟舞，怪石紫鱗錯。", "坡仙不可見，墨香儼猶昨。", "迤邐跨五洞，解衣小盤礴。", "烟蘿蔓千樹，風松鼓萬壑。", "元放時往來，仙家有真樂。", "石鼓叩即鳴，乳泉甘比酪。", "對此黄花秋，風景良不惡。", "更欲窮絕頂，不憚疲兩脚。", "謝屐隨縱橫，嘉帽任落魄。", "回首日已晡，空山唳猿鶴。", "羽衣坐玄石，呼茗待佳客。", "拂弦寫秋聲，洗琖營晚酌。", "詩成走風雨，鬼神亦驚愕。", "何時了功名，來尋赤松約。"]'),
('11e9f784-1fb7-45fb-aca6-08b9184a0801','隋隄柳','江鉌','宋','宋诗','song-poetry','','[]','錦纜龍舟萬里來，醉鄉繁盛忽塵埃。',32,'全唐诗/poet.song.210000.json','["錦纜龍舟萬里來，醉鄉繁盛忽塵埃。", "空遺兩岸千株柳，雨葉風花作恨媒。"]'),
('466c777f-9979-4627-805f-3e3672d4ce5d','句','劉雪巢','宋','宋诗','song-poetry','','[]','不知何處有唐詩。',8,'全唐诗/poet.song.210000.json','["不知何處有唐詩。"]'),
('48bc62d1-606f-4d55-898d-5fa36c1581ef','小園梅未盡放叔用府教以詩索和勉用韻以謝','魏近思','宋','宋诗','song-poetry','','[]','造化機緘莫恨遲，須知開謝各因時。',64,'全唐诗/poet.song.210000.json','["造化機緘莫恨遲，須知開謝各因時。", "物華未分隨春意，梅蘂先饒露玉肌。", "雪裏精神千萬態，水邊瀟灑兩三枝。", "何當携酒澆花去，且遣詩筒爲報知。"]'),
('4e185a1d-6c7f-463e-a20d-936fe0cef059','染絲上春機','許玠','宋','宋诗','song-poetry','','[]','錦江之水來蜀西，女紅染絲上春機。',126,'全唐诗/poet.song.210000.json','["錦江之水來蜀西，女紅染絲上春機。", "可憐欲織未織時，思君意緒如亂絲。", "亂絲尚可理，妾愁渺無際。", "寒窗軋軋千萬梭，斷魂隨梭暗來去。", "蕩子醉花月，妾辜鸞鏡妝。", "寒蛩只解趣機杼，爭奈情如刀劍傷。", "織成回紋詩，寄與白玉郎。", "願郎勿棄置，上有雙鴛鴦。", "𩕚著雙鴛鴦，忍教孤妾守空房。"]'),
('03e0b6f2-bb28-473d-a5ba-7273a5f87b3d','美人對鏡歌','許玠','宋','宋诗','song-poetry','','[]','天上雄雞啼一聲，人間萬雞相應鳴。',160,'全唐诗/poet.song.210000.json','["天上雄雞啼一聲，人間萬雞相應鳴。", "美人紅酣尚未醒，鎖掣金匙鸚鵡驚。", "鸚鵡從來巧言語，聲聒錦幃殘夢起。", "猛揎羅袖窩綠雲，步逼妝臺趁梳洗。", "玉奩脫覆光爍人，洞房環曲驚曉春。", "不是清空月飛入，如何中有姮娥身。", "軒轅百鍊今湮滅，揚州青銅却奇絕。", "人非照鏡鏡照人，鏡亦分明爲人說。", "媸妍一鏡固兩般，狐婦懷姦心膽寒。", "閨中少女色莊麗，眉頰不妨終日看。"]'),
('66837d6d-5a27-438f-9dfc-7504d9c635df','漢宮春夜','許玠','宋','宋诗','song-poetry','','[]','虛輪絢采千門外，窗眼滲光金箔碎。',96,'全唐诗/poet.song.210000.json','["虛輪絢采千門外，窗眼滲光金箔碎。", "渴龍滴水續銅壺，簷馬呼風摇玉佩。", "宮車聲遠翠幌幽，珠簾閑却珊瑚鈎。", "眉山兩點亦何有，中鎖萬斛相思愁。", "蜀羅蜜炬光明滅，紅淚難濺守宮血。", "遥夜春寒聽曉鐘，角聲滿地梨花雪。"]'),
('ad599a3d-cd06-4c18-867f-baf35fa8a58e','句  其一','許玠','宋','宋诗','song-poetry','','[]','宇宙雙蓬鬢。',6,'全唐诗/poet.song.210000.json','["宇宙雙蓬鬢。"]'),
('c09c9a91-c71b-4675-a6f7-731339b4e9a1','句  其二','許玠','宋','宋诗','song-poetry','','[]','興隨流水遠。',6,'全唐诗/poet.song.210000.json','["興隨流水遠。"]'),
('71928627-2c6f-42c8-bc53-95c8b2174425','句  其三','許玠','宋','宋诗','song-poetry','','[]','立盡疏簾落絮風。',8,'全唐诗/poet.song.210000.json','["立盡疏簾落絮風。"]'),
('76a59bf3-c4f3-43db-9125-31fa5b92ee6d','句  其四','許玠','宋','宋诗','song-poetry','','[]','不辦扁舟訪安道。',8,'全唐诗/poet.song.210000.json','["不辦扁舟訪安道。"]'),
('8e2f1c4c-4766-4730-9174-1fa114862fb0','句  其五','許玠','宋','宋诗','song-poetry','','[]','苔封曲徑無人到。',8,'全唐诗/poet.song.210000.json','["苔封曲徑無人到。"]'),
('3f369c5f-d7ed-4519-bcfb-24f2dd07e3aa','紅莧','史繩祖','宋','宋诗','song-poetry','','[]','易稱紅莧美柔英，夬决窮陰日旅辰。',32,'全唐诗/poet.song.210000.json','["易稱紅莧美柔英，夬决窮陰日旅辰。", "不以色紅爲貴尚，何因赤莧有仙人。"]'),
('14c7abc7-0539-4a1e-bb28-4d38679d284d','巖桂','史繩祖','宋','宋诗','song-poetry','','[]','四出花中異，三開格外芳。',24,'全唐诗/poet.song.210000.json','["四出花中異，三開格外芳。", "名高評月品，韻勝霸秋香。"]'),
('730c39bb-e9af-4a2e-a6c0-305596469151','南樓','劉似祖','宋','宋诗','song-poetry','','[]','雁過危欄字字愁，誰將官柳繫行舟。',64,'全唐诗/poet.song.210000.json','["雁過危欄字字愁，誰將官柳繫行舟。", "不知東去大江水，流出西川第幾州。", "漢上僅遺孤壘在，斗邊忽見數星浮。", "夜深莫問當年事，不是禰衡鸚鵡洲。"]'),
('c9d90a0b-6ab8-4fc1-8327-2c3de0d669c7','病中二首','方左鉞','宋','宋诗','song-poetry','','[]','日費行將典到琴，窮愁那復病相侵。',64,'全唐诗/poet.song.210000.json','["日費行將典到琴，窮愁那復病相侵。", "倩人合藥無真料，就枕吟詩苦見心。", "僕獻奇方單用草，醫言速效莫如參。", "池亭咫尺無由到，空聽蟬聲想綠深。"]'),
('973a9e56-90fa-41d3-83b8-b760fe9fbf2f','海口','方左鉞','宋','宋诗','song-poetry','','[]','家園幾本芙蓉樹，蘂漸紅時又出來。',32,'全唐诗/poet.song.210000.json','["家園幾本芙蓉樹，蘂漸紅時又出來。", "却向秋風山路上，別人池館看花開。"]'),
('54b83acf-0a72-4b73-a71d-3b54ba763af2','忘機','宋伯仁','宋','宋诗','song-poetry','','[]','我以漚爲我，漚爲我即漚。',24,'全唐诗/poet.song.210000.json','["我以漚爲我，漚爲我即漚。", "非漚亦非我，機事兩忘不。"]'),
('b77ee346-78c2-427b-aa10-aadfd2a717ca','漁人','宋伯仁','宋','宋诗','song-poetry','','[]','不求豪富不求官，衣鉢相傳一釣竿。',32,'全唐诗/poet.song.210000.json','["不求豪富不求官，衣鉢相傳一釣竿。", "醉展綠蓑眠便得，滿城風雨自春寒。"]'),
('9dd21d91-8a4c-494c-b212-01396f5e07a1','春晴','宋伯仁','宋','宋诗','song-poetry','','[]','風淡簾櫳花弄影，雨餘池館燕爭泥。',32,'全唐诗/poet.song.210000.json','["風淡簾櫳花弄影，雨餘池館燕爭泥。", "春光去就輕如葉，一任聲聲杜宇啼。"]'),
('52167401-02cf-4654-9bdb-0cd67a17750f','無題','宋伯仁','宋','宋诗','song-poetry','','[]','落花簾箔雨垂垂，重念長亭折柳時。',32,'全唐诗/poet.song.210000.json','["落花簾箔雨垂垂，重念長亭折柳時。", "人在一犂春水外，此情唯有鵓鳩知。"]'),
('308550eb-faac-4000-80e8-dabf7fb866fd','村市','宋伯仁','宋','宋诗','song-poetry','','[]','山暗風屯雨，溪渾水浴沙。',48,'全唐诗/poet.song.210000.json','["山暗風屯雨，溪渾水浴沙。", "小橋通古寺，疎柳納殘鴉。", "苜蓿重沽酒，芝麻旋點茶。", "願人長似舊，歲歲插桃花。"]'),
('5ecf591c-969f-43b3-8647-4c563fc3e805','初夏','宋伯仁','宋','宋诗','song-poetry','','[]','杜宇枝頭雨未乾，曉來猶學夜來寒。',64,'全唐诗/poet.song.210000.json','["杜宇枝頭雨未乾，曉來猶學夜來寒。", "花如舊日全然少，梅亦何心只爾酸。", "世事淺深連酌酒，春光行止一憑闌。", "流鶯默默渾無語，只把遊人冷眼看。"]'),
('0aa50560-94ff-4dd3-b094-f2a6a479e09d','夏日  其一','宋伯仁','宋','宋诗','song-poetry','','[]','滿庭新綠午陰陰，風弄疎簾雨弄晴。',32,'全唐诗/poet.song.210000.json','["滿庭新綠午陰陰，風弄疎簾雨弄晴。", "窗下岸書眠一覺，不知人世有公卿。"]'),
('d0ecbcdb-57e3-44f1-bf2a-4e44387e401e','夏日  其二','宋伯仁','宋','宋诗','song-poetry','','[]','泓泓圓碧漾新荷，獵獵斜風顫綠莎。',32,'全唐诗/poet.song.210000.json','["泓泓圓碧漾新荷，獵獵斜風顫綠莎。", "農事正忙三月後，野田齊唱插秧歌。"]'),
('493811c2-766b-4245-b49e-a65e4c0e7ba6','夏日  其三','宋伯仁','宋','宋诗','song-poetry','','[]','數點沙鷗掠野塘，雨聲初歇水微茫。',32,'全唐诗/poet.song.210000.json','["數點沙鷗掠野塘，雨聲初歇水微茫。", "橋邊十里荷花蕩，輸與漁人卧晚凉。"]'),
('90c3fd31-f2f6-4357-9f7b-64646f5d39fa','寓興','宋伯仁','宋','宋诗','song-poetry','','[]','又近重陽節，傷心事可嗟。',48,'全唐诗/poet.song.210000.json','["又近重陽節，傷心事可嗟。", "塞鴻河洛志，籬菊古今花。", "苦雨牀俱漏，顛風扇莫遮。", "漁船如一葉，快活似儂家。"]'),
('b6535201-d9d0-43d2-ba08-4ff06ce8206b','農家','宋伯仁','宋','宋诗','song-poetry','','[]','茅屋三間槿作籬，白頭婆子葺冬衣。',32,'全唐诗/poet.song.210000.json','["茅屋三間槿作籬，白頭婆子葺冬衣。", "兒童飽飯黄昏後，短笛橫吹喚不歸。"]'),
('489d506b-b6fc-4900-ad77-ca987deee9d6','觀書','宋伯仁','宋','宋诗','song-poetry','','[]','一篝燈影夜窗寒，靜展青編子細看。',32,'全唐诗/poet.song.210000.json','["一篝燈影夜窗寒，靜展青編子細看。", "會得聖賢千古意，不須場屋苦求官。"]'),
('13ab296a-d6b5-4d9a-81a7-1e03cd39ad96','夜坐','宋伯仁','宋','宋诗','song-poetry','','[]','柏香煙裏瀹山茶，窮似燒丹道士家。',32,'全唐诗/poet.song.210000.json','["柏香煙裏瀹山茶，窮似燒丹道士家。", "窗紙漸明寒月上，一肱清夢入梅花。"]'),
('082114bf-223a-4471-8900-6bb48ac51d6f','簡如臯趙買鹽','宋伯仁','宋','宋诗','song-poetry','','[]','傾蓋相逢盡故人，如君喜色更津津。',64,'全唐诗/poet.song.210000.json','["傾蓋相逢盡故人，如君喜色更津津。", "三更雖共金樽月，半日難留玉麈塵。", "淮海浮名徒惹手，田園歸計好謀身。", "何時同醉孤山路，笑撚梅花問早春。"]'),
('15e02aee-076b-4caa-8815-5bb946d5ee80','月夕得友偶集文選古詩句賦感懷一首','宋伯仁','宋','宋诗','song-poetry','','[]','人生寄一世，但傷知音稀。',96,'全唐诗/poet.song.210000.json','["人生寄一世，但傷知音稀。", "明月何皎皎，遊子寒無衣。", "客從遠方來，携手同車歸。", "愁多知夜長，各在天一涯。", "生平不滿百，歲暮一何速。", "冠带自相索，何不策高足。", "還顧望故鄉，冉冉孤生竹。", "含意俱未申，誰能爲此曲。"]'),
('d6e4499b-4704-4386-9fbf-223bce585e6b','秋田小立','宋伯仁','宋','宋诗','song-poetry','','[]','兩間茅屋是誰家，淺水汀洲舞荻花。',32,'全唐诗/poet.song.210000.json','["兩間茅屋是誰家，淺水汀洲舞荻花。", "牧笛數聲紅日晚，自慚身世客天涯。"]'),
('953aa9c5-caa0-4875-86cc-ba7b2ff3c773','寄海安林監鎮','宋伯仁','宋','宋诗','song-poetry','','[]','風摇紅葉下林端，又見長淮九月寒。',64,'全唐诗/poet.song.210000.json','["風摇紅葉下林端，又見長淮九月寒。", "詩草未諧唐律呂，菊花如憶晉衣冠。", "目窮鹺竈煙初息，夢想亭沙雨未乾。", "客宦有緣隨處好，不須來作小場官。"]'),
('642375f4-01ef-4ed5-9386-d11a8451acd3','悶中','宋伯仁','宋','宋诗','song-poetry','','[]','一千里外鬢斑斑，枉被微官奪笑顔。',64,'全唐诗/poet.song.210000.json','["一千里外鬢斑斑，枉被微官奪笑顔。", "酒後稍知寒力退，悶中尤惜世途艱。", "丹砂藥劑寧如健，鐘鼎功名不似閑。", "何日五湖深處住，四窗煙雨納青山。"]'),
('2f0b7a80-6266-4f9f-a004-5bf37938f897','答林行父','宋伯仁','宋','宋诗','song-poetry','','[]','男兒未肯著漁蓑，且把屠龍一劍磨。',64,'全唐诗/poet.song.210000.json','["男兒未肯著漁蓑，且把屠龍一劍磨。", "宣室豈容無賈誼，詞林尚可著廉頗。", "壯懷每被愁懷惱，官况寧如旅况多。", "我欲便歸歸未得，江南孤負採菱歌。"]'),
('a5214def-f8ec-468e-8177-72c3c1ba5820','留春','宋伯仁','宋','宋诗','song-poetry','','[]','春事無多始得晴，江頭纔有麗人行。',32,'全唐诗/poet.song.210000.json','["春事無多始得晴，江頭纔有麗人行。", "柳絲綰住東風脚，落盡桃花去未成。"]'),
('1d63a4bc-49cb-4203-b251-5b8c14996146','苦雨督鹺課甚迫','宋伯仁','宋','宋诗','song-poetry','','[]','僕僕驅馳夢不安，猥哉誰恤買鹺官。',64,'全唐诗/poet.song.210000.json','["僕僕驅馳夢不安，猥哉誰恤買鹺官。", "星臺閣住春來俸，雨意翻成夜半寒。", "可說話人能幾輩，難區處事更多般。", "桃花一日都開了，插滿銅瓶亦倦看。"]'),
('22383f3d-f664-408e-ab03-d4c0dbe680e6','寄舊友二首  其一','宋伯仁','宋','宋诗','song-poetry','','[]','男兒未遇總英雄，漂飯非憐計已窮。',64,'全唐诗/poet.song.210000.json','["男兒未遇總英雄，漂飯非憐計已窮。", "鮑叔但能知管仲，孔明何必拜龐公。", "秋江萍梗人何處，夜月梅花夢亦同。", "借問選詩編幾許，玄暉瀟散漸唐風。"]'),
('b23e3bdc-1052-4e73-8125-ff0966202c40','寄舊友二首  其二','宋伯仁','宋','宋诗','song-poetry','','[]','微官寧得似窮儒，俛首逢迎氣不舒。',64,'全唐诗/poet.song.210000.json','["微官寧得似窮儒，俛首逢迎氣不舒。", "便是伐薪能煮海，何如燒葉自觀書。", "半蓬寒雨苕溪酒，一線西風震澤魚。", "但得此身無繫束，江南有地著頑疎。"]'),
('1ff1f717-065c-4087-ac40-888464a22eff','通新代者書偶作','宋伯仁','宋','宋诗','song-poetry','','[]','庭陰日日杜鵑啼，問我胡爲未賦歸。',64,'全唐诗/poet.song.210000.json','["庭陰日日杜鵑啼，問我胡爲未賦歸。", "官况苦如梅豆小，人情輕似柳綿飛。", "三年獨自知操縱，兩耳從他說是非。", "瓜戍喜催新代者，獃衫應許換征衣。"]'),
('f26c35f1-57d4-4a63-b631-b3c3d7e74a73','秋雨簡劉主簿','宋伯仁','宋','宋诗','song-poetry','','[]','秋到天涯未兩旬，西風無日不霖霪。',64,'全唐诗/poet.song.210000.json','["秋到天涯未兩旬，西風無日不霖霪。", "數行新雁千門曉，十幅輕帆萬里心。", "薄宦只宜聞早去，長淮未許作狂吟。", "江南誰倚闌干曲，丹桂香中酒自斟。"]'),
('f2a8facb-81f7-4200-be79-53e85d9ee27d','寄海安趙路分','宋伯仁','宋','宋诗','song-poetry','','[]','雨濕中秋節，重陽始得晴。',48,'全唐诗/poet.song.210000.json','["雨濕中秋節，重陽始得晴。", "菊花榮辱重，萍梗去留輕。", "詩卷抄無盡，鄉書寫未成。", "鱸魚如釣得，分我一杯羹。"]'),
('7c6dd9db-bc94-4dc0-bd9b-af9f480590f5','拼桑得替題道院','宋伯仁','宋','宋诗','song-poetry','','[]','煮海三年不等閑，幾多歸夢繞青山。',64,'全唐诗/poet.song.210000.json','["煮海三年不等閑，幾多歸夢繞青山。", "鳶肩詩瘦羞郊島，蝸角名虛愧觸蠻。", "戈淅劍炊恬砑耐，雲翻雨覆任癡頑。", "知機人識圓機意，盡在西風一笑間。"]'),
('592d28c3-a0af-4487-86fc-7d7497d81135','歸渡柴墟江口','宋伯仁','宋','宋诗','song-poetry','','[]','白頭浪裏葉舟輕，全靠檣桅寄死生。',32,'全唐诗/poet.song.210000.json','["白頭浪裏葉舟輕，全靠檣桅寄死生。", "唯有青山無一事，不憂風雨不憂晴。"]'),
('21b650dd-2734-4a82-8461-21a8a0c87495','送楊提幹過淮求辟','宋伯仁','宋','宋诗','song-poetry','','[]','功名會底不爲難，莫把登科作等閑。',64,'全唐诗/poet.song.210000.json','["功名會底不爲難，莫把登科作等閑。", "豪傑豈容忘矢石，行藏只要識機關。", "天連芳草千家雨，月照長蘆四面山。", "但是辟書休自嬾，偏親綠鬢已成斑。"]'),
('53c75936-a65c-44a4-ba6b-5537ffd7b1eb','兀坐','宋伯仁','宋','宋诗','song-poetry','','[]','坐對清清一穗香，悄無人語日偏長。',32,'全唐诗/poet.song.210000.json','["坐對清清一穗香，悄無人語日偏長。", "硯盤數點梅花片，暗引遊蜂度粉牆。"]'),
('e9f58779-a309-4ba3-909c-3748ca714ff1','晚凉','宋伯仁','宋','宋诗','song-poetry','','[]','兩兩蟬聲送夕陽，竹陰移綠上藤牀。',32,'全唐诗/poet.song.210000.json','["兩兩蟬聲送夕陽，竹陰移綠上藤牀。", "黄昏急雨無多子，喜得今宵夢亦凉。"]'),
('8f678cb3-3e35-4a0a-a34a-ab945f003457','湖上','宋伯仁','宋','宋诗','song-poetry','','[]','一泓寒玉浸青山，粧點樓臺夕照間。',32,'全唐诗/poet.song.210000.json','["一泓寒玉浸青山，粧點樓臺夕照間。", "歌管滿船春未嬾，惜無人伴白鷗閑。"]'),
('e3f5344f-cea7-4e15-ba42-dfc855afd7ac','都闉遭爇','宋伯仁','宋','宋诗','song-poetry','','[]','融風何事入神州，一掃天衢萬百樓。',64,'全唐诗/poet.song.210000.json','["融風何事入神州，一掃天衢萬百樓。", "莫爲朱門誇炙手，又令赤子嘆焦頭。", "詩人幸有湖山在，壯士難爲富貴謀。", "世事可驚言不盡，得休休處便休休。"]'),
('5c6a9ed2-7ea1-471f-af26-b54717eb7292','贈寫梅者','宋伯仁','宋','宋诗','song-poetry','','[]','學畫梅花又學詩，不須頻說見錢遲。',32,'全唐诗/poet.song.210000.json','["學畫梅花又學詩，不須頻說見錢遲。", "知音自有和羹手，祇恐知音未得知。"]'),
('43304ffa-0126-44bb-8c8a-f261235c550d','寓西馬塍','宋伯仁','宋','宋诗','song-poetry','','[]','十畝荒林屋數間，門通小艇水灣灣。',64,'全唐诗/poet.song.210000.json','["十畝荒林屋數間，門通小艇水灣灣。", "人行遠路多嫌僻，我得安居却稱閑。", "樽酒相忘霜後菊，一詩難盡雨中山。", "何時漾下浮名事，只與田翁剩往還。"]'),
('32626411-c05e-4c98-9b30-b46c5a5658ab','殘菊','宋伯仁','宋','宋诗','song-poetry','','[]','黄華十月愈風流，不把重陽作話頭。',32,'全唐诗/poet.song.210000.json','["黄華十月愈風流，不把重陽作話頭。", "昨夜滿林霜似雪，笑他紅葉冷颼颼。"]'),
('7da71970-5af9-4a03-958d-8f5eae33a3cf','初冬','宋伯仁','宋','宋诗','song-poetry','','[]','過了重陽便作寒，貂裘心事未容安。',64,'全唐诗/poet.song.210000.json','["過了重陽便作寒，貂裘心事未容安。", "貧時侯伯人難識，醉裏乾坤我自寬。", "紅葉已飄千萬點，黄花羞對兩三般。", "小窗破處須頻補，莫放西風正眼看。"]'),
('208a0cfb-8e9e-45a8-8952-f5d031a7167f','西湖晚歸  其一','宋伯仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一輪紅日倚青山，只在湖光數里間。',32,'全唐诗/poet.song.210000.json','["一輪紅日倚青山，只在湖光數里間。", "聽得畫船人說道，錢塘門到夜深關。"]'),
('df1afb31-ab3a-40c0-b408-96552e76b4a3','西湖晚歸  其二','宋伯仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風力尖纖酒力微，重添脫下薄綿衣。',32,'全唐诗/poet.song.210000.json','["風力尖纖酒力微，重添脫下薄綿衣。", "心忙愈覺蘇堤遠，趁得漁船載得歸。"]'),
('272c66f7-2099-4a5a-9fcd-a2b921e1c211','得石刻戲書','宋伯仁','宋','宋诗','song-poetry','','[]','蘭亭墨妙總非真，石鼓遺文字亦湮。',32,'全唐诗/poet.song.210000.json','["蘭亭墨妙總非真，石鼓遺文字亦湮。", "更有斷崖刊詛楚，遼哉千載笑亡秦。"]'),
('6de45ca6-694e-477d-b413-d29e13cc4a2c','觀寺中盂蘭盆會有嘆','宋伯仁','宋','宋诗','song-poetry','','[]','欣欣來認祖先名，梵杵丁東月二更。',32,'全唐诗/poet.song.210000.json','["欣欣來認祖先名，梵杵丁東月二更。", "滿地紙錢香篆冷，更無真哭兩三聲。"]'),
('8dcb2c32-3758-4f7a-a340-60fd629857b9','羊角埂晚行','宋伯仁','宋','宋诗','song-poetry','','[]','葛裙蒲履帽烏紗，迤邐乘凉到水涯。',32,'全唐诗/poet.song.210000.json','["葛裙蒲履帽烏紗，迤邐乘凉到水涯。", "數寺晚鐘聲未歇，滿身明月看荷花。"]'),
('f07f567c-1192-4ecc-a62f-59601148a5e2','別妻','宋伯仁','宋','宋诗','song-poetry','','[]','又買扁舟又客遊，泪痕羞染黑貂裘。',32,'全唐诗/poet.song.210000.json','["又買扁舟又客遊，泪痕羞染黑貂裘。", "西風庭戶從瀟索，莫把黄花當我愁。"]'),
('881ef0b4-3e06-415b-b640-cb8ea65c90ce','村莊即事','宋伯仁','宋','宋诗','song-poetry','','[]','青旗獵獵又村莊，僊景還他是水鄉。',64,'全唐诗/poet.song.210000.json','["青旗獵獵又村莊，僊景還他是水鄉。", "人近七旬頭未白，山無重數葉初黄。", "稻畦明月家家酒，茅屋清歌處處霜。", "滿地菊花秋欲老，客懷牢落愧重陽。"]'),
('cc8a11c4-3356-44fb-806f-f0e4083197af','勉吟者','宋伯仁','宋','宋诗','song-poetry','','[]','詩不窮人窮乃工，蹇馿宜立灞橋風。',32,'全唐诗/poet.song.210000.json','["詩不窮人窮乃工，蹇馿宜立灞橋風。", "安排兩箇推敲字，豈在梨花院落中。"]'),
('b33f44d2-148c-418a-b93e-0943db1330e2','爛溪','宋伯仁','宋','宋诗','song-poetry','','[]','幾家籬落傍溪居，只看青山儘自如。',64,'全唐诗/poet.song.210000.json','["幾家籬落傍溪居，只看青山儘自如。", "隔岸有橋多賣酒，小籃無處不提魚。", "何時茅屋人同住，旋買瓜田雨自鋤。", "寄語牧童休笑我，都緣錯讀半生書。"]'),
('b4969d64-29a9-42b7-b3ae-a8b6dc2317a4','泊船吳江','宋伯仁','宋','宋诗','song-poetry','','[]','垂虹一抹跨晴江，好解帆繩繫矮樁。',32,'全唐诗/poet.song.210000.json','["垂虹一抹跨晴江，好解帆繩繫矮樁。", "水浸碧天天浸月，只消推起小篷窗。"]'),
('8a0b08da-8d85-4cdd-807b-d71e6cb1204c','荷包鮓','宋伯仁','宋','宋诗','song-poetry','','[]','買得荷包酒旋沽，荷包惜不是鱸魚。',32,'全唐诗/poet.song.210000.json','["買得荷包酒旋沽，荷包惜不是鱸魚。", "鱸魚不見張翰輩，自向滄波隠處居。"]'),
('22cd926d-a3c6-43ae-9d63-7dc451ac0a88','吳江四橋','宋伯仁','宋','宋诗','song-poetry','','[]','不獨吳江第四橋，風波處處險如潮。',32,'全唐诗/poet.song.210000.json','["不獨吳江第四橋，風波處處險如潮。", "人心但得平如水，浪自滔天櫓自摇。"]'),
('7e1a164b-f80f-48d4-a5b3-c1e3c99f2b1c','買牋紙','宋伯仁','宋','宋诗','song-poetry','','[]','丁寧黄帽入蘇州，吉利橋邊泊小舟。',32,'全唐诗/poet.song.210000.json','["丁寧黄帽入蘇州，吉利橋邊泊小舟。", "買得吳牋纔可去，詩成免得向人求。"]'),
('7c6e0f70-80ed-47a2-85ae-0bc012502144','西津渡','宋伯仁','宋','宋诗','song-poetry','','[]','掀天雪浪鎮三邊，億萬王師未必然。',32,'全唐诗/poet.song.210000.json','["掀天雪浪鎮三邊，億萬王師未必然。", "可惜大江如舊日，苦無人著祖生鞭。"]'),
('b14552ca-cbf8-4d48-abbe-185b78e1f6fb','登海陵城','宋伯仁','宋','宋诗','song-poetry','','[]','淮楚年年一番秋，西風慣識古譙樓。',64,'全唐诗/poet.song.210000.json','["淮楚年年一番秋，西風慣識古譙樓。", "金湯城壁休清野，玉帳英雄未白頭。", "霜草萬家人冷落，凍雲千疊雁綢繆。", "中原目即難修整，且對屯兵說近愁。"]'),
('3a2a600d-d47a-44ce-b129-f000efbf598b','寄白子元','宋伯仁','宋','宋诗','song-poetry','','[]','一番書滿兩番求，千里重來我更羞。',64,'全唐诗/poet.song.210000.json','["一番書滿兩番求，千里重來我更羞。", "薄世告人難啟口，小官何事不擔憂。", "知心唯有長天月，把酒還思故國秋。", "只待菊花開遍了，半蓑寒雨上輕舟。"]'),
('beb3abd1-3e7e-4651-93ef-01e283a6d7fb','自歎','宋伯仁','宋','宋诗','song-poetry','','[]','又作淮南客，邊塵壓鬢毛。',48,'全唐诗/poet.song.210000.json','["又作淮南客，邊塵壓鬢毛。", "夜長蛩聒聒，家遠雁忉忉。", "把酒天徒問，推篷月正高。", "英雄四方志，休戀故人袍。"]'),
('62a3969d-0696-41ed-875e-dbe9c2606300','聞角','宋伯仁','宋','宋诗','song-poetry','','[]','曉角經秋每厭聽，那堪和月在邊城。',32,'全唐诗/poet.song.210000.json','["曉角經秋每厭聽，那堪和月在邊城。", "從來只說梅花引，未識梅花曲外聲。"]'),
('fa9b0270-2e89-4b42-850a-1ed18df6d28c','別朱冷官','宋伯仁','宋','宋诗','song-poetry','','[]','客中奔走易蹉跎，學館癡留月又過。',64,'全唐诗/poet.song.210000.json','["客中奔走易蹉跎，學館癡留月又過。", "橙蟹醉斟知己重，蓴鱸鄉話憶人多。", "吳陵今夜三更月，霅水明朝一棹歌。", "船在白蘋亭下過，有無傳語曬漁蓑。"]'),
('3de62da7-da1b-42d2-ad48-aca9d8b03e6e','出陸','宋伯仁','宋','宋诗','song-poetry','','[]','吳陵咫尺是惟揚，徒步方知去路長。',64,'全唐诗/poet.song.210000.json','["吳陵咫尺是惟揚，徒步方知去路長。", "漁屋試霜蘆葉老，酒家留客豆花香。", "秋光淺淡人同瘦，雁影參差我共忙。", "僕子莫嗟行李重，擔頭强半舊詩囊。"]'),
('1238663a-2907-4237-8b10-f633cf2dcb9a','揚州騎鶴樓','宋伯仁','宋','宋诗','song-poetry','','[]','醉倚闌干獨黯然，淮南不比數年前。',32,'全唐诗/poet.song.210000.json','["醉倚闌干獨黯然，淮南不比數年前。", "只宜跨鶴翩然去，休說腰纏十萬錢。"]'),
('eb91c93d-6c85-40ac-833c-6dab0b01e8ed','瓊花','宋伯仁','宋','宋诗','song-poetry','','[]','莫訝重栽聚八仙，幾經邊警亦堪憐。',32,'全唐诗/poet.song.210000.json','["莫訝重栽聚八仙，幾經邊警亦堪憐。", "珠簾十里春狼籍，且把天香作舊年。"]'),
('df02930c-65e3-4929-9708-e7e9346053ac','值雨','宋伯仁','宋','宋诗','song-poetry','','[]','吳陵兩月雨留連，來問瓊花雨亦然。',64,'全唐诗/poet.song.210000.json','["吳陵兩月雨留連，來問瓊花雨亦然。", "市酒未銷狂客恨，塞鴻先作嫩寒天。", "只憂松下無三逕，不管囊中欠一錢。", "揚子渡頭風正急，未知何日買歸船。"]'),
('cd42db57-46a8-4d33-8adc-020b37b51ffe','民夫','宋伯仁','宋','宋诗','song-poetry','','[]','閫帥差夫欲太平，浚河纔了又修城。',64,'全唐诗/poet.song.210000.json','["閫帥差夫欲太平，浚河纔了又修城。", "挑泥鍫钁無休日，失業妻兒有嘆聲。", "兩箇布衫寒透骨，半盂蒸飯冷無羹。", "何時一統山河了，只向春田带雨耕。"]'),
('4824de64-fe6c-4436-bb1a-79567612daa5','行色','宋伯仁','宋','宋诗','song-poetry','','[]','擬作惟揚數月留，西風勸我買歸舟。',64,'全唐诗/poet.song.210000.json','["擬作惟揚數月留，西風勸我買歸舟。", "功名得失千年夢，豪傑窮通萬斛愁。", "黄菊已花休戀酒，青山何處不登樓。", "漁翁自倚船篷睡，一任男兒白盡頭。"]'),
('d366d34b-2831-4a2b-9736-2e1fee0250a0','瓜洲阻風','宋伯仁','宋','宋诗','song-poetry','','[]','狂風未許放歸船，借得僧房半榻眠。',64,'全唐诗/poet.song.210000.json','["狂風未許放歸船，借得僧房半榻眠。", "落雁影收帆脚外，怒濤聲到枕頭邊。", "黄蘆葉底秋將老，白羽書中病未痊。", "傳語將軍多著力，揚州不比舊家年。"]'),
('8304db7a-8419-4445-9506-5348d0296191','焦山簡主僧無庵','宋伯仁','宋','宋诗','song-poetry','','[]','輕摇風槳過焦山，山色相留半日閑。',64,'全唐诗/poet.song.210000.json','["輕摇風槳過焦山，山色相留半日閑。", "萬頃月波秋雨後，一篝煙翠夕陽間。", "城依鐵甕心尤壯，酒對金峯鬢惜斑。", "願得淮頭來好語，吸江亭下且怡顔。"]'),
('e399dc8d-c362-4cc2-a92c-ebc77a40c294','邊頭老馬','宋伯仁','宋','宋诗','song-poetry','','[]','解下韁繩便欲眠，絕無筋力可勝鞭。',64,'全唐诗/poet.song.210000.json','["解下韁繩便欲眠，絕無筋力可勝鞭。", "霜蹄遍識淮南地，夜草猶吞塞北煙。", "怕逐綵旗排偃月，寧思金鐙趁朝天。", "華山自有安身處，試問將軍在幾年。"]'),
('cd7c4f53-7915-45bb-b2f0-7969766e592a','夜過烏鎮','宋伯仁','宋','宋诗','song-poetry','','[]','望極模糊古樹林，彎彎溪港似難尋。',64,'全唐诗/poet.song.210000.json','["望極模糊古樹林，彎彎溪港似難尋。", "荻蘆花重霜初下，桑柘陰移月未沉。", "恨別情懷雖戀酒，送衣時節怕聞砧。", "夜行船上山歌意，說盡還家一片心。"]'),
('993ca72e-3c7e-42bc-9180-db2a9e980c6d','家書','宋伯仁','宋','宋诗','song-poetry','','[]','未得還鄉泪欲珠，一書封了又躊躇。',32,'全唐诗/poet.song.210000.json','["未得還鄉泪欲珠，一書封了又躊躇。", "家人會得征夫意，門外西風即是書。"]'),
('9c5c40c2-535e-4a59-9ee9-5603e0e73f7d','看邸報','宋伯仁','宋','宋诗','song-poetry','','[]','朝家日日有遷除，休說人才媿國初。',32,'全唐诗/poet.song.210000.json','["朝家日日有遷除，休說人才媿國初。", "岩穴幾多茅蓋屋，安知不是孔明廬。"]'),
('3d259164-8d9c-4347-acca-caf607a446b3','荷葉浦','宋伯仁','宋','宋诗','song-poetry','','[]','小舡摇蕩水中央，喜得歸程近帝鄉。',64,'全唐诗/poet.song.210000.json','["小舡摇蕩水中央，喜得歸程近帝鄉。", "秋與荻花俱淡薄，地名荷葉素凄凉。", "幾番來往人雖熟，兩月奔波話更長。", "巡檢不知何日滿，一堤衰柳對夕陽。"]'),
('ea0e8313-6445-4b5c-bc54-3ba4e7bdede0','到家','宋伯仁','宋','宋诗','song-poetry','','[]','塵壓征裘滿，今朝喜到家。',48,'全唐诗/poet.song.210000.json','["塵壓征裘滿，今朝喜到家。", "牽衣兒欲泪，滿地菊初花。", "瓦甑添蒸芋，銅鐺旋煮茶。", "安貧儒者事，何必戀天涯。"]'),
('e9aa3d21-1e35-410f-b095-d46bedf40f98','簡張寄翁秀才','宋伯仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','徽外琴聲局外棋，此心能得幾人知。',64,'全唐诗/poet.song.210000.json','["徽外琴聲局外棋，此心能得幾人知。", "縱橫謾說三千字，陶寫須吟百一詩。", "秋到蓼花蟬噪後，雨敲荷葉釣歸時。", "西湖儘著張公子，莫把吟篷月共移。"]'),
('08202a99-6d06-4ef5-b8a9-c4d77ee38048','送馬廿七秀才歸小枯村','宋伯仁','宋','宋诗','song-poetry','','[]','輕輕飛絮撲花枝，喜傍蘭亭說舊詩。',32,'全唐诗/poet.song.210000.json','["輕輕飛絮撲花枝，喜傍蘭亭說舊詩。", "君去小枯應爲我，細看山带晚晴時。"]'),
('f59124cc-ef3c-42d9-87f6-51cf66bae8dd','上安晚先生鄭左相','宋伯仁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','直上昭文便乞閑，貂蟬鬢底未全斑。',64,'全唐诗/poet.song.210000.json','["直上昭文便乞閑，貂蟬鬢底未全斑。", "靜看世事千年後，總在梅花一笑間。", "松菊主賓雖自得，君王休戚暗相關。", "更須正笏巖廊上，整頓皇家若泰山。"]'),
('b7578253-b795-4ee7-aefa-dd860f946baa','題李長嘯漕元賃居','宋伯仁','宋','宋诗','song-poetry','','[]','可種梅花便可居，此身安處即吾廬。',64,'全唐诗/poet.song.210000.json','["可種梅花便可居，此身安處即吾廬。", "胸中丘壑無今古，筆底煙霞自卷舒。", "著脚且堅君子操，知心自有聖人書。", "吾儕幸是苕川客，只好溪頭學釣魚。"]'),
('4d832342-cbbe-439f-8e5a-6f1873566d14','呈菊坡先生陳樞使','宋伯仁','宋','宋诗','song-poetry','','[]','但知猿鶴伴閑居，不覺憂時鬢已疎。',64,'全唐诗/poet.song.210000.json','["但知猿鶴伴閑居，不覺憂時鬢已疎。", "對客怕言今日事，挑燈重讀少年書。", "樓迎山色詩堪畫，門對梅花月共鋤。", "相業累興明主意，先生只恐自躊躇。"]'),
('c0a0435d-bc0a-4a6f-9179-220e743f5daa','和浙東童倉使建昌家圃梅花玉雪亭詩三首  其一','宋伯仁','宋','宋诗','song-poetry','','[]','要識生涯便有涯，暗香叢裏作人家。',32,'全唐诗/poet.song.210000.json','["要識生涯便有涯，暗香叢裏作人家。", "紛紛紅紫休相角，別是春風一樣花。"]'),
('b3c1668d-b46d-4e67-9535-c856b0e61458','和浙東童倉使建昌家圃梅花玉雪亭詩三首  其二','宋伯仁','宋','宋诗','song-poetry','','[]','雲繞疎籬水繞亭，主人清處著梅清。',32,'全唐诗/poet.song.210000.json','["雲繞疎籬水繞亭，主人清處著梅清。", "雖然借得坡翁意，人與梅花更有情。"]'),
('5c8b3d2e-516f-43f9-b435-6ce1cc7c978e','和浙東童倉使建昌家圃梅花玉雪亭詩三首  其三','宋伯仁','宋','宋诗','song-poetry','','[]','黄昏約略酒醒時，塞管何煩特地吹。',32,'全唐诗/poet.song.210000.json','["黄昏約略酒醒時，塞管何煩特地吹。", "是則調羹消息早，不妨留伴月鈎垂。"]'),
('699e9dee-d844-4422-acef-2946e7068158','寄題天台王主簿約牖','宋伯仁','宋','宋诗','song-poetry','','[]','世道巇嶇可厭尋，牖名以約孰知音。',64,'全唐诗/poet.song.210000.json','["世道巇嶇可厭尋，牖名以約孰知音。", "數櫺秋雨千年事，一剔寒篝萬古心。", "山入酒巵青耿耿，風摇槐影綠愔愔。", "坎爻六四君休說，笑拍闌干月滿襟。"]'),
('a68756a5-12f3-4d4e-8253-eb635bf3bdb3','賀游先生再入元樞','宋伯仁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','粵從寶紹歷嘉淳，國事如棋局幾新。',64,'全唐诗/poet.song.210000.json','["粵從寶紹歷嘉淳，國事如棋局幾新。", "欲識萬年占氣脈，須教一著頓精神。", "重臣休憚頭盈雪，赤子咸期屋自春。", "天下倚公心更切，泰山宗社在垂紳。"]'),
('cfd99757-6f27-4f53-9525-b0fbfc2654ef','賀鳳山先生李文昌赴召','宋伯仁','宋','宋诗','song-poetry','','["\u592a\u6e56"]','國老如公僅幾人，豈宜長嘯太湖濱。',64,'全唐诗/poet.song.210000.json','["國老如公僅幾人，豈宜長嘯太湖濱。", "疇咨宰相調元化，詔趣尚書侍紫宸。", "欲振國威千載立，當從局面一番新。", "先生莫作前時看，多少枯根望早春。"]'),
('de514af4-5cf8-43d4-bb06-8c3d89b86ad7','呈可齋先生陳侍郎','宋伯仁','宋','宋诗','song-poetry','','[]','男兒心事少陵詩，不與英雄說又誰。',64,'全唐诗/poet.song.210000.json','["男兒心事少陵詩，不與英雄說又誰。", "衰鬢未甘無用處，壯懷圖見太平時。", "休慚夜雨挑寒灺，喜聽春枰改舊棋。", "一信暖風花萬蕾，孤根應發凍梅枝。"]'),
('fe97d971-12ad-45a8-9681-a5bdf22b1e37','呈留耕先生王侍郎','宋伯仁','宋','宋诗','song-poetry','','[]','夜雨篝燈夢未閑，十年殊愧屋頭山。',64,'全唐诗/poet.song.210000.json','["夜雨篝燈夢未閑，十年殊愧屋頭山。", "喜聞局面棋聲別，不憚吟髭雪樣斑。", "漁釣醉歌人所願，功名心事國相關。", "辟書笑倒梅邊鶴，盡在先生指顧間。"]'),
('44206847-8521-438d-915b-51f8f9416631','賀元樞游先生除右相','宋伯仁','宋','宋诗','song-poetry','','[]','元樞登相未爲奇，奇在先生甚嬾爲。',64,'全唐诗/poet.song.210000.json','["元樞登相未爲奇，奇在先生甚嬾爲。", "四海熙熙今有日，九重眷眷已多時。", "人才豈用拘彝調，邊事常如援拙棋。", "天下兒童頌君實，太平欣卜萬年基。"]'),
('06b017a1-a926-41fd-a0a5-ca253d8bb08e','賀鶴林吳尚書赴召除隆興','宋伯仁','宋','宋诗','song-poetry','','[]','鸞翔芝檢下溪堂，醉夢驚回午正凉。',64,'全唐诗/poet.song.210000.json','["鸞翔芝檢下溪堂，醉夢驚回午正凉。", "寵報帝俞催宰相，且將州紱召文昌。", "蘋花襟袖宮花近，詩草簾櫳諫草香。", "大化一新多吉士，卷阿歷歷告成王。"]'),
('0b5c1794-50e4-4d85-9ac3-fbb7b3f02d54','寄鄭貢父秀才','宋伯仁','宋','宋诗','song-poetry','','[]','至友惜分飛，嘹嘹雁獨知。',48,'全唐诗/poet.song.210000.json','["至友惜分飛，嘹嘹雁獨知。", "想斟新社酒，多讀盛唐詩。", "白髮愁何慮，清貧久却宜。", "曾觀時事否，又是一盤棋。"]'),
('1d6b1866-1306-4b88-beb8-e9d2570d9df2','送廬陵王月窗秀才之武昌謁秋壑賈侍郎','宋伯仁','宋','宋诗','song-poetry','','[]','一緉芒鞋一橐詩，等閑西上欲何之。',64,'全唐诗/poet.song.210000.json','["一緉芒鞋一橐詩，等閑西上欲何之。", "青原山下家雖遠，黄鶴樓前笛未吹。", "秋壑最宜秋到後，月窗當趁月明時。", "問君如見調羹手，說寄梅花寄阿誰。"]'),
('176690db-6c4c-4a4a-b72a-e4a25cf0e6c8','上存耕先生趙大資','宋伯仁','宋','宋诗','song-poetry','','[]','清朝登用舊英耆，聖主憂民展皺眉。',64,'全唐诗/poet.song.210000.json','["清朝登用舊英耆，聖主憂民展皺眉。", "萬寓已綿千歲脈，十年新改一盤棋。", "吟髭雪映堯黄屋，講厦春生漢玉巵。", "補衮日增磐石重，詩人喜見太平時。"]'),
('35efcf79-5d27-40fe-bb6a-4e35ac6a0308','題象山縣棲霞觀應真亭簡住持張羽士  其一','宋伯仁','宋','宋诗','song-poetry','','[]','杜鵑聲裏立東風，山色應憐鬢已蓬。',64,'全唐诗/poet.song.210000.json','["杜鵑聲裏立東風，山色應憐鬢已蓬。", "二麥曉寒新雨後，一年春事落花中。", "醉斟浮蟻邀仙客，笑揖飛鷗問釣翁。", "簷外萬竿君子竹，虛心能得幾人同。"]'),
('45493e0d-7f00-4843-a5ac-e410fa03616c','題象山縣棲霞觀應真亭簡住持張羽士  其二','宋伯仁','宋','宋诗','song-poetry','','[]','萬玉叢中屋四簷，柳花時候笑掀髯。',64,'全唐诗/poet.song.210000.json','["萬玉叢中屋四簷，柳花時候笑掀髯。", "誰將海上山千點，幻作人間畫一縑。", "藥竈未寒丹可煉，春風猶力酒宜添。", "透瓶泉冷無人酌，輸與黄冠自養恬。"]'),
('3ccd9fc6-f28f-4453-b32b-e6039dacc203','寄題臨江玉實齋司戶百花洲','宋伯仁','宋','宋诗','song-poetry','','[]','錦囊詩裏識花洲，何日清江得醉游。',64,'全唐诗/poet.song.210000.json','["錦囊詩裏識花洲，何日清江得醉游。", "百畝故園重餖飣，四賢遺像愈風流。", "香浮紅樹春應早，雪壓寒梅月想留。", "我有煙波魚具了，一絲風底願維舟。"]'),
('ccd0ff11-db36-4c2d-8662-6c69d1b5a172','寄呈東甽先生曹侍郎','宋伯仁','宋','宋诗','song-poetry','','[]','芝書催覲已多時，底事歸班似嬾歸。',64,'全唐诗/poet.song.210000.json','["芝書催覲已多時，底事歸班似嬾歸。", "諸老正緣無定說，先生只得暗知機。", "柳花樽俎春千點，竹屋雲山綠四圍。", "東甽東邊行樂遍，不妨款曲上黄扉。"]'),
('6cfd2cd9-6685-4d11-bf6d-ae496b2e3acc','曹娥謝趙菊莊相訪','宋伯仁','宋','宋诗','song-poetry','','[]','江程潮汛小，沙磧纜行舟。',48,'全唐诗/poet.song.210000.json','["江程潮汛小，沙磧纜行舟。", "挈酒尋詩好，披心話客愁。", "雲歸山欲晚，風急雨如秋。", "可惜相逢處，匆匆不少留。"]'),
('34c13bd9-a774-41c2-9468-d80b688dc99e','寄呈檢正徐侍郎','宋伯仁','宋','宋诗','song-poetry','','[]','紋楸一著響新棋，驚起英雄睡足時。',64,'全唐诗/poet.song.210000.json','["紋楸一著響新棋，驚起英雄睡足時。", "南渡欲恢前漢業，北窗誰戀晚唐詩。", "熬波滄海徒勞爾，舉酒青天欲問之。", "吾道正歸公造化，暖風須到落花枝。"]'),
('ccc96586-9634-4f33-ae52-37b3f382be6f','題智門寺寄住山伊岩玉老  其一','宋伯仁','宋','宋诗','song-poetry','','[]','紫微深處著招提，古蹟名臣事兩奇。',64,'全唐诗/poet.song.210000.json','["紫微深處著招提，古蹟名臣事兩奇。", "宣子畫由高廟治，越王心有孝宗知。", "萬竿玉立春來早，六角池深月上遲。", "禪定十年簾不卷，不知門外幾盤棋。"]'),
('2f6ff701-4a45-452e-aa38-bdc6e026cba3','題智門寺寄住山伊岩玉老  其二','宋伯仁','宋','宋诗','song-poetry','','[]','笋轎衝煙落翠巔，白岩山裏借牀眠。',64,'全唐诗/poet.song.210000.json','["笋轎衝煙落翠巔，白岩山裏借牀眠。", "飽聽溪水雲深處，笑索梅花雪後天。", "幾世世修三世福，萬燈燈是一燈緣。", "吾生誤讀磨崖頌，落得吳霜點鬢邊。"]'),
('376f5e46-8b8a-402c-98cb-85371e2e3847','謝沿海制使顔侍郎舉','宋伯仁','宋','宋诗','song-poetry','','[]','羞把牀頭短鋏彈，弓裘殊媿一絲官。',64,'全唐诗/poet.song.210000.json','["羞把牀頭短鋏彈，弓裘殊媿一絲官。", "但知曉雪侵髭滿，不擬春風著眼看。", "東閤選掄前固有，西班騰踏近尤難。", "先生濃點陶鎔筆，安得梅花月共寒。"]'),
('20c2c20e-104b-4f89-96a4-69fe4d2da0f7','謝浙東趙憲使舉','宋伯仁','宋','宋诗','song-poetry','','[]','未肯歸耕負郭田，舉杯方欲問青天。',64,'全唐诗/poet.song.210000.json','["未肯歸耕負郭田，舉杯方欲問青天。", "鄉心固憶張翰鱠，壯志還思祖逖鞭。", "政化一番新事業，春風千里頼陶甄。", "男兒得遇人知己，願聽雞聲夜不眠。"]'),
('92aa75b4-3da9-465e-8edc-323f952be6d3','贈僧妙源新創寶葉庵','宋伯仁','宋','宋诗','song-poetry','','[]','立錐無地未爲窮，况有三椽似鶴籠。',64,'全唐诗/poet.song.210000.json','["立錐無地未爲窮，况有三椽似鶴籠。", "細納海山聽夜雨，旋栽松竹引秋風。", "詩如東野肩頭瘦，禪與西來鼻孔同。", "他日寺成君記取，維摩牀畫雪岩翁。"]'),
('a55e4e17-5e26-4d29-ae88-52cd317a4ae2','秋風歌上游丞相及臺諫','宋伯仁','宋','宋诗','song-poetry','','[]','噫吁嚱，秋風從天來，一掃酷吏熱。',116,'全唐诗/poet.song.210000.json','["噫吁嚱，秋風從天來，一掃酷吏熱。", "嗷嗷天下心，無復苦炊爇。", "叢叢籬邊花，幽香知素節。", "與花同一嘯，世事花能說。", "前兮酷暑在，擊楫志如鐵。", "豈無如謝安，圍棋聲未歇。", "胸中森甲兵，千里勝自决。", "詩人捫蝨窮，憂時心惙惙。", "歌秋風兮歌國風，問知音兮問豪傑。"]'),
('a1194dba-1214-46f0-8dfb-4c7f53da3ee8','四十','宋伯仁','宋','宋诗','song-poetry','','[]','役役人間世，齊頭四十年。',48,'全唐诗/poet.song.210000.json','["役役人間世，齊頭四十年。", "讀書雖未已，作事亦徒然。", "宦業蕉中鹿，生涯葉底蟬。", "願逢時務好，一榻醉時眠。"]'),
('43ad003d-515d-4fe5-9211-2308bee367f8','寓目  其一','宋伯仁','宋','宋诗','song-poetry','','[]','暖風輕撥繡簾開，放入雙雙紫燕來。',32,'全唐诗/poet.song.210000.json','["暖風輕撥繡簾開，放入雙雙紫燕來。", "燕子似於人有舊，細銜花片落粧臺。"]'),
('a5b5d81c-6f64-43d2-addf-5fed1c43bcfe','寓目  其二','宋伯仁','宋','宋诗','song-poetry','','[]','晝景逢春漸漸長，博山添爇半匙香。',32,'全唐诗/poet.song.210000.json','["晝景逢春漸漸長，博山添爇半匙香。", "梅花一片嬌無力，自趁晴風過粉牆。"]'),
('93046d75-78c7-4d7c-86a0-4404273584a5','久雨','宋伯仁','宋','宋诗','song-poetry','','[]','暗數春來雨，曾無兩日晴。',48,'全唐诗/poet.song.210000.json','["暗數春來雨，曾無兩日晴。", "樹連山莫辨，橋與水俱平。", "閉戶惟便懶，逢人且問耕。", "海棠花落盡，顦顇幾流鶯。"]'),
('25f08ba4-c08a-49f5-a72c-aaf4a54edfbb','訪高菊磵','宋伯仁','宋','宋诗','song-poetry','','[]','可惜吳中不見君，短篷空載一溪雲。',32,'全唐诗/poet.song.210000.json','["可惜吳中不見君，短篷空載一溪雲。", "知君已到孤山下，日日梅花酒半醺。"]'),
('92e1d707-e8b9-45e1-8cd3-e29ff4670256','張監稅新居','宋伯仁','宋','宋诗','song-poetry','','[]','爲愛灘頭只兩家，也來隨分作生涯。',64,'全唐诗/poet.song.210000.json','["爲愛灘頭只兩家，也來隨分作生涯。", "依山築屋先栽柳，買地爲園旋種花。", "聊把功名循世態，只憑詩酒度年華。", "與梅一夜論心事，石鼎茶乾月未斜。"]'),
('98a82434-40b1-4104-a45e-9dfdfa95f04b','尋孫花翁','宋伯仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東風吹雨濕西湖，未許蘇隄酒剩酤。',32,'全唐诗/poet.song.210000.json','["東風吹雨濕西湖，未許蘇隄酒剩酤。", "試向花翁問花訊，不知花似去年無。"]'),
('218086d0-dd43-4229-a23b-95ca78e5c2ba','春雪不止','宋伯仁','宋','宋诗','song-poetry','','[]','春來雪意愈遲遛，又學飛綿過小樓。',64,'全唐诗/poet.song.210000.json','["春來雪意愈遲遛，又學飛綿過小樓。", "暖逐東風雖易化，猛如前月未容休。", "鶯花消息孤詩課，蠶麥生涯累客愁。", "莫道遠人多凍殺，王師亦有在邊頭。"]'),
('678c9c44-dc8c-46f4-bb42-78b5d070743b','無事','宋伯仁','宋','宋诗','song-poetry','','[]','日日溪頭看好山，塵囂無一可相關。',32,'全唐诗/poet.song.210000.json','["日日溪頭看好山，塵囂無一可相關。", "梅花未必能如我，花謝花開未得閒。"]'),
('99b14d01-3741-4b3e-a542-dc4bd1cae091','訪林可山','宋伯仁','宋','宋诗','song-poetry','','[]','可山無日不吟詩，我欲論詩未有期。',32,'全唐诗/poet.song.210000.json','["可山無日不吟詩，我欲論詩未有期。", "幾次孤山明月下，手挼梅蕊立多時。"]'),
('b05b5742-b6a7-4a21-aa5a-5eb2a19a3d9e','簡施芸隠','宋伯仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪後東風作峭寒，客懷零亂客眉攢。',32,'全唐诗/poet.song.210000.json','["雪後東風作峭寒，客懷零亂客眉攢。", "杭州雖近西湖月，寧似湖州把釣竿。"]'),
('213bfa07-2546-4b16-9a0e-da49e62a3a59','丁家村','宋伯仁','宋','宋诗','song-poetry','','[]','不滿十來家，門閭半以柴。',48,'全唐诗/poet.song.210000.json','["不滿十來家，門閭半以柴。", "日烘蘭入鼻，風掠草侵鞋。", "土酒融春興，行歌放客懷。", "何須高買屋，一一近天街。"]'),
('f9338e03-2b4f-4bf8-9ab0-4c7fd65cccff','再會夏石芝','宋伯仁','宋','宋诗','song-poetry','','[]','自與君相別，駸駸已數年。',48,'全唐诗/poet.song.210000.json','["自與君相別，駸駸已數年。", "一緘書不寄，千里夢徒然。", "雨店花新長，風櫺月幾圓。", "嶺梅無恙否，愁滿鬢絲邊。"]'),
('e92aa381-9ca8-4bc2-a505-52c06b492cd1','舊同官張法曹','宋伯仁','宋','宋诗','song-poetry','','[]','熬波同看楚天秋，多少艱難說未休。',32,'全唐诗/poet.song.210000.json','["熬波同看楚天秋，多少艱難說未休。", "今日共依湖柳住，夢中猶怕踏邊頭。"]'),
('2207c226-1f8b-47e0-bbfc-b98da71b99c7','雪後','宋伯仁','宋','宋诗','song-poetry','','[]','暖地難爲雪，春天易得晴。',48,'全唐诗/poet.song.210000.json','["暖地難爲雪，春天易得晴。", "落梅狂客意，啼鳥故園聲。", "愁樂從他事，湖山寄此生。", "願將身與世，渾似柳梢輕。"]'),
('da11a827-e697-40d4-9247-4bcb5a69914b','紙鷂','宋伯仁','宋','宋诗','song-poetry','','[]','弄假如真舞碧空，吹噓全在一絲風。',32,'全唐诗/poet.song.210000.json','["弄假如真舞碧空，吹噓全在一絲風。", "唯慚尺五天將近，猶在兒童掌握中。"]'),
('2e327b54-bcee-467d-80e8-31b43f570b28','湖上新晴','宋伯仁','宋','宋诗','song-poetry','','[]','湖邊膏雨弄晴時，桃杏紅爭錦一機。',32,'全唐诗/poet.song.210000.json','["湖邊膏雨弄晴時，桃杏紅爭錦一機。", "楊柳也如新及第，向人爭舞綠羅衣。"]'),
('d53302c1-4424-4b77-8280-4e3acd2ff591','晚春溪行','宋伯仁','宋','宋诗','song-poetry','','[]','青山數里一溪橫，片片花邊舞燕輕。',32,'全唐诗/poet.song.210000.json','["青山數里一溪橫，片片花邊舞燕輕。", "耕遍水田新雨足，晴天曉色柳風清。"]'),
('5b3a34b3-5301-4547-b524-622c4f37c693','悶甚','宋伯仁','宋','宋诗','song-poetry','','[]','酴醾開已殘，窗戶尚輕寒。',48,'全唐诗/poet.song.210000.json','["酴醾開已殘，窗戶尚輕寒。", "往事多因拙，清尊强自寬。", "對妻憐病久，顧影易心酸。", "更展淵明集，從頭子細看。"]'),
('d9d8012a-6316-46cd-b332-eba277922858','雨中','宋伯仁','宋','宋诗','song-poetry','','[]','終日翻盆雨，池亭晚更凉。',48,'全唐诗/poet.song.210000.json','["終日翻盆雨，池亭晚更凉。", "對琴思古意，釃酒惜韶光。", "綠漲便鷗懶，殘花笑蝶忙。", "高田皆可插，好與報君王。"]'),
('c22c8380-bbb4-43a8-87d0-d7a7876e5cc1','妙智菴','宋伯仁','宋','宋诗','song-poetry','','[]','結屋占山巔，源流未有年。',48,'全唐诗/poet.song.210000.json','["結屋占山巔，源流未有年。", "便非真隠者，且喜得安然。", "石洞雲同卧，茶鐺客對煎。", "我來聊小憩，詩滿夕陽天。"]'),
('1d3868ad-7fdc-4461-ba49-4fda96e22696','嘲不識字','宋伯仁','宋','宋诗','song-poetry','','[]','難字逢人問，村中一小兒。',48,'全唐诗/poet.song.210000.json','["難字逢人問，村中一小兒。", "璋麞寧易辨，亥豕似堪疑。", "鹵莽原非莽，耕犂別字犂。", "識丁何足道，煮字不充饑。"]'),
('60950620-3691-4168-b7d1-95984c575a4b','村學究','宋伯仁','宋','宋诗','song-poetry','','[]','八九頑童一草廬，土朱勤點七言書。',32,'全唐诗/poet.song.210000.json','["八九頑童一草廬，土朱勤點七言書。", "晚聽學長吹樵笛，國子先生殆不如。"]'),
('a6339161-bc19-4bb8-90bc-e8dba698d832','讀林可山西湖衣鉢','宋伯仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅花花下月黄昏，獨自行歌掩竹門。',32,'全唐诗/poet.song.210000.json','["梅花花下月黄昏，獨自行歌掩竹門。", "只道梅花全屬我，不知和靖有仍孫。"]'),
('e665a62a-8c11-4da1-b657-e42af4e5a3cb','寄樓雲卧','宋伯仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲卧西湖又幾年，吟鞍多在酒鑪邊。',64,'全唐诗/poet.song.210000.json','["雲卧西湖又幾年，吟鞍多在酒鑪邊。", "定知今古皆春夢，不把功名作宿緣。", "芳草滿汀山带雨，黄梅落地水連天。", "相逢未說江南事，且問何時理釣船。"]'),
('0bb33868-d90d-4b86-99cd-b08380805614','村姑二首  其一','宋伯仁','宋','宋诗','song-poetry','','[]','翠鬟雙妥未梳頭，紡緯車邊坐欲羞。',32,'全唐诗/poet.song.210000.json','["翠鬟雙妥未梳頭，紡緯車邊坐欲羞。", "幾度採桑歸較晚，阿孃疑看落花愁。"]'),
('539c96c5-087a-457a-89ce-f633b4f34e0d','村姑二首  其二','宋伯仁','宋','宋诗','song-poetry','','[]','底事蹉跎二八年，嫁時裝著未周旋。',32,'全唐诗/poet.song.210000.json','["底事蹉跎二八年，嫁時裝著未周旋。", "年年織得新絲絹，又被家翁作稅錢。"]'),
('8ffee65e-ebf2-4c31-abff-bd3595900c3c','簡吳荆溪','宋伯仁','宋','宋诗','song-poetry','','[]','薄宦從來錯，寧容著意求。',48,'全唐诗/poet.song.210000.json','["薄宦從來錯，寧容著意求。", "自慚千里夢，空作一番愁。", "笑我人如昨，知心雨未休。", "荆溪清徹底，願泊釣魚舟。"]'),
('1ac69fe0-d387-4d00-8f27-d0ec686cee00','學館閒題','宋伯仁','宋','宋诗','song-poetry','','[]','據見定時俱是足，苦思量處便成癡。',32,'全唐诗/poet.song.210000.json','["據見定時俱是足，苦思量處便成癡。", "請君打退閒煩惱，啜粥烹茶細和詩。"]'),
('dd5f8867-069f-4b3c-b3fd-fa7bb6014b89','答林巡檢惠詩','宋伯仁','宋','宋诗','song-poetry','','[]','客久情懷惡，逢人懶說詩。',48,'全唐诗/poet.song.210000.json','["客久情懷惡，逢人懶說詩。", "不堪秋到後，將近雁來時。", "欹枕皆歸夢，同心只舊知。", "淵明籬下菊，誰伴傲霜枝。"]'),
('ad86b288-08a1-45b7-9aed-4f6a90fb6669','秋花','宋伯仁','宋','宋诗','song-poetry','','[]','鳳兒花雜雁來紅，更有鷄冠弄紫茸。',32,'全唐诗/poet.song.210000.json','["鳳兒花雜雁來紅，更有鷄冠弄紫茸。", "可笑倚闌人醉後，只將青眼看芙蓉。"]'),
('aa837663-6ade-4578-98dd-59ab98fc7290','早秋','宋伯仁','宋','宋诗','song-poetry','','[]','秋天一餉晚風凉，笑語人傳早稻香。',32,'全唐诗/poet.song.210000.json','["秋天一餉晚風凉，笑語人傳早稻香。", "樓上醉時簾半捲，愁添客鬢兩蒼蒼。"]'),
('efb8dc35-fbd8-43f3-ac83-51ee1fa3a736','別友人','宋伯仁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','菊花村晚雁來天，同住蘭舟未十年。',32,'全唐诗/poet.song.210000.json','["菊花村晚雁來天，同住蘭舟未十年。", "今日送君須盡醉，離人獨上洞庭船。"]'),
('6b86738a-6c87-4a72-880f-0807b381f0d3','對菊','宋伯仁','宋','宋诗','song-poetry','','[]','少有惺惺得到頭，此心何苦懶方收。',64,'全唐诗/poet.song.210000.json','["少有惺惺得到頭，此心何苦懶方收。", "五湖煙雨常如昔，一稔功名自不由。", "世事莫將真箇看，客程難作舊時留。", "人間豈少淵明□，見著黄花便合羞。"]'),
('ff4c9a83-36a9-4e50-aa78-8b02b81d79b3','累字戲作解愁吟簡舊同寮','宋伯仁','宋','宋诗','song-poetry','','[]','愁。',135,'全唐诗/poet.song.210000.json','["愁。", "知不。", "空白頭。", "心事驚秋。", "歸興滿滄洲。", "貂蟬雖出兜鍪。", "功名有愧黑貂裘。", "夷齊與盜跖總荒丘。", "無非蘧蘧栩栩夢莊周。", "空教笑倒江上煙雨汀鷗。", "一琴一劍一童一鶴一茶甌。", "自不須苦苦高卧元龍百尺樓。", "著眼看翻雲覆雨處豪傑總成羞。", "牙旗金甲蹇馿破帽窮通一任前脩。", "五湖千萬頃明月則儘可棹歌橫釣舟。"]'),
('cdf79a17-9100-41d8-9d84-ef38cb52d9b8','蘇州有感','宋伯仁','宋','宋诗','song-poetry','','[]','秋意滿姑蘇，扁舟憶五湖。',48,'全唐诗/poet.song.210000.json','["秋意滿姑蘇，扁舟憶五湖。", "鈴聲邊報急，帆影客心孤。", "野港青如染，遥山澹欲無。", "英雄應念我，時事滿銀鬚。"]'),
('9f800fd2-119e-45f6-bdde-697d17827a94','棋','宋伯仁','宋','宋诗','song-poetry','','[]','亂鴉飛鷺勢縱橫，對面機心豈易萌。',32,'全唐诗/poet.song.210000.json','["亂鴉飛鷺勢縱橫，對面機心豈易萌。", "一著錯時都是錯，寧無冷眼看輸贏。"]'),
('a468a9bf-c298-4f36-85d1-1b9782c10c3d','水邊聞雁','宋伯仁','宋','宋诗','song-poetry','','[]','蘆花新有雁，四面水連天。',24,'全唐诗/poet.song.210000.json','["蘆花新有雁，四面水連天。", "清浄非人世，吾詩詠不全。"]'),
('f7c487ca-975e-48c6-aa04-5c4bf553bdf3','嘲醉者','宋伯仁','宋','宋诗','song-poetry','','[]','李白日斟三百盞，醉時寧記脫朝靴。',32,'全唐诗/poet.song.210000.json','["李白日斟三百盞，醉時寧記脫朝靴。", "一千八十萬杯酒，百歲消磨未是多。"]'),
('c1d8e90f-8dc4-4b23-ad09-864c59d29ad5','村','宋伯仁','宋','宋诗','song-poetry','','[]','又是江南割稻天，家家兒女笑相牽。',32,'全唐诗/poet.song.210000.json','["又是江南割稻天，家家兒女笑相牽。", "芙蓉占斷清溪水，獨許漁人醉艤船。"]'),
('e278eb2a-e23a-490c-b450-0355716960b6','離維揚','宋伯仁','宋','宋诗','song-poetry','','[]','不爲鱸魚憶故鄉，只緣心事近重陽。',32,'全唐诗/poet.song.210000.json','["不爲鱸魚憶故鄉，只緣心事近重陽。", "鬢絲添得三分白，空被黄花笑一場。"]'),
('d80dba85-b17f-44b0-8781-8e44b1a7eb73','維揚萬花園','宋伯仁','宋','宋诗','song-poetry','','[]','細柳營基鎖綠苔，萬花新種小亭臺。',32,'全唐诗/poet.song.210000.json','["細柳營基鎖綠苔，萬花新種小亭臺。", "芙蓉喜見江南客，故向西風一夜開。"]'),
('4712cb7a-fecd-4b4a-a1a7-cb8e6376c1f8','雨中遠望','宋伯仁','宋','宋诗','song-poetry','','[]','山匝濃雲水匝天，秋容黯淡荻花邊。',32,'全唐诗/poet.song.210000.json','["山匝濃雲水匝天，秋容黯淡荻花邊。", "瀟湘八景誰收去，留下波心小釣船。"]'),
('b3099359-109d-4ad1-b5d6-b4857c625231','勸僧還鄉','宋伯仁','宋','宋诗','song-poetry','','[]','世事無過爾爾，禪心只好休休。',28,'全唐诗/poet.song.210000.json','["世事無過爾爾，禪心只好休休。", "江上數峯如削，西風不礙歸舟。"]'),
('c2580c43-2e06-4d04-900c-1b49e7d5f090','舟中九日','宋伯仁','宋','宋诗','song-poetry','','[]','巴得重陽未到家，短篷根底憶黄花。',32,'全唐诗/poet.song.210000.json','["巴得重陽未到家，短篷根底憶黄花。", "烏紗不爲西風舞，空與同舟說孟嘉。"]'),
('a4584f90-3036-4fea-b800-ca5b3d1551af','安居','宋伯仁','宋','宋诗','song-poetry','','[]','窮通豈在苦勞神，且作安居懶散人。',64,'全唐诗/poet.song.210000.json','["窮通豈在苦勞神，且作安居懶散人。", "買地種花多種竹，煮茶邀客也邀鄰。", "求名豈識書三上，得興無過醉一巡。", "喜得滿𥰭收芋栗，杜陵應未笑全貧。"]'),
('3dab9450-9055-4207-b51c-2b1073fc5483','有感','宋伯仁','宋','宋诗','song-poetry','','[]','窗戶清清半掩門，小兒揩淚立黄昏。',32,'全唐诗/poet.song.210000.json','["窗戶清清半掩門，小兒揩淚立黄昏。", "幾多心事無人問，獨看梅花月半痕。"]'),
('4d0561a1-5832-4a7c-a5b3-1e52e81ebe96','聽琴','宋伯仁','宋','宋诗','song-poetry','','[]','靜夜聽鳴琴，秋風動幽谷。',24,'全唐诗/poet.song.210000.json','["靜夜聽鳴琴，秋風動幽谷。", "何爲鍾子期，千古無人續。"]'),
('7378cef6-33e5-4a9e-9b94-4a4473ce4f9e','楮先生','宋伯仁','宋','宋诗','song-poetry','','[]','先生邂逅龍亭日，多少雲仍滿世間。',64,'全唐诗/poet.song.210000.json','["先生邂逅龍亭日，多少雲仍滿世間。", "千古典謨文獨記，九流毫髮事相關。", "代庖阿堵名尤重，製甲防邊職未閒。", "只與道人爲鶴帳，始能清夢繞湖山。"]'),
('23673fe9-4bb6-4904-86f6-318b81b6a848','歲旦','宋伯仁','宋','宋诗','song-poetry','','[]','居閒無賀客，早起只如常。',48,'全唐诗/poet.song.210000.json','["居閒無賀客，早起只如常。", "桃版隨人換，梅花隔歲香。", "春風回笑語，雲氣卜豐穰。", "柏酒何勞勸，心平壽自長。"]'),
('61441eba-dded-4041-b316-2abcfaab0621','五老  其一','宋伯仁','宋','宋诗','song-poetry','','[]','壯年期佐漢中興，豈謂蟠螭睡不醒。',32,'全唐诗/poet.song.210000.json','["壯年期佐漢中興，豈謂蟠螭睡不醒。", "可惜滿牀廷對稿，白頭翻錄道家經。"]'),
('233ee89a-615f-42a2-9382-5e6b3fa9d831','五老  其二','宋伯仁','宋','宋诗','song-poetry','','[]','髀肉豐腴鬢髮疎，將軍健飯待何如。',32,'全唐诗/poet.song.210000.json','["髀肉豐腴鬢髮疎，將軍健飯待何如。", "七禽不了中原事，羞讀君王問勞書。"]'),
('5e87226b-b738-43cd-9afa-875ec34bec10','五老  其三','宋伯仁','宋','宋诗','song-poetry','','[]','齒髮俱無背已駝，雨耕摩破幾青蓑。',32,'全唐诗/poet.song.210000.json','["齒髮俱無背已駝，雨耕摩破幾青蓑。", "高皇慶壽推恩詔，暗讀全文忘不多。"]'),
('82b305ac-3c9b-4a57-ae3a-0b75fc12a6c6','五老  其四','宋伯仁','宋','宋诗','song-poetry','','[]','短髮衰髯一棹船，白頭波浪幾掀天。',32,'全唐诗/poet.song.210000.json','["短髮衰髯一棹船，白頭波浪幾掀天。", "兒孫各占蘆花住，網得鱸魚即酒錢。"]'),
('57ce61dc-917c-45ed-ac38-d96dab96d6b2','五老  其五','宋伯仁','宋','宋诗','song-poetry','','[]','著破箱中欲嫁衣，翠顰何止只憂葵。',32,'全唐诗/poet.song.210000.json','["著破箱中欲嫁衣，翠顰何止只憂葵。", "春來偷摘斑斑髮，淚濕菱花只自知。"]'),
('45900821-dd93-4071-9cd3-5789495e2dd0','遠訪友人不值','宋伯仁','宋','宋诗','song-poetry','','[]','寒食花枝插滿頭，長亭搔首晚悠悠。',32,'全唐诗/poet.song.210000.json','["寒食花枝插滿頭，長亭搔首晚悠悠。", "灞陵老子無人識，別是天涯一段愁。"]'),
('6874cd6e-c164-4180-bf51-617b2cb501c8','寄征夫','宋伯仁','宋','宋诗','song-poetry','','[]','待君君未歸，寄書書不去。',66,'全唐诗/poet.song.210000.json','["待君君未歸，寄書書不去。", "寄書書可去，有意殊難語。", "深夜彈琵琶，思君在何處，知君在何處。", "不禁春事已闌珊，東風吹起楊花絮，東風吹落楊花絮。"]'),
('0fe8e004-7271-4acd-814a-f07e39c36125','客樓戲集唐人句','宋伯仁','宋','宋诗','song-poetry','','[]','門掩楊花一夜風，自憐羈客尚飄篷。',32,'全唐诗/poet.song.210000.json','["門掩楊花一夜風，自憐羈客尚飄篷。", "不堪吟罷東回首，鳥傍巖花戲晚紅。"]'),
('4b751248-cd53-480f-aa02-f970caa94993','贈僧了性','宋伯仁','宋','宋诗','song-poetry','','[]','雖然年紀小，胸次已江湖。',48,'全唐诗/poet.song.210000.json','["雖然年紀小，胸次已江湖。", "貝葉連宵看，梅花一樣臞。", "記詩誠敢許，戒酒恐應無。", "好向蘇堤上，行行掐數珠。"]'),
('032f14d4-1a2b-41e0-bc89-51832655b4f6','醉中登樓','宋伯仁','宋','宋诗','song-poetry','','[]','明主何嘗棄浩然，杯中有物且隨緣。',32,'全唐诗/poet.song.210000.json','["明主何嘗棄浩然，杯中有物且隨緣。", "倚樓心事誰消遣，一點飛禽落釣船。"]'),
('0811d637-5bc5-4469-b336-dc2d93c972e5','嘲燕','宋伯仁','宋','宋诗','song-poetry','','[]','年來乳燕亦堪羞，不學楊花得自由。',32,'全唐诗/poet.song.210000.json','["年來乳燕亦堪羞，不學楊花得自由。", "飛過幾家門戶去，直須尋見最高樓。"]'),
('820c167d-3627-4281-b424-6a9732bced39','瓶梅','宋伯仁','宋','宋诗','song-poetry','','[]','南枝斜插古軍持，瘦影參差落硯池。',32,'全唐诗/poet.song.210000.json','["南枝斜插古軍持，瘦影參差落硯池。", "莫道人家窗戶暖，等閒忘却隴頭時。"]'),
('21b0ccaa-dc2e-4a55-855a-aa1b0ad3ef80','春半','宋伯仁','宋','宋诗','song-poetry','','[]','春到已多時，遊人替衲衣。',48,'全唐诗/poet.song.211000.json','["春到已多時，遊人替衲衣。", "柳眠鶯喚醒，花瘦雨添肥。", "官事癡能了，人情久易非。", "一貧能自守，贏得掩柴扉。"]'),
('957aa115-312d-4932-8998-9cd37725a810','散愁四首  其一','宋伯仁','宋','宋诗','song-poetry','','[]','著意功名四十年，柳花空滿鬢絲邊。',32,'全唐诗/poet.song.211000.json','["著意功名四十年，柳花空滿鬢絲邊。", "男兒無補朝廷事，有愧饑餐困即眠。"]'),
('dedafe14-faf3-4f63-898a-bf52be24d13b','散愁四首  其二','宋伯仁','宋','宋诗','song-poetry','','[]','小樓呼酒揖青山，翠碧瓏璁一笑間。',32,'全唐诗/poet.song.211000.json','["小樓呼酒揖青山，翠碧瓏璁一笑間。", "山若有情應問我，如何猶似野人閒。"]'),
('43c72388-7b2b-4e74-9e17-9deba0f28101','散愁四首  其三','宋伯仁','宋','宋诗','song-poetry','','[]','清貧如水儘無妨，只願伊周立廟堂。',32,'全唐诗/poet.song.211000.json','["清貧如水儘無妨，只願伊周立廟堂。", "扶起太平千載脈，且隨農父樂耕桑。"]'),
('a4f552db-94f9-475c-ae9e-67b89bca366b','散愁四首  其四','宋伯仁','宋','宋诗','song-poetry','','[]','旋買犁鋤學種田，一聲長嘯霅溪邊。',32,'全唐诗/poet.song.211000.json','["旋買犁鋤學種田，一聲長嘯霅溪邊。", "微茫白水山如畫，好箇江南萬里天。"]'),
('3b8ea739-ab1e-469f-9f60-587213a5bb82','午睡','宋伯仁','宋','宋诗','song-poetry','','[]','午夢驚回筍簟凉，坦夷襟度即瀟湘。',64,'全唐诗/poet.song.211000.json','["午夢驚回筍簟凉，坦夷襟度即瀟湘。", "詩高自與梅花好，食淡方知菜味長。", "事說萬端多畫虎，人無一念不亡羊。", "滿頭飛絮春零亂，莫笑狂夫老更狂。"]'),
('b38a58b4-76fa-439b-bac1-e2cc1a821978','酒邊','宋伯仁','宋','宋诗','song-poetry','','[]','一醉復一醉，陶陶醉未休。',48,'全唐诗/poet.song.211000.json','["一醉復一醉，陶陶醉未休。", "何傷於日月，知我者春秋。", "萬事難追昔，千金不解愁。", "白鷗飛浩蕩，此興屬漁舟。"]'),
('06671b04-7b85-4831-afa2-42fb54b46df8','小舟晚賞荷花','宋伯仁','宋','宋诗','song-poetry','','[]','天浮月影水浮天，路繞山頭樹繞煙。',32,'全唐诗/poet.song.211000.json','["天浮月影水浮天，路繞山頭樹繞煙。", "船小小行人意適，藕花新索酒杯傳。"]'),
('5b1833f9-65b1-4ba7-9a9d-83559e85ad5d','清明插柳','宋伯仁','宋','宋诗','song-poetry','','[]','清明是處插垂楊，院宇深深綠翠藏。',32,'全唐诗/poet.song.211000.json','["清明是處插垂楊，院宇深深綠翠藏。", "心地不爲塵俗累，不簪楊柳也何妨。"]'),
('a5077bcd-0582-4c71-b033-9c23c9ff23ce','晚春二首  其一','宋伯仁','宋','宋诗','song-poetry','','[]','風甃殘花滿地紅，別離樽俎謾匆匆。',32,'全唐诗/poet.song.211000.json','["風甃殘花滿地紅，別離樽俎謾匆匆。", "春光未肯收心去，却在荼䕷細影中。"]'),
('194dd41d-d5b8-4f7e-a330-a0eab1937e17','晚春二首  其二','宋伯仁','宋','宋诗','song-poetry','','[]','綠陰陰裏惜韶華，自縛筠梢掃落花。',32,'全唐诗/poet.song.211000.json','["綠陰陰裏惜韶華，自縛筠梢掃落花。", "可笑遊人心未懶，杜鵑啼處撥琵琶。"]'),
('25693982-a6c3-4bb7-bfd2-664e1845b530','清和','宋伯仁','宋','宋诗','song-poetry','','[]','詩債還無足，家園亦倦看。',48,'全唐诗/poet.song.211000.json','["詩債還無足，家園亦倦看。", "客遊宜致仕，午睡當之官。", "舌笑張儀在，心憑達摩安。", "清和天氣好，應免夾衣寒。"]'),
('c9dd23e8-f691-4000-997f-23a21ff26f33','久坐','宋伯仁','宋','宋诗','song-poetry','','[]','坐久如忘世，松窗日未斜。',48,'全唐诗/poet.song.211000.json','["坐久如忘世，松窗日未斜。", "營巢鴉噪樹，作夢蝶眠花。", "易課推三畫，醫方錄數家。", "瓶笙聲未絕，更點土山茶。"]'),
('c868419a-4ec7-4ec4-b35a-ebff0ce7e879','戲作','宋伯仁','宋','宋诗','song-poetry','','[]','青梅黄盡雨無多，柳影重重午日過。',32,'全唐诗/poet.song.211000.json','["青梅黄盡雨無多，柳影重重午日過。", "忽聽隔籬人語笑，採蓮艇子上新河。"]'),
('a32dc504-ddee-49ac-9fbc-5911ad46a812','玉泉寺金魚','宋伯仁','宋','宋诗','song-poetry','','[]','金鱗韜隠已多時，寺壁重泥又有詩。',32,'全唐诗/poet.song.211000.json','["金鱗韜隠已多時，寺壁重泥又有詩。", "龍若久懷霖雨志，不應蟠屈小方池。"]'),
('178e7112-efc5-4504-8dd0-54cc3822d1ae','僻居','宋伯仁','宋','宋诗','song-poetry','','[]','居僻恬無事，開軒挹晚晴。',48,'全唐诗/poet.song.211000.json','["居僻恬無事，開軒挹晚晴。", "雨耽雲脚重，風約燕身輕。", "有子爭梨栗，無朋問死生。", "每憂人載酒，剝啄打門聲。"]'),
('ddc4435d-da14-4de7-ad7c-061aacdc393d','倦吟','宋伯仁','宋','宋诗','song-poetry','','[]','競病推敲欲嘔心，何如危坐拆桐陰。',32,'全唐诗/poet.song.211000.json','["競病推敲欲嘔心，何如危坐拆桐陰。", "新蟬咽咽知人意，學我年來抱膝吟。"]'),
('2a6d477d-f31a-4c85-bfda-c6e9235b30e8','云云','宋伯仁','宋','宋诗','song-poetry','','[]','休將閒耳聽云云，只作深居耳不聞。',64,'全唐诗/poet.song.211000.json','["休將閒耳聽云云，只作深居耳不聞。", "素志肯隨時節改，清貧難許利名分。", "忘情茅屋無非燕，著脚春山獨是雲。", "試問急流誰勇退，故園同看木欣欣。"]'),
('60201b0b-6f43-40d1-8eeb-578e6b871a73','愁','宋伯仁','宋','宋诗','song-poetry','','[]','愁懷難畫亦難詩，惟有流鶯暗得知。',32,'全唐诗/poet.song.211000.json','["愁懷難畫亦難詩，惟有流鶯暗得知。", "我亦無言鶯不語，柳邊相看立多時。"]'),
('cdbe0791-0be9-456e-a22a-b34f4fdc5907','蓼花','宋伯仁','宋','宋诗','song-poetry','','[]','秋到梧桐我未宜，蓼花何事已先知。',32,'全唐诗/poet.song.211000.json','["秋到梧桐我未宜，蓼花何事已先知。", "朝來數點西風雨，喜見深紅四五枝。"]'),
('694b1e44-a545-41bf-8333-1a5cfd1129a9','懶','宋伯仁','宋','宋诗','song-poetry','','[]','懶懶懶復懶，而今懶更宜。',48,'全唐诗/poet.song.211000.json','["懶懶懶復懶，而今懶更宜。", "此身聊復爾，萬事欲何之。", "尚覺瓢爲贅，奚煩鍤自隨。", "客來眠正熟，裙幅任題詩。"]'),
('5ecbe4eb-0b98-4cde-92f1-e319f1393748','書座左','宋伯仁','宋','宋诗','song-poetry','','[]','天地一蘧廬，吾身自卷舒。',48,'全唐诗/poet.song.211000.json','["天地一蘧廬，吾身自卷舒。", "翁能從失馬，子亦豈知魚。", "謹獨甘居漏，安貧且飯疏。", "昨非今未是，寧不賦歸歟。"]'),
('30e6f98b-a3d9-4095-bf71-4b37a300e94f','書座右','宋伯仁','宋','宋诗','song-poetry','','[]','蠻觸小功名，須教一念輕。',48,'全唐诗/poet.song.211000.json','["蠻觸小功名，須教一念輕。", "受恩知報飯，臨事貴懲羹。", "壽域惟仁宅，心田以道耕。", "泰然忘物我，無使狎鷗驚。"]'),
('80428ff7-e979-45b8-8867-361a953c880f','凉','宋伯仁','宋','宋诗','song-poetry','','[]','不擬西風一頓凉，看看凉近木樨香。',32,'全唐诗/poet.song.211000.json','["不擬西風一頓凉，看看凉近木樨香。", "人家未得征夫信，蚤有砧聲怯雁行。"]'),
('b201a505-937f-4195-b17c-19e8eb289914','荷花','宋伯仁','宋','宋诗','song-poetry','','[]','綠蓋半篙新雨，紅香一點清風。',28,'全唐诗/poet.song.211000.json','["綠蓋半篙新雨，紅香一點清風。", "天賦本根如玉，濂溪以道心同。"]'),
('7fe246e6-9121-4715-86d1-c3b5ff0cd8bd','扇','宋伯仁','宋','宋诗','song-poetry','','[]','師璋今有幾家同，名重蒲葵價亦穹。',32,'全唐诗/poet.song.211000.json','["師璋今有幾家同，名重蒲葵價亦穹。", "髹柄但誇千縷骨，不知曾未掩西風。"]'),
('d39608de-41b6-4a45-a452-ff6382490d4f','中秋月','宋伯仁','宋','宋诗','song-poetry','','[]','只與閒時月一般，寧知今夕最團欒。',64,'全唐诗/poet.song.211000.json','["只與閒時月一般，寧知今夕最團欒。", "竹邊借柄還如扇，花下傳杯可當盤。", "野兔易忘終夜夢，林烏未許一枝安。", "人生幾箇中秋節，那得都將笑眼看。"]'),
('1f9cdbfa-0606-48d4-a8c0-293337a0fe3c','席上有舉東坡集歸去來字成詩十首醉中戲續一首','宋伯仁','宋','宋诗','song-poetry','','[]','傲世欲何求，歸來已倦遊。',48,'全唐诗/poet.song.211000.json','["傲世欲何求，歸來已倦遊。", "琴詩聊自嘯，丘壑復相留。", "問菊時携酒，乘風或棹舟。", "樂天良有以，心事老田疇。"]'),
('c7888614-334b-4884-bb14-a0331acc883e','漁父吟','宋伯仁','宋','宋诗','song-poetry','','[]','小舟如雁許，穩穩下波心。',48,'全唐诗/poet.song.211000.json','["小舟如雁許，穩穩下波心。", "蓑笠幾風雨，江山無古今。", "清歌鳴短棹，紅葉滿疎林。", "一醉不知世，前村月未沈。"]'),
('5359884f-f40b-4716-a2fb-a18f8d9d9143','秋風','宋伯仁','宋','宋诗','song-poetry','','[]','秋風卷秋葉，秋思滿秋天。',48,'全唐诗/poet.song.211000.json','["秋風卷秋葉，秋思滿秋天。", "骨立山如削，聲低雁欲眠。", "客愁無暇日，農事喜豐年。", "說著鱸蓴事，歸心滿釣船。"]'),
('a9739b28-9bfb-4431-ab5e-7d74c4d92fd4','聽雨','宋伯仁','宋','宋诗','song-poetry','','[]','凍雨瀟瀟未肯晴，灑窗聲似煮茶聲。',32,'全唐诗/poet.song.211000.json','["凍雨瀟瀟未肯晴，灑窗聲似煮茶聲。", "山童酤得鄰家酒，炒栗爐頭獨自傾。"]'),
('d9bd3cee-bb83-41a7-90a1-4fb4deab0615','村田樂','宋伯仁','宋','宋诗','song-poetry','','[]','打稻天如二月天，滿村和氣樂豐年。',32,'全唐诗/poet.song.211000.json','["打稻天如二月天，滿村和氣樂豐年。", "田翁爛醉身如舞，兩箇兒童策上船。"]'),
('599d83eb-ca2e-4431-bf91-cd95b66d66f7','問梅','宋伯仁','宋','宋诗','song-poetry','','[]','癡風衮衮送寒來，竹裏人家總未開。',32,'全唐诗/poet.song.211000.json','["癡風衮衮送寒來，竹裏人家總未開。", "唯有老巖心事苦，瘦筇敲雪問梅腮。"]'),
('85b66419-7603-4b5d-881c-d9e484fcfedf','山下','宋伯仁','宋','宋诗','song-poetry','','[]','山下六七里，山前八九家。',24,'全唐诗/poet.song.211000.json','["山下六七里，山前八九家。", "家家清到骨，只賣水仙花。"]'),
('7f64dd5f-92f1-4afc-b950-ee45e68ad23e','落葉','宋伯仁','宋','宋诗','song-poetry','','[]','捲地西風促雨來，掃除黄葉滿蒼苔。',32,'全唐诗/poet.song.211000.json','["捲地西風促雨來，掃除黄葉滿蒼苔。", "垂楊蚤有青青眼，只礙梅花未敢開。"]'),
('5e8794de-bb12-40d1-b472-34bfe0618c94','梅蘭','宋伯仁','宋','宋诗','song-poetry','','[]','清標同插古軍持，清似西山凍餒時。',32,'全唐诗/poet.song.211000.json','["清標同插古軍持，清似西山凍餒時。", "嚼蕊弄香無說處，屈平和靖已何之。"]'),
('752ff047-0a90-4e42-8848-a239871463c5','佳人歌','宋伯仁','宋','宋诗','song-poetry','','[]','淡傅粉，淺畫眉，鬢邊休插桃花枝。',136,'全唐诗/poet.song.211000.json','["淡傅粉，淺畫眉，鬢邊休插桃花枝。", "白面郎君馬如箭，回頭再盼情依依。", "文君未識相如面，朱弦聲裏猶相戀，風流勝事千古傳。", "寧如文君當時深深深處深庭院，臨邛亦免王孫怨。", "佳人佳人休捲簾，門外落花春正甜。", "繡牀午困語聲寂，博山篆冷香頻添。", "佳人噫，佳人吁，今人安得人人思秋胡，黄金不認真丈夫。"]'),
('6db273b2-3089-4ea3-8f34-6d19f3694a8c','醜女歌','宋伯仁','宋','宋诗','song-poetry','','[]','梳風楊柳笑，沐雨杏花羞。',145,'全唐诗/poet.song.211000.json','["梳風楊柳笑，沐雨杏花羞。", "看看三十餘，不敢下粧樓。", "待媒媒不來，對娘娘共哭。", "何時王右軍，來坦東牀腹。", "君不見西施絕色天下白，能使麋鹿走吳宮。", "玉環一笑百媚生，能使漁陽鞞鼓驚玄宗。", "無鹽無鹽形貌惡，當時一段議論千古生清風。", "美婦未必美，所美貌徒美。", "醜婦未必醜，所醜行不醜。", "醜妻惡妾壽乃翁，何須能勸羊羔酒。"]'),
('b58f82cb-5996-4ef2-9277-e52165f01e98','梅花喜神譜 蓓蕾四枝 其一','宋伯仁','宋','宋诗','song-poetry','','[]','南枝發岐穎，崆峒占歲登。',24,'全唐诗/poet.song.211000.json','["南枝發岐穎，崆峒占歲登。", "當思漢光武，一飯能中興。"]'),
('8eb84332-e22e-4ccc-8ce2-6f52fe510d40','梅花喜神譜 蓓蕾四枝 其二','宋伯仁','宋','宋诗','song-poetry','','[]','靜看隋堤人，紛紛幾榮辱。',24,'全唐诗/poet.song.211000.json','["靜看隋堤人，紛紛幾榮辱。", "蠻腰休逞妍，所見元非俗。"]'),
('51329b7b-f13e-4614-9b56-ef22cb49b1e8','梅花喜神譜 蓓蕾四枝 其三','宋伯仁','宋','宋诗','song-poetry','','[]','獻頌侈春朝，爭期千歲壽。',24,'全唐诗/poet.song.211000.json','["獻頌侈春朝，爭期千歲壽。", "凌寒傲歲時，自與冰霜久。"]'),
('892b0516-cae9-4c57-aa42-b562ebee7a6e','梅花喜神譜 蓓蕾四枝 其四','宋伯仁','宋','宋诗','song-poetry','','[]','爬沙走江海，慣識風波惡。',24,'全唐诗/poet.song.211000.json','["爬沙走江海，慣識風波惡。", "東君爲主張，顯戮逃砧鑊。"]'),
('d3764229-299a-4e69-b6e5-908f9b0267bc','梅花喜神譜 小蕊一十六枝 其一','宋伯仁','宋','宋诗','song-poetry','','[]','藥性貴溫凉，胡爲辛且烈。',24,'全唐诗/poet.song.211000.json','["藥性貴溫凉，胡爲辛且烈。", "無與桂附徒，天資更趨熱。"]'),
('46183e45-2c19-4318-833f-12f08891fa78','梅花喜神譜 小蕊一十六枝 其二','宋伯仁','宋','宋诗','song-poetry','','[]','樊素艷而歌，樂天何所羨。',24,'全唐诗/poet.song.211000.json','["樊素艷而歌，樂天何所羨。", "須結帝王知，拜寵明光殿。"]'),
('43afdde9-6e4d-49e2-a6a0-a79fd1581b73','梅花喜神譜 小蕊一十六枝 其三','宋伯仁','宋','宋诗','song-poetry','','[]','風掣五雲開，明星燦南極。',24,'全唐诗/poet.song.211000.json','["風掣五雲開，明星燦南極。", "嘉祥自朝廷，何幸愚親識。"]'),
('42ed0853-9458-4233-9354-d58b01ae9c5b','梅花喜神譜 小蕊一十六枝 其四','宋伯仁','宋','宋诗','song-poetry','','[]','佛有光明臺，蚌胎奚足貴。',24,'全唐诗/poet.song.211000.json','["佛有光明臺，蚌胎奚足貴。", "聊以矜俗人，徒爲寶所費。"]'),
('9287063d-4e58-40e2-8887-92fab3afa840','梅花喜神譜 小蕊一十六枝 其五','宋伯仁','宋','宋诗','song-poetry','','[]','阿堵本何物，貫朽殊堪羞。',24,'全唐诗/poet.song.211000.json','["阿堵本何物，貫朽殊堪羞。", "空囊留得一，千古欽清流。"]'),
('4018b6d0-16fc-4947-97a8-34490606ca04','梅花喜神譜 小蕊一十六枝 其六','宋伯仁','宋','宋诗','song-poetry','','[]','善舞幾當場，妖姿呈窈窕。',24,'全唐诗/poet.song.211000.json','["善舞幾當場，妖姿呈窈窕。", "當場人自迷，郭郎未容笑。"]'),
('f0aa466d-3424-49d3-9d57-63692d6ff241','梅花喜神譜 小蕊一十六枝 其七','宋伯仁','宋','宋诗','song-poetry','','[]','三窟不須營，蒙恬素心友。',24,'全唐诗/poet.song.211000.json','["三窟不須營，蒙恬素心友。", "識盡天下書，只要文章手。"]'),
('5735d361-019a-4ca0-bd94-9f441a03ced3','梅花喜神譜 小蕊一十六枝 其八','宋伯仁','宋','宋诗','song-poetry','','[]','寒風偃枯草，掉尾來山巔。',24,'全唐诗/poet.song.211000.json','["寒風偃枯草，掉尾來山巔。", "出柙勢可畏，老鬚寧易編。"]'),
('dfa72db3-c338-4c12-bfae-36ba566df146','梅花喜神譜 小蕊一十六枝 其九','宋伯仁','宋','宋诗','song-poetry','','[]','錦囊藴珠璣，長養南風力。',24,'全唐诗/poet.song.211000.json','["錦囊藴珠璣，長養南風力。", "當年東老家，曾代中書筆。"]'),
('112c51af-4e84-4611-bb1b-1b8c6ae9a4c0','梅花喜神譜 小蕊一十六枝 其一○','宋伯仁','宋','宋诗','song-poetry','','[]','來自淤泥中，根苗何足取。',24,'全唐诗/poet.song.211000.json','["來自淤泥中，根苗何足取。", "餖飣上盤登，敢爲梨栗伍。"]'),
('f73895f4-7d9b-43ad-ba0e-af75be71f282','梅花喜神譜 小蕊一十六枝 其一一','宋伯仁','宋','宋诗','song-poetry','','[]','宛陵有靈根，圓紅珍可芼。',24,'全唐诗/poet.song.211000.json','["宛陵有靈根，圓紅珍可芼。", "衛人感齊恩，瓊琚未容報。"]'),
('f8c107a3-519a-4670-bb64-e1b8e46d1d56','梅花喜神譜 小蕊一十六枝 其一二','宋伯仁','宋','宋诗','song-poetry','','[]','纔脫錦衣䙀，童顔嬌可詫。',24,'全唐诗/poet.song.211000.json','["纔脫錦衣䙀，童顔嬌可詫。", "只恐粧鬼時，愛之還又怕。"]'),
('4bc04643-004d-417c-bc8d-51576a134e04','梅花喜神譜 小蕊一十六枝 其一三','宋伯仁','宋','宋诗','song-poetry','','[]','垂垂生井上，遊子休整冠。',24,'全唐诗/poet.song.211000.json','["垂垂生井上，遊子休整冠。", "道旁徒自苦，青眼誰能看。"]'),
('466908c3-de17-4788-81e3-1be6f69fbe2f','梅花喜神譜 小蕊一十六枝 其一四','宋伯仁','宋','宋诗','song-poetry','','[]','東陵人已仙，黯淡斜陽暮。',24,'全唐诗/poet.song.211000.json','["東陵人已仙，黯淡斜陽暮。", "可慚名利心，孜孜問葵戍。"]'),
('9d9ad6c3-e9ee-4871-ae39-22bc6db9dfcf','梅花喜神譜 小蕊一十六枝 其一五','宋伯仁','宋','宋诗','song-poetry','','[]','生長滄波中，收羅向書室。',24,'全唐诗/poet.song.211000.json','["生長滄波中，收羅向書室。", "剡藤無不平，祇恐無椽筆。"]'),
('0825e516-49b6-4848-beaf-0bff243259e0','梅花喜神譜 小蕊一十六枝 其一六','宋伯仁','宋','宋诗','song-poetry','','[]','清波漾蛙子，古書形似之。',24,'全唐诗/poet.song.211000.json','["清波漾蛙子，古書形似之。", "可惜書廢久，時人無能知。"]'),
('9dfd2148-e1b5-4031-9153-de60b873749d','梅花喜神譜 大蕊八枝 其一','宋伯仁','宋','宋诗','song-poetry','','[]','高山流水音，泠泠生指下。',24,'全唐诗/poet.song.211000.json','["高山流水音，泠泠生指下。", "無與俗人彈，伯牙恐嘲駡。"]'),
('b87611e5-0024-44f8-a971-83d3b53a32ff','梅花喜神譜 大蕊八枝 其二','宋伯仁','宋','宋诗','song-poetry','','[]','蟾宮有兔臼，搗藥千萬年。',24,'全唐诗/poet.song.211000.json','["蟾宮有兔臼，搗藥千萬年。", "藥有長生術，世人無計傳。"]'),
('a0d74b3e-5089-4e71-83fd-f54b243d9e70','梅花喜神譜 大蕊八枝 其三','宋伯仁','宋','宋诗','song-poetry','','[]','休與鷸相持，自有山川隔。',24,'全唐诗/poet.song.211000.json','["休與鷸相持，自有山川隔。", "祝君無孕珠，恐非保身策。"]'),
('6c24fa51-9b3d-4182-a8dd-d867d933c09c','梅花喜神譜 大蕊八枝 其四','宋伯仁','宋','宋诗','song-poetry','','[]','曳頸吟松梢，何異揚州鶴。',24,'全唐诗/poet.song.211000.json','["曳頸吟松梢，何異揚州鶴。", "胡爲鶴未成，苦被玄裳錯。"]'),
('b59fe2e2-2786-471c-9dba-54f4d33782c4','梅花喜神譜 大蕊八枝 其五','宋伯仁','宋','宋诗','song-poetry','','[]','中尊嚴祀典，鬯未祼而實。',24,'全唐诗/poet.song.211000.json','["中尊嚴祀典，鬯未祼而實。", "將祼而實彜，禮文知有秩。"]'),
('3e505c8d-4fbd-40a5-975a-f46820dd663e','梅花喜神譜 大蕊八枝 其六','宋伯仁','宋','宋诗','song-poetry','','[]','方深有制度，撞之以合樂。',24,'全唐诗/poet.song.211000.json','["方深有制度，撞之以合樂。", "止樂戛以敔，始終知所覺。"]'),
