('8315d9a7-4c4e-41be-a32f-2e300390a918','梅花喜神譜 欲謝一十六枝 其一六','宋伯仁','宋','宋诗','song-poetry','','[]','春透水波明，江湖從落魄。',24,'全唐诗/poet.song.211000.json','["春透水波明，江湖從落魄。", "三十六鱗成，禹門看一躍。"]'),
('e55847a0-e27d-4dea-bd20-cbae58a33093','梅花喜神譜 就實六枝 其一','宋伯仁','宋','宋诗','song-poetry','','[]','羽翼漢家了，忘形天地間。',24,'全唐诗/poet.song.211000.json','["羽翼漢家了，忘形天地間。", "箇中有真樂，奚必拘商山。"]'),
('5e21751a-2903-4e75-96e1-399ff06fd87d','梅花喜神譜 就實六枝 其二','宋伯仁','宋','宋诗','song-poetry','','[]','品字列輕舠，占盡吳江雪。',24,'全唐诗/poet.song.211000.json','["品字列輕舠，占盡吳江雪。", "丁寧紅蓼花，莫與利名說。"]'),
('09d5c151-9d53-4626-b567-667201cbff8a','梅花喜神譜 就實六枝 其三','宋伯仁','宋','宋诗','song-poetry','','[]','東門風飄飄，雙佩清如水。',24,'全唐诗/poet.song.211000.json','["東門風飄飄，雙佩清如水。", "出門相送人，胡不共知止。"]'),
('dbf55017-54f8-4dca-9bbc-aa3916130540','梅花喜神譜 就實六枝 其四','宋伯仁','宋','宋诗','song-poetry','','[]','一竿風雨寒，獨占嚴陵瀨。',24,'全唐诗/poet.song.211000.json','["一竿風雨寒，獨占嚴陵瀨。", "苟非伸脚眠，曷見光武大。"]'),
('ea699310-a906-4a4f-8f94-608a9d3f4fae','梅花喜神譜 就實六枝 其五','宋伯仁','宋','宋诗','song-poetry','','[]','醉帽不輕飛，秋菊有佳色。',24,'全唐诗/poet.song.211000.json','["醉帽不輕飛，秋菊有佳色。", "自慚羣座中，主人猶未識。"]'),
('7219ffe5-b06c-4099-9e30-122ebd8b1a44','梅花喜神譜 就實六枝 其六','宋伯仁','宋','宋诗','song-poetry','','[]','脫白弄青玉，風味猶辛酸。',24,'全唐诗/poet.song.211000.json','["脫白弄青玉，風味猶辛酸。", "指日夢惟肖，羹調天下安。"]'),
('37e28b80-716b-4fba-aafc-3b5d23af04ef','柬趙監鹽','宋伯仁','宋','宋诗','song-poetry','','[]','西風吹破黑貂裘，多少江山惜倦遊。',64,'全唐诗/poet.song.211000.json','["西風吹破黑貂裘，多少江山惜倦遊。", "紅葉已霜天欲暮，綠蓑初雨客吟秋。", "人逢知己無榮辱，事不縈懷任去留。", "但是菊花開便好，醉中休說異鄉愁。"]'),
('a37754d2-0503-49d0-a238-4ff961f42b5f','古意','葉茵','宋','宋诗','song-poetry','','[]','悠悠澗邊人，濺濺澗中水。',24,'全唐诗/poet.song.211000.json','["悠悠澗邊人，濺濺澗中水。", "水流無返時，人生流水耳。"]'),
('7f53cea9-7ddf-461f-992b-86c1c149048d','偶成','葉茵','宋','宋诗','song-poetry','','[]','春陰晴復陰，因物悟浮生。',48,'全唐诗/poet.song.211000.json','["春陰晴復陰，因物悟浮生。", "杜宇鄉心重，楊花世事輕。", "知非蘧伯玉，覺是晉淵明。", "此意誰人會，騎牛訪偶耕。"]'),
('fa121459-9189-4cc6-8400-a4bfbe1d14c7','蘇堤','葉茵','宋','宋诗','song-poetry','','[]','南北山圍翡翠隄，隄邊綠漲軟琉璃。',64,'全唐诗/poet.song.211000.json','["南北山圍翡翠隄，隄邊綠漲軟琉璃。", "參差臺榭無餘地，雜遝輪蹄了四時。", "楊柳又多前日樹，梅花祗少近人詩。", "停篙不看春風面，閒伴漁翁理釣絲。"]'),
('742a0cd1-3f2e-4c3a-ab66-1985e6753047','野望','葉茵','宋','宋诗','song-poetry','','[]','白水沿隄護綠苗，鷄鳴犬卧柳邊橋。',32,'全唐诗/poet.song.211000.json','["白水沿隄護綠苗，鷄鳴犬卧柳邊橋。", "數家雖不成村落，一夢何曾到市朝。"]'),
('50469afd-8c32-4e31-b5c9-e873b3d19b74','次潘紫巖虎丘韻','葉茵','宋','宋诗','song-poetry','','[]','潭深劍氣鉎，樹瘦嵐光薄。',48,'全唐诗/poet.song.211000.json','["潭深劍氣鉎，樹瘦嵐光薄。", "石壇古即今，藤花開又落。", "晉士已結廬，吳市猶舞鶴。", "沈吟發幽懷，人世舟藏壑。"]'),
('9b35026e-24ff-469f-96fc-94e30b0ebbb7','別韓菊山','葉茵','宋','宋诗','song-poetry','','[]','結廬甫里鄰，顧瞻誰與遊。',192,'全唐诗/poet.song.211000.json','["結廬甫里鄰，顧瞻誰與遊。", "掩荆樂魚鳥，握管成樵謳。", "有客賞茲趣，柳下時停舟。", "自締十年契，投簪不願侯。", "一朝過我別，匪伊趨東州。", "敢問何爲爾，讀書松竹幽。", "輦母遠之官，謾作升斗謀。", "執手話勞役，揮杯忘獻酬。", "離懷聿云悲，重來如此不。", "何當羽厥身，千里雲悠悠。", "上下相追逐，赤城少延留。", "其中有玉人，而可爲吾儔。", "此志不可得，迢迢水東流。", "載言涉征途，途脩暑氣遒。", "袗絺自金玉，脂車裹糧餱。", "我將植佳菊，長對南山秋。"]'),
('6d04cd25-2950-4e98-a35f-e34235c4d64a','水竹墅十詠 曲水流觴','葉茵','宋','宋诗','song-poetry','','[]','蘭亭飲者徒，因物寓天理。',24,'全唐诗/poet.song.211000.json','["蘭亭飲者徒，因物寓天理。", "著眼靜中觀，坎止流行耳。"]'),
('755dfbf6-267a-496c-afdb-5626f92ffa57','水竹墅十詠 峭壁寒潭','葉茵','宋','宋诗','song-poetry','','[]','百丈崖懸立，一泓流綠漪。',24,'全唐诗/poet.song.211000.json','["百丈崖懸立，一泓流綠漪。", "品題無好語，摹寫冷泉詩。"]'),
('987c75e0-c386-4217-9825-0aafa2ad83f1','水竹墅十詠 安樂窩','葉茵','宋','宋诗','song-poetry','','[]','受用十三詩，不離方寸地。',24,'全唐诗/poet.song.211000.json','["受用十三詩，不離方寸地。", "門外自風波，行之以無事。"]'),
('35585ab1-aef0-4e10-83e2-1e9a2cf75784','水竹墅十詠 野堂','葉茵','宋','宋诗','song-poetry','','[]','風來無市聲，景物占深浄。',24,'全唐诗/poet.song.211000.json','["風來無市聲，景物占深浄。", "鷗狎堂上翁，時來點天鏡。"]'),
('3ca912e0-23f2-4477-81fd-80200d51f0fd','水竹墅十詠 竹風水月','葉茵','宋','宋诗','song-poetry','','[]','造物無盡藏，散在林泉中。',24,'全唐诗/poet.song.211000.json','["造物無盡藏，散在林泉中。", "結亭相周旋，人與萬境空。"]'),
('c496ae6d-5a74-43c2-b941-07dc76a8c803','水竹墅十詠 廣寒世界','葉茵','宋','宋诗','song-poetry','','[]','鼻祖舊遊地，留得老桂香。',24,'全唐诗/poet.song.211000.json','["鼻祖舊遊地，留得老桂香。", "有能培植之，此香傳諸郎。"]'),
('40b50a41-55be-4ead-9a2d-199836319ce3','水竹墅十詠 盟鷗','葉茵','宋','宋诗','song-poetry','','[]','同此江湖心，有盟非知己。',24,'全唐诗/poet.song.211000.json','["同此江湖心，有盟非知己。", "我亦畏機人，莫入驚波裏。"]'),
('030dea25-0a81-46ce-834d-4cc5dcc69605','水竹墅十詠 得春橋','葉茵','宋','宋诗','song-poetry','','[]','策馿風雪中，東君獻詩料。',24,'全唐诗/poet.song.211000.json','["策馿風雪中，東君獻詩料。", "花驚非故吾，聊復索花笑。"]'),
('79949d43-9eb2-41d2-aa6e-d718c1aeffbe','水竹墅十詠 賞心橋','葉茵','宋','宋诗','song-poetry','','[]','沿隄過竹所，履聲驚龜魚。',24,'全唐诗/poet.song.211000.json','["沿隄過竹所，履聲驚龜魚。", "人生適意耳，何必駟馬車。"]'),
('99990e45-328b-4b0c-b2ec-f94ee4cc41b2','水竹墅十詠 尋源橋','葉茵','宋','宋诗','song-poetry','','[]','躞蹀水窮處，雞犬非人間。',24,'全唐诗/poet.song.211000.json','["躞蹀水窮處，雞犬非人間。", "褰裳不用涉，迤邐逃秦山。"]'),
('3a4c78e0-5feb-4901-b375-2f858a85423a','愛閒亭','葉茵','宋','宋诗','song-poetry','','[]','苔深雨徑寒，花落徑斕斑。',48,'全唐诗/poet.song.211000.json','["苔深雨徑寒，花落徑斕斑。", "此處無名利，誰人肯往還。", "性慵棋局廢，坐久茗甌閒。", "禪觀非難事，休官學住山。"]'),
('59daed16-1dbb-44c7-9d3a-74c9c8cb549d','江湖偉觀','葉茵','宋','宋诗','song-poetry','','[]','此地舊寒碧，留題護竹君。',48,'全唐诗/poet.song.211000.json','["此地舊寒碧，留題護竹君。", "窗虛不礙月，壁老易生雲。", "一水東西隔，兩山南北分。", "未堪低著眼，世事正紛紛。"]'),
('dbe8954c-182b-443c-8e3b-798ea40e9c82','何氏書堂','葉茵','宋','宋诗','song-poetry','','[]','千歲松陰護一亭，風來猶带讀書聲。',64,'全唐诗/poet.song.211000.json','["千歲松陰護一亭，風來猶带讀書聲。", "雖無芳史摹勳業，自有青山說姓名。", "客撫豐碑苔剝落，春歸暗徑草生成。", "幾年訪古謀清隠，好借虛簷著短檠。"]'),
('db9c56fc-9360-432b-a564-36bf9bae95d6','天平山謁范文正祠登白雲亭','葉茵','宋','宋诗','song-poetry','','[]','爲謁先儒馬鬣塋，倚藤得得上天平。',64,'全唐诗/poet.song.211000.json','["爲謁先儒馬鬣塋，倚藤得得上天平。", "直疑寺外崚嶒石，猶是胸中數萬兵。", "松障四開心目快，山泉一歃骨毛清。", "坐間恰動思親念，隠隠白雲何處生。"]'),
('73b1cc56-24f2-4dea-b6ce-d83cddd71141','次林和靖先生梅韻','葉茵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','世上羣芳未敢妍，獨將春色占南園。',64,'全唐诗/poet.song.211000.json','["世上羣芳未敢妍，獨將春色占南園。", "生來清質十分瘦，肯受紅塵一點昏。", "東閣詩成應動興，西湖僊去謾招魂。", "便須結客陪花笑，句引幽香入酒尊。"]'),
('3d72e7f1-2efa-43e1-8665-fe8bccd7fae9','蟠松靈巖寺草堂之前舊有蟠松尤古','葉茵','宋','宋诗','song-poetry','','[]','一畝清陰覆客衣，相逢疑是草堂時。',64,'全唐诗/poet.song.211000.json','["一畝清陰覆客衣，相逢疑是草堂時。", "隠然錯節盤根勢，欠者昂霄聳壑姿。", "天遣蟄龍憑石窟，人攀巢鶻俯霜枝。", "百年培植今誰屬，何待歲寒然後知。"]'),
('c5afb7ab-f372-4872-bc2b-dcdaaf0fd2df','寄所思','葉茵','宋','宋诗','song-poetry','','[]','淅淅竹下風，活活橋畔水。',72,'全唐诗/poet.song.211000.json','["淅淅竹下風，活活橋畔水。", "蕭蕭掩柴荆，去去隠君子。", "夙夜勞我思，之德洵且美。", "瞻彼南山阿，有桂發叢蘂。", "奮手折其榮，懷袖香盈只。", "願爲靈鵲飛，遞聲入君耳。"]'),
('e247bfab-31fe-4a82-b2ec-2aa419ab60e2','春去','葉茵','宋','宋诗','song-poetry','','[]','幾陣紅侵野草，一團綠染庭槐。',28,'全唐诗/poet.song.211000.json','["幾陣紅侵野草，一團綠染庭槐。", "夢裏未知春去，翩翩胡蝶飛來。"]'),
('0dc21f09-db10-4686-bc16-88a7f948ffdd','歸途','葉茵','宋','宋诗','song-poetry','','[]','春來天氣半陰晴，那更奔馳一月程。',32,'全唐诗/poet.song.211000.json','["春來天氣半陰晴，那更奔馳一月程。", "又恐花時成草草，還家插柳佐清明。"]'),
('bdb7e785-4af1-4f26-9ad8-10d93100d280','山行','葉茵','宋','宋诗','song-poetry','','[]','青山不識我姓字，我亦不識青山名。',32,'全唐诗/poet.song.211000.json','["青山不識我姓字，我亦不識青山名。", "飛來白鳥似相識，對我對山三兩聲。"]'),
('210efd6d-5bd3-4579-908f-cd96065399bc','次出郊韻','葉茵','宋','宋诗','song-poetry','','[]','支藤乘興入春郊，梅壓疎籬亞竹梢。',32,'全唐诗/poet.song.211000.json','["支藤乘興入春郊，梅壓疎籬亞竹梢。", "剩喜此行詩有料，吟來渾不費推敲。"]'),
('34d87ef1-53c1-47e6-b291-4febbc4dde5f','生日口占','葉茵','宋','宋诗','song-poetry','','[]','舉室相先起五更，爲翁誕日壽金觥。',32,'全唐诗/poet.song.211000.json','["舉室相先起五更，爲翁誕日壽金觥。", "癡兒未識翁年甲，五十年前今夜生。"]'),
('e9d9b5bb-a1c7-4542-9b71-6eb74e6aabfe','酒邊次趙東閣韻','葉茵','宋','宋诗','song-poetry','','[]','竹褪粉痕新，銷磨九十春。',48,'全唐诗/poet.song.211000.json','["竹褪粉痕新，銷磨九十春。", "中年真率性，上古太平人。", "有夢詩將聖，無愁酒不神。", "靜看紅紫路，翻覆幾回塵。"]'),
('9bd0413b-4424-4a4b-abeb-416859f1bc07','友人自淮至','葉茵','宋','宋诗','song-poetry','','[]','別子若爲久，於心終不忘。',48,'全唐诗/poet.song.211000.json','["別子若爲久，於心終不忘。", "一杯評舊雨，兩鬢對新霜。", "客裏春行早，愁邊夜坐長。", "明時成擯棄，無語及淮鄉。"]'),
('a456b1dc-2224-4261-898f-f32fb0cf9d9d','霅城','葉茵','宋','宋诗','song-poetry','','[]','愛向其中艤短篷，眼前景物總玲瓏。',64,'全唐诗/poet.song.211000.json','["愛向其中艤短篷，眼前景物總玲瓏。", "神僊窟宅垂楊裏，圖畫溪山落照中。", "甚是繁華輸俠少，也須幽勝屬衰翁。", "世間風月無如此，賣鶴來謀地一弓。"]'),
('7d5c8e22-504e-4001-8a70-b7658dbb699b','次中秋不見月韻','葉茵','宋','宋诗','song-poetry','','[]','五分秋色到銀河，應是蟾蜍浴細波。',64,'全唐诗/poet.song.211000.json','["五分秋色到銀河，應是蟾蜍浴細波。", "握手相期千里共，舉頭無柰片雲何。", "愁邊幸自逢歡伯，清處何須著艷娥。", "未可來宵倦游賞，光輝依舊向人多。"]'),
('12127077-d0e8-4877-b31c-a626adff3a6d','雨中梅','葉茵','宋','宋诗','song-poetry','','[]','竛竮竹外枝，啼妝凌曉霰。',24,'全唐诗/poet.song.211000.json','["竛竮竹外枝，啼妝凌曉霰。", "東君不主盟，對人作此面。"]'),
('d4f9ab02-dfe2-4fc2-b061-df769c049990','即事','葉茵','宋','宋诗','song-poetry','','[]','竹暗筍無數，江晴水有痕。',24,'全唐诗/poet.song.211000.json','["竹暗筍無數，江晴水有痕。", "田蛙喧麥隴，野犬卧柴門。"]'),
('40a733ca-baea-4ee5-93f1-a6bdeb16b310','過溪','葉茵','宋','宋诗','song-poetry','','[]','筍輿軋軋亂山中，籬落桃花潑眼紅。',32,'全唐诗/poet.song.211000.json','["筍輿軋軋亂山中，籬落桃花潑眼紅。", "小駐渡頭呼艇子，一溪淺綠漾晴風。"]'),
('e579d427-ee05-447b-bb86-538a549a6312','白髮','葉茵','宋','宋诗','song-poetry','','[]','半世持竿笠澤濱，鬢邊留得幾莖春。',32,'全唐诗/poet.song.211000.json','["半世持竿笠澤濱，鬢邊留得幾莖春。", "近來白髮無公道，暗把黑頭饒貴人。"]'),
('e6424af6-2602-496d-8cd9-0f6bf9c77499','泊舟溪口','葉茵','宋','宋诗','song-poetry','','[]','萬柳陰中繫客船，桑條如竹葉如錢。',32,'全唐诗/poet.song.211000.json','["萬柳陰中繫客船，桑條如竹葉如錢。", "大姑小婦挑甘薺，摇手烏兒正二眠。"]'),
('daa0ac79-9497-41e3-a63e-920bc5202e15','賦順適堂','葉茵','宋','宋诗','song-poetry','','[]','暗觸少陵機，茅居峙竹扉。',48,'全唐诗/poet.song.211000.json','["暗觸少陵機，茅居峙竹扉。", "安時貧亦樂，聞道詠而歸。", "鳬鶴從長短，鳶魚自躍飛。", "吾猶臧穀耳，夷跖是耶非。"]'),
('8c120552-5e27-43d8-be98-4a9c7aa547e1','除夜立春','葉茵','宋','宋诗','song-poetry','','[]','別歲傳佳話，論文憶舊盟。',48,'全唐诗/poet.song.211000.json','["別歲傳佳話，論文憶舊盟。", "黄柑凝臘釀，爆竹带春聲。", "節序有終始，兒童爭送迎。", "此身强健在，列炬到天明。"]'),
('ff4c1ac9-e570-4ad3-8f0d-8f56c4da0963','梅','葉茵','宋','宋诗','song-poetry','','[]','疎影幾黄昏，明明野水濱。',48,'全唐诗/poet.song.211000.json','["疎影幾黄昏，明明野水濱。", "未風先信息，無雪更精神。", "一白見真色，萬紅隨後塵。", "自來花下飲，肺腑盡生春。"]'),
('ade4aec5-633c-4508-8b69-d18dd928dc16','晉子生日','葉茵','宋','宋诗','song-poetry','','[]','今朝阿晉紀桑弧，郎罷持杯勉讀書。',64,'全唐诗/poet.song.211000.json','["今朝阿晉紀桑弧，郎罷持杯勉讀書。", "斷莫繞家覓梨栗，更須爲國習耘鉏。", "義方授汝心還愧，陰德於予計肯疎。", "學取老萊如許壽，年年綵袖拜庭除。"]'),
('2e02027e-af74-4356-bbe3-5af0f11d135c','自和','葉茵','宋','宋诗','song-poetry','','[]','壯士須張燕角弧，男兒須誦聖人書。',64,'全唐诗/poet.song.211000.json','["壯士須張燕角弧，男兒須誦聖人書。", "譬如田叟祈多稼，未有春時不荷鉏。", "分內功名從早晚，腹中學問怕空疎。", "老夫猶記昌黎語，潢潦朝盈夕已除。"]'),
('0c6ec058-06f2-4dcb-b100-b125d20d0bc6','又','葉茵','宋','宋诗','song-poetry','','[]','一鴈雲間落勁弧，經秋不見寄來書。',64,'全唐诗/poet.song.211000.json','["一鴈雲間落勁弧，經秋不見寄來書。", "人情自昔如翻紙，世道從今甚借鉏。", "鹿夢隍中知得喪，爵羅門外看親疎。", "歲寒獨有梅花月，香影年年到戶除。"]'),
('370d8af7-3d54-4e5f-834f-a0f400b61dc5','別可山','葉茵','宋','宋诗','song-poetry','','[]','松江之左，可漁可農。',240,'全唐诗/poet.song.211000.json','["松江之左，可漁可農。", "古樹陰陰，碧波溶溶。", "子契予好，携家而從。", "載笑載語，乃棹輕篷。", "冥訪前脩，天隨室邇。", "中心孔嘉，爰居爰止。", "有薰自南，景物清美。", "槐柳于前，煩歊潜弭。", "我有旨酒，與子酌之。", "既醉且舞，且歌而詩。", "陶然樂只，厥情怡怡。", "一日舍去，豈不念茲。", "客懷先秋，興言欲別。", "屢止屢辭，行計已决。", "送子于舟，期我乎雪。", "敬哉前邁，于時炎熱。", "惆悵若失，延佇長津。", "復面猶賒，柰何夕晨。", "豈無他友，白首如新。", "念子實繁，融融天真。", "北山有梅，南山有雲。", "下有猿鶴，中有隠君。", "千里命駕，予敢不厪。", "乃志必獲，載歌斯文。"]'),
('6ca033ba-a659-48df-aa33-93d8e90431cb','止菴','葉茵','宋','宋诗','song-poetry','','[]','時事艱難路險巇，得來名利亦何爲。',32,'全唐诗/poet.song.211000.json','["時事艱難路險巇，得來名利亦何爲。", "趙州茶罷速歸去，莫待鐘鳴漏盡時。"]'),
('d811802d-28ac-485b-94f8-a3f85b648111','讀釣臺集','葉茵','宋','宋诗','song-poetry','','[]','萬仞山頭放一絲，爭吟好句記當時。',32,'全唐诗/poet.song.211000.json','["萬仞山頭放一絲，爭吟好句記當時。", "能詩若不能垂釣，祗恐先生不受詩。"]'),
('49815447-b9b7-4c06-8565-dcb8d33d2611','遊西洞庭山','葉茵','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','漫遊三十載，屐齒暈蒼苔。',48,'全唐诗/poet.song.211000.json','["漫遊三十載，屐齒暈蒼苔。", "兩地無多里，一生能幾回。", "洞深龍未蟄，丹熟竈無灰。", "已覺忘身世，松梢有鶴來。"]'),
('09d8ead7-7c88-4c33-89c8-70a91aa376af','山行','葉茵','宋','宋诗','song-poetry','','[]','未了行春債，因哦遣興詩。',48,'全唐诗/poet.song.211000.json','["未了行春債，因哦遣興詩。", "寒多啼鳥噤，路滑蹇馿遲。", "久雨紅辭樹，深林綠授枝。", "驚心衰朽日，容易過花時。"]'),
('9d2d4aa8-872d-4764-9e07-587a9340fcb7','入山','葉茵','宋','宋诗','song-poetry','','[]','到來非俗境，一片隠心生。',48,'全唐诗/poet.song.211000.json','["到來非俗境，一片隠心生。", "曉霧沈山色，春禽和水聲。", "逢人多古貌，對語率真情。", "同在無懷世，爐熏答聖明。"]'),
('cb32ad7f-6b3e-45d4-8ddc-7b4a59b3f956','蟬','葉茵','宋','宋诗','song-poetry','','[]','柳外聲殘日未殘，棲身未穩擇枝安。',32,'全唐诗/poet.song.211000.json','["柳外聲殘日未殘，棲身未穩擇枝安。", "不須過有螳螂慮，黄雀從傍冷眼看。"]'),
('28fda336-7310-4c08-b125-a1bd91ec406c','螢','葉茵','宋','宋诗','song-poetry','','[]','自明自滅度方池，熠熠飛來去覺遲。',32,'全唐诗/poet.song.211000.json','["自明自滅度方池，熠熠飛來去覺遲。", "入坐點衣情分熟，納交元在讀書時。"]'),
('edda2350-6415-4997-aeff-89030cc7ab2a','蟬','葉茵','宋','宋诗','song-poetry','','[]','壁間吟不待秋時，吟苦中宵動客悲。',32,'全唐诗/poet.song.211000.json','["壁間吟不待秋時，吟苦中宵動客悲。", "勸汝不須催婦織，家家五月賣新絲。"]'),
('f6868d50-f9b0-46b9-8885-c6fc36c901a2','酷暑','葉茵','宋','宋诗','song-poetry','','[]','動息汗流珠，無風可滌除。',48,'全唐诗/poet.song.211000.json','["動息汗流珠，無風可滌除。", "炎威獄下吏，生意鼎中魚。", "席地抔冰水，扃門謝客車。", "因思游宦者，曾未憶家居。"]'),
('57b6524d-03dd-4b79-bb4c-7c9afe0c043b','秋至','葉茵','宋','宋诗','song-poetry','','[]','節序暗推移，清商漸戒期。',53,'全唐诗/poet.song.211000.json','["節序暗推移，清商漸戒期。", "旅懷{萘示=虫}早計，凉信柳先知。", "萬事到雙鬢，餘生消幾詩。", "最憐梁上燕，巢穩又歸時。"]'),
('94b29aa4-b2d2-4a47-bb7b-763fa4d2a0f9','苦雨','葉茵','宋','宋诗','song-poetry','','[]','農事正紛紛，天時异所聞。',48,'全唐诗/poet.song.211000.json','["農事正紛紛，天時异所聞。", "舉頭方見日，翻手又爲雲。", "茅舍蛙分部，槐庭蟻失羣。", "裁成憂國疏，齋沐告吾君。"]'),
('88fd39a6-4915-434d-bc96-72b754ae129e','出郊','葉茵','宋','宋诗','song-poetry','','[]','多謝天公佐好晴，只今載酒作郊行。',64,'全唐诗/poet.song.211000.json','["多謝天公佐好晴，只今載酒作郊行。", "飛花戀客閒中意，遠笛吟春景外聲。", "已把物情歸幻相，且將足力趁浮生。", "南堂辦得休休計，燕雀充庭亦賀成。"]'),
('bac5738b-f7f6-4f9b-83b9-54b8977f7eeb','謝朱宜中隸字','葉茵','宋','宋诗','song-poetry','','[]','隸法如公有典刑，拙中藏巧混天成。',64,'全唐诗/poet.song.211000.json','["隸法如公有典刑，拙中藏巧混天成。", "因觀體製超前輩，旋闢軒窗乞扁名。", "氣象晉人遒且勁，源流漢刻古而清。", "得來喜對兒曹語，一字千金勝滿籯。"]'),
('541726b6-d2ed-40f1-91e6-6a122619c12f','鱸膾','葉茵','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','圉圉洞庭陰，西風苦不情。',120,'全唐诗/poet.song.211000.json','["圉圉洞庭陰，西風苦不情。", "墮罾雲葉亂，落刃雪花明。", "列俎移桃菊，香齏搗桂橙。", "四腮傳雅詠，巨口竊嘉名。", "誤上僊翁釣，羞陪虜使觥。", "甘腴殊机肉，鮮脆厭侯鯖。", "銀鯽將同調，絲蓴久共盟。", "祗緣鄉味重，自覺宦情輕。", "風度偏宜酒，頭顱尚可羹。", "謫僊空汗漫，何處膾長鯨。"]'),
('32fb6d97-84f3-473b-a581-59456551d804','竹夫人','葉茵','宋','宋诗','song-poetry','','[]','風神林下秀，寵數夢中新。',48,'全唐诗/poet.song.211000.json','["風神林下秀，寵數夢中新。", "假使不如肉，爭知見似人。", "茗奴甘謝事，黄妳喜論親。", "凜凜百年操，從教進退頻。"]'),
('3b5a8123-38c0-46aa-94b1-827ec131cbb9','城下小菴','葉茵','宋','宋诗','song-poetry','','[]','水緣城詰曲，水際暗桑麻。',48,'全唐诗/poet.song.211000.json','["水緣城詰曲，水際暗桑麻。", "籬落深村路，閭閻處士家。", "煙篁黏半籜，風柳颺輕花。", "隨喜跏趺坐，香寒月影斜。"]'),
('79235625-b8ef-48ce-99e4-e2b568eaa162','棹雪','葉茵','宋','宋诗','song-poetry','','[]','放船中流天模糊，淅淅霎霎鳴茭蘆。',100,'全唐诗/poet.song.211000.json','["放船中流天模糊，淅淅霎霎鳴茭蘆。", "萬頃剎那成玉壺，柔艣蕩漾歌吳歈。", "老漁直前相招呼，骨相子猷洵且都。", "其人豈是斯人徒，相顧而笑掀虬鬚。", "汝爲汝兮吾非吾，剡溪風景今何如。", "誰能爲人作畫圖，予方奮臂持竿獨釣于江湖。"]'),
('739060eb-50dc-4d4a-902b-b63024c13416','壽藏十韻','葉茵','宋','宋诗','song-poetry','','[]','門限何須鐵，因爲淺近謀。',120,'全唐诗/poet.song.211000.json','["門限何須鐵，因爲淺近謀。", "假令長富貴，消得幾春秋。", "壽固緣心地，人誰免首丘。", "子能忘後慮，是亦慕前脩。", "繭室名猶在，魚山志可求。", "迴岡許埋骨，吉兆協眠牛。", "懶作化臺號，何妨引客遊。", "不愁飽螻蟻，最喜近松楸。", "物變終於盡，吾生行且休。", "年年春色裏，洗勺聽溪流。"]'),
('26d4624e-dee4-4272-b3be-c2ed126d67ef','田父吟五首  其一','葉茵','宋','宋诗','song-poetry','','[]','去年積潦苦無收，今歲逢人說有秋。',32,'全唐诗/poet.song.211000.json','["去年積潦苦無收，今歲逢人說有秋。", "未擬香秔供一飽，穇穇新藁蓋簷頭。"]'),
('0050fd8d-87bb-4f7f-b541-99e986b99097','田父吟五首  其二','葉茵','宋','宋诗','song-poetry','','[]','夜登車桁晝耘秧，怕說風傷與水傷。',32,'全唐诗/poet.song.211000.json','["夜登車桁晝耘秧，怕說風傷與水傷。", "歷盡艱辛雙鬢白，今秋方覺稻花香。"]'),
('4ac0be67-5fa1-49b1-9b40-7cb6206cd335','田父吟五首  其三','葉茵','宋','宋诗','song-poetry','','[]','老天應是念農夫，萬頃黄雲著地鋪。',32,'全唐诗/poet.song.211000.json','["老天應是念農夫，萬頃黄雲著地鋪。", "有穀未爲兒女計，半償私債半官租。"]'),
('524cf0e9-4537-4170-af18-15b16fb1de22','田父吟五首  其四','葉茵','宋','宋诗','song-poetry','','[]','記得年時竈不煙，土倉今番遶門邊。',32,'全唐诗/poet.song.211000.json','["記得年時竈不煙，土倉今番遶門邊。", "已占此後無憂色，綠遍村前菜麥田。"]'),
('3d311e61-b986-440b-ad45-717785c84621','田父吟五首  其五','葉茵','宋','宋诗','song-poetry','','[]','逢逢社鼓佐豐年，酒熟那逢釀雪天。',32,'全唐诗/poet.song.211000.json','["逢逢社鼓佐豐年，酒熟那逢釀雪天。", "擘橘煮雞償一醉，布衾烘暖抱孫眠。"]'),
('2e2a131c-d296-48c8-b3c1-75e98acf7502','林可山至','葉茵','宋','宋诗','song-poetry','','[]','梅花山底伴雲閒，謾逐閒雲出故山。',32,'全唐诗/poet.song.211000.json','["梅花山底伴雲閒，謾逐閒雲出故山。", "君慰我思君莫去，一詩先遣白雲還。"]'),
('18ebadfd-1481-45a3-8a7f-28c120d1c65b','雜興二首  其一','葉茵','宋','宋诗','song-poetry','','[]','兀兀北窗下，嘈嘈林間鳴。',48,'全唐诗/poet.song.211000.json','["兀兀北窗下，嘈嘈林間鳴。", "聲各奏小大，諒亦隨其形。", "倏然氣肅冽，一夕俱沈冥。", "試語塵中士，細聽秋蟲聲。"]'),
('40eaf2c7-c3d7-4b8f-a1ea-62f388089d4d','雜興二首  其二','葉茵','宋','宋诗','song-poetry','','[]','七十云古希，予年三之二。',48,'全唐诗/poet.song.211000.json','["七十云古希，予年三之二。", "來景殊無多，那復就枯瘁。", "窘步驚畏途，撫心慨時事。", "何以怡餘生，一日委一醉。"]'),
('1cde6bf0-7a6e-4960-a5eb-70a0f67832ff','垂虹亭','葉茵','宋','宋诗','song-poetry','','[]','東西耕釣窟，左右利名津。',24,'全唐诗/poet.song.211000.json','["東西耕釣窟，左右利名津。", "倚遍闌干曲，知幾有幾人。"]'),
('699f025c-8738-47ff-8bdd-c065964f48ff','鱸鄉道院','葉茵','宋','宋诗','song-poetry','','[]','田可耕兮圃可蔬，幾年夢不到亨衢。',64,'全唐诗/poet.song.211000.json','["田可耕兮圃可蔬，幾年夢不到亨衢。", "山林受用琴書鶴，天地交遊風月吾。", "事變無涯人老矣，死生有命汝知乎。", "客來時復一杯酒，畫作鱸鄉醉隠圖。"]'),
('2f1bfbd5-3a24-4d42-b13a-ebfaa5358faa','送徐兄訪陳宰','葉茵','宋','宋诗','song-poetry','','[]','投老持竿柳外村，尺書久不抵脩門。',32,'全唐诗/poet.song.211000.json','["投老持竿柳外村，尺書久不抵脩門。", "料應下榻從容日，自說通家好子孫。"]'),
('4eb5ff62-e608-4347-a8b0-66265427fe4f','山行','葉茵','宋','宋诗','song-poetry','','[]','舍棹入山村，山深樹自繁。',48,'全唐诗/poet.song.211000.json','["舍棹入山村，山深樹自繁。", "短歌田舍樂，長揖野人尊。", "苔老雲生石，松高月闖門。", "不聞名利語，太古一乾坤。"]'),
('ad5a2949-4bdd-4804-84aa-69512339da46','瀟湘八景圖 平沙鴈落','葉茵','宋','宋诗','song-poetry','','[]','江風飄塵白如練，征翰遠赴蘆花岸。',64,'全唐诗/poet.song.211000.json','["江風飄塵白如練，征翰遠赴蘆花岸。", "寒霧昏昏漁火明，欲飛不飛行陣亂。", "相從萬里多崎嶇，呼鳴警察夜有奴。", "衡陽路杳速歸去，未可容易來江湖。"]'),
('f97850fd-bf97-4df7-be65-a32ba7868b34','瀟湘八景圖 遠浦帆歸','葉茵','宋','宋诗','song-poetry','','[]','水天冥冥日催暮，輕蒲飽風疾飛羽。',64,'全唐诗/poet.song.211000.json','["水天冥冥日催暮，輕蒲飽風疾飛羽。", "回頭遥指舟前灣，浪急篷欹下柔艣。", "稠楊枯桑深處村，老妻挾兒環在門。", "蓴羹香滑茅柴熟，對語別時應斷魂。"]'),
('f247951f-813c-43ec-839f-9d726a97f55a','瀟湘八景圖 山市晴嵐','葉茵','宋','宋诗','song-poetry','','[]','巖麓新霽浮紫烟，幾家雞犬喧一鄽。',64,'全唐诗/poet.song.211000.json','["巖麓新霽浮紫烟，幾家雞犬喧一鄽。", "憧憧人得蠅頭利，不了青帘酤酒錢。", "松陰散亂日易暝，風光漸入牛羊徑。", "赬肩赤脚分途歸，野唱樵歌動幽聽。"]'),
('621573d6-14eb-4af9-b1a2-98847b454632','瀟湘八景圖 江天暮雪','葉茵','宋','宋诗','song-poetry','','[]','癡雲貼水天四垂，寒鴉凍雀無樹棲。',64,'全唐诗/poet.song.211000.json','["癡雲貼水天四垂，寒鴉凍雀無樹棲。", "紛紛萬頃水花亂，光眩銀海迷東西。", "中有輕舠移斷浦，玉笠瓊蓑一漁父。", "鼓枻而歌歌豐年，田家有麥無愁苦。"]'),
('da52c31e-e619-4ec1-855b-7e85dfa99e01','瀟湘八景圖 洞庭秋月','葉茵','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','長波淼淼七百里，蒹葭颯颯西風起。',64,'全唐诗/poet.song.211000.json','["長波淼淼七百里，蒹葭颯颯西風起。", "玉輪輾出琉璃宮，碧落空明無表裏。", "幾峯森列青崔嵬，不知人世皆塵埃。", "夜深絲竹遞清響，疑是楚王曾歸來。"]'),
('c4d8e3de-dc82-4cf1-b50e-68fef860b51c','瀟湘八景圖 瀟湘夜雨','葉茵','宋','宋诗','song-poetry','','[]','雲氣浮江天已夕，江樹號風飛雨迫。',64,'全唐诗/poet.song.211000.json','["雲氣浮江天已夕，江樹號風飛雨迫。", "淒涼正則賦懷沙，疑與漁翁分半席。", "一聲曖迺隔中流，打篷淅霎添旅愁。", "土膏動脈曉色媚，農將有事于西疇。"]'),
('0bb50e24-bb85-4ac9-92f2-3919ac2180ee','瀟湘八景圖 烟寺晚鐘','葉茵','宋','宋诗','song-poetry','','[]','冥濛一抹籠崢嶸，崢嶸深處傳疎聲。',64,'全唐诗/poet.song.211000.json','["冥濛一抹籠崢嶸，崢嶸深處傳疎聲。", "溪橫古槎低欲折，隠約前村通去程。", "萬里征夫不知宿，數盡飛鴉栖古木。", "輸與中邊三四僧，枯藤挑雲歸佛屋。"]'),
('9cf8f8fb-3ddb-4684-90fd-7216dbd20521','瀟湘八景圖 漁村夕照','葉茵','宋','宋诗','song-poetry','','[]','家家傍水開柴扉，綠楊影裏沈斜暉。',64,'全唐诗/poet.song.211000.json','["家家傍水開柴扉，綠楊影裏沈斜暉。", "妻炊黄粱子挂網，獨枕莓苔眠釣磯。", "得魚博錢平生志，世間寵辱不能累。", "路近桃源多裔孫，定知秦晉興亡事。"]'),
('9cb1dad0-ff68-4281-b7e6-30a958d7695f','古意二首  其一','葉茵','宋','宋诗','song-poetry','','[]','逝波不可迴，白鳥不可馴。',24,'全唐诗/poet.song.211000.json','["逝波不可迴，白鳥不可馴。", "古人成感慨，今人猶古人。"]'),
('b963ca5c-891d-4df2-91ee-ded38dad6571','古意二首  其二','葉茵','宋','宋诗','song-poetry','','[]','境空納風月，心遠辭埃塵。',24,'全唐诗/poet.song.211000.json','["境空納風月，心遠辭埃塵。", "終日窮目力，得景亡天真。"]'),
('fbd69301-f80f-4447-a692-796a1836f8ac','次韻','葉茵','宋','宋诗','song-poetry','','[]','生涯老布衾，清處更清吟。',48,'全唐诗/poet.song.211000.json','["生涯老布衾，清處更清吟。", "舊事即新夢，今人非古心。", "意行雙謝屐，道在一陶琴。", "誰解無名利，其中有淺深。"]'),
('239773f0-353f-432d-945e-ddd40498d555','次池亭韻','葉茵','宋','宋诗','song-poetry','','[]','憑虛結草亭，占得古來清。',48,'全唐诗/poet.song.211000.json','["憑虛結草亭，占得古來清。", "睡債茶驅遣，詩情酒發明。", "梅撐拳石瘦，蘆障一闌平。", "未盡逍遥意，重尋枕簟盟。"]'),
('a0b8d505-b300-47d8-9c48-f7a1db09194e','秀實長子玉麟朞晬','葉茵','宋','宋诗','song-poetry','','[]','門左蓬弧喜事新，四朝先佛慶生辰。',64,'全唐诗/poet.song.211000.json','["門左蓬弧喜事新，四朝先佛慶生辰。", "嶢嶢已露峙頭玉，表表因名繫角麟。", "鼻祖同庚光後葉，卯君著瑞定前身。", "我來摩頂爲兒壽，一歲從今百歲春。"]'),
('29496ac4-3a0f-46b9-bcdc-c4a0bf463e0f','琉璃砲燈','葉茵','宋','宋诗','song-poetry','','[]','體製先天太極圖，燈籠真是水晶無。',64,'全唐诗/poet.song.211000.json','["體製先天太極圖，燈籠真是水晶無。", "遠看玉兔光中魄，近得驪龍頷下珠。", "一焰空明疑火燧，寸波靜定即冰壺。", "游魚且作沈潛計，鱗甲成時入五湖。"]'),
('4cc07e37-cf75-4a7e-8196-d2868ddbfcec','幼弟墓下','葉茵','宋','宋诗','song-poetry','','[]','春到棣無色，風來松亦悲。',48,'全唐诗/poet.song.211000.json','["春到棣無色，風來松亦悲。", "細看雲起處，不復鴈歸時。", "憶汝九京隔，嗟予兩鬢衰。", "寥寥今古意，獨許杜陵知。"]'),
('b5cb6fb8-1f7f-49c9-9266-e8283c7ef0fb','室人墓下','葉茵','宋','宋诗','song-poetry','','[]','楚愴埋香地，卿須念藁砧。',48,'全唐诗/poet.song.211000.json','["楚愴埋香地，卿須念藁砧。", "齊眉中道訣，同穴百年心。", "刀尺凝餘澤，松梧带老陰。", "可能如饁婦，相對白頭吟。"]'),
('e2c0d905-2a61-4f2c-a91d-ae255898744d','次孫花翁韻','葉茵','宋','宋诗','song-poetry','','[]','湖海幾經年，論交豈偶然。',48,'全唐诗/poet.song.211000.json','["湖海幾經年，論交豈偶然。", "坐間尊島佛，客裏識坡仙。", "解使狂心服，還羞懶腹便。", "拈來唐句法，玄入小乘禪。"]'),
('f921b578-ec1c-4cdc-bf39-20b695a7f8c6','吳江三高祠 范蠡','葉茵','宋','宋诗','song-poetry','','["\u592a\u6e56"]','越敢吞吳皆范子，後來廟食太湖濱。',32,'全唐诗/poet.song.211000.json','["越敢吞吳皆范子，後來廟食太湖濱。", "邦人豈是忘仇怨，要勉吳臣似越臣。"]'),
('12d7b76d-2aeb-4ce5-8334-d23714732ead','吳江三高祠 張翰','葉茵','宋','宋诗','song-poetry','','[]','膾鱸元不動鄉思，拂袖西風已見幾。',32,'全唐诗/poet.song.211000.json','["膾鱸元不動鄉思，拂袖西風已見幾。", "江上如今來往客，但言鱸膾不言歸。"]'),
('4e39ae9c-8af1-443c-abc6-7d61a0d527bc','吳江三高祠 陸龜蒙','葉茵','宋','宋诗','song-poetry','','[]','江湖蕭散樂平生，夜課圖書日課耕。',32,'全唐诗/poet.song.211000.json','["江湖蕭散樂平生，夜課圖書日課耕。", "一段高風猶凜凜，逢人肯說鴨呼名。"]'),
('77e89442-e889-444c-8c4d-b92b34bea51b','欲別','葉茵','宋','宋诗','song-poetry','','[]','欲別哽無語，蘸酒評歸期。',24,'全唐诗/poet.song.211000.json','["欲別哽無語，蘸酒評歸期。", "潮汐有朝暮，郎心無轉移。"]'),
('173d3cb0-1642-40e7-b542-70bc9e00b7bd','次韻','葉茵','宋','宋诗','song-poetry','','[]','懶作千年調，偷閒得幾回。',48,'全唐诗/poet.song.211000.json','["懶作千年調，偷閒得幾回。", "吟壇元不峻，俗駕可曾來。", "蘚碧牆陰合，榴紅屋角開。", "枕肱真樂在，飲水當傳杯。"]'),
('f03797c3-4a43-4a14-abb8-bed419bb6cb3','夜坐偶成','葉茵','宋','宋诗','song-poetry','','[]','蓴鱸江上鄉，穩處著虛堂。',48,'全唐诗/poet.song.211000.json','["蓴鱸江上鄉，穩處著虛堂。", "却掃百念息，貪吟萬景忙。", "螢流風戶牖，蛙閙雨池塘。", "夢熟田家事，牛衣趁蒔秧。"]'),
('e68c3d52-cfbc-4e11-b951-364134bca756','次月蝕韻','葉茵','宋','宋诗','song-poetry','','[]','起來搔首夜如何，瞥見蝦蟇影裏過。',64,'全唐诗/poet.song.211000.json','["起來搔首夜如何，瞥見蝦蟇影裏過。", "幸自十分懸素魄，豈應一息駐妖魔。", "光清於水塵難滓，色白如圭玷可磨。", "休誦玉川艱險句，終篇比興爲元和。"]'),
('8efdc65a-0f09-4931-9720-ea8a5aa7e18e','次弔原韻','葉茵','宋','宋诗','song-poetry','','[]','爲憐舉世不曾醒，放浪形骸澤畔行。',64,'全唐诗/poet.song.211000.json','["爲憐舉世不曾醒，放浪形骸澤畔行。", "會得危言危行意，佐成濯足濯纓名。", "義無可去緣同姓，心亦何求要獨清。", "今日龍舟雖古意，吳人未必楚人情。"]'),
('6cd4e13e-26b8-4bb1-9ba9-25e9863b08f2','笑靨花','葉茵','宋','宋诗','song-poetry','','[]','蔟蔟瓊瑶屑，花神點綴工。',24,'全唐诗/poet.song.211000.json','["蔟蔟瓊瑶屑，花神點綴工。", "似知吟興動，滿面是春風。"]'),
('803c9b95-82e7-4f3f-9481-fdc7174ec585','涵空閣','葉茵','宋','宋诗','song-poetry','','[]','浪說涵空未是空，一闌羅列幾巃嵸。',32,'全唐诗/poet.song.211000.json','["浪說涵空未是空，一闌羅列幾巃嵸。", "世人若問空中景，此景從來是夢中。"]'),
('a36d3574-d80a-4bc5-9cbb-b8dd0d2c0d17','草堂','葉茵','宋','宋诗','song-poetry','','[]','幾年蝸蚓占山扉，喚轉風光似舊時。',32,'全唐诗/poet.song.211000.json','["幾年蝸蚓占山扉，喚轉風光似舊時。", "從此禪門多事在，篆香重課少陵詩。"]'),
('5cd7e7a4-ff44-4f13-b955-4d84340baa0f','琴堂','葉茵','宋','宋诗','song-poetry','','[]','片石鄰空掌樣平，吳兒曾此御瑶琴。',32,'全唐诗/poet.song.211000.json','["片石鄰空掌樣平，吳兒曾此御瑶琴。", "琴中腔調誰人識，獨有顰妃是賞音。"]'),
('ca256639-089b-4d43-9f96-26debd8aa0f7','洗妝池','葉茵','宋','宋诗','song-poetry','','[]','離宮脂粉尚穠香，人去僧來歲月長。',32,'全唐诗/poet.song.211000.json','["離宮脂粉尚穠香，人去僧來歲月長。", "鐘磬咒成功德水，根塵洗盡水清凉。"]'),
('394e95b3-a109-4a63-8e66-d0124ec49a66','卓筆峰','葉茵','宋','宋诗','song-poetry','','[]','疑是飛來天柱峯，一尖秀出白雲中。',32,'全唐诗/poet.song.211000.json','["疑是飛來天柱峯，一尖秀出白雲中。", "料應宰相書成後，留得殘毫倚半空。"]'),
('e3c39e1a-092d-47b3-a646-f58ff1305e16','一片峰','葉茵','宋','宋诗','song-poetry','','[]','十丈蒼圭似削齊，摩挲信是古來碑。',32,'全唐诗/poet.song.211000.json','["十丈蒼圭似削齊，摩挲信是古來碑。", "不刊二范忠勞績，合寫諸賢唱詠詩。"]'),
('48c010cc-bd19-4642-8e5d-4a88a745486e','頭陀巖','葉茵','宋','宋诗','song-poetry','','[]','舊說頭陀坐石巔，披肩壞衲不知年。',32,'全唐诗/poet.song.211000.json','["舊說頭陀坐石巔，披肩壞衲不知年。", "空巖聖得頭陀號，啼鳥枯松也解禪。"]'),
('56ad1d24-6fa0-4e5f-9644-47f310944091','一線泉','葉茵','宋','宋诗','song-poetry','','[]','銀潢萬丈下嵯峨，想是天孫挂玉梭。',32,'全唐诗/poet.song.211000.json','["銀潢萬丈下嵯峨，想是天孫挂玉梭。", "休道此泉絲樣小，涓涓將見作江河。"]'),
('c4e36fd8-404e-4545-a046-834b05bef740','次韻','葉茵','宋','宋诗','song-poetry','','[]','時清歎陸沈，楚澤伴漁吟。',48,'全唐诗/poet.song.211000.json','["時清歎陸沈，楚澤伴漁吟。", "探索聖賢語，發明天地心。", "無機棋少著，有趣樹多陰。", "坐上皆知己，賡酬夜向深。"]'),
('0f2a727d-ed62-4962-bc5d-9b59ec57be23','春晚二首  其一','葉茵','宋','宋诗','song-poetry','','[]','紅紫雨離披，風光別壯時。',48,'全唐诗/poet.song.211000.json','["紅紫雨離披，風光別壯時。", "世情楊絮覺，心事杜鵑知。", "屋角溪連井，林梢菊障籬。", "幸無塵役役，倚檻數晴絲。"]'),
('26ddb2af-7afa-47e7-82a3-ca1a9bf8b7fb','春晚二首  其二','葉茵','宋','宋诗','song-poetry','','[]','春色漸昏昏，那逢日带曛。',48,'全唐诗/poet.song.211000.json','["春色漸昏昏，那逢日带曛。", "落花紅一尺，新筍綠三分。", "憶友盟留石，尋詩思入雲。", "風光到田舍，瘦策看耕耘。"]'),
('b09e33bb-3db5-46c1-bdf2-f03065dc63c2','自遣','葉茵','宋','宋诗','song-poetry','','[]','蟻夢功名覺即休，駒陰歲月去難留。',64,'全唐诗/poet.song.211000.json','["蟻夢功名覺即休，駒陰歲月去難留。", "傷今不復并三樂，擬古猶堪續四愁。", "松下抱琴塵外境，雨餘蒔藥柳邊洲。", "老來莫問浮生事，醉後同爲造物游。"]'),
('24169e9c-9669-4a8d-a3f3-13566a9dbf88','題順適堂','葉茵','宋','宋诗','song-poetry','','[]','甫里相望江盡頭，得鄰而隠了浮休。',64,'全唐诗/poet.song.211000.json','["甫里相望江盡頭，得鄰而隠了浮休。", "落花流水元無礙，野鶴孤雲儘自由。", "順裏委心彭澤賦，適時乘興剡溪舟。", "區區世上分蠻觸，對客忘言茗一甌。"]'),
('b15f267e-6a4f-471a-bf7f-144f9221062b','曹娥廟','葉茵','宋','宋诗','song-poetry','','[]','孝本當爲事，時人或不然。',48,'全唐诗/poet.song.211000.json','["孝本當爲事，時人或不然。", "娥兮知此理，命也委之天。", "五日抱屍出，千年作史傳。", "英靈猶耿耿，有慊莫登船。"]'),
('0f185819-7f9a-4d87-859e-2a0e175a74f1','憶弟','葉茵','宋','宋诗','song-poetry','','[]','支藤來海嶠，骨肉海西邊。',48,'全唐诗/poet.song.211000.json','["支藤來海嶠，骨肉海西邊。", "對月成千里，舉頭同一天。", "更沈寒戍角，歌急晚潮船。", "孤鴈商予意，聲聲落枕前。"]'),
('4fe3d82d-7281-4185-95c7-c9a7533e1d34','相逢','葉茵','宋','宋诗','song-poetry','','[]','相逢疑舊識，敲火自煎茶。',48,'全唐诗/poet.song.211000.json','["相逢疑舊識，敲火自煎茶。", "盛欲爲留計，其如未是家。", "東西分地脈，南北兩天涯。", "別後思君處，空齋讖燭花。"]'),
('c2c4b675-011f-4504-8630-50926d1c38e4','自感二首  其一','葉茵','宋','宋诗','song-poetry','','[]','未險先藜杖，逢亭便小留。',24,'全唐诗/poet.song.211000.json','["未險先藜杖，逢亭便小留。", "今番已非昔，後去可能遊。"]'),
('1fff29e9-f251-47b0-9312-2b08e2d78b35','自感二首  其二','葉茵','宋','宋诗','song-poetry','','[]','倦聽花卿曲，狂歌俠士行。',24,'全唐诗/poet.song.211000.json','["倦聽花卿曲，狂歌俠士行。", "年華與心事，醉裏自分明。"]'),
('ffdd07c5-1f99-41f8-94e8-2f2665ab3c50','山居','葉茵','宋','宋诗','song-poetry','','[]','古木環池竹數竿，疎籬補菊屋三間。',32,'全唐诗/poet.song.211000.json','["古木環池竹數竿，疎籬補菊屋三間。", "白雲不放紅塵入，無怪山人懶出山。"]'),
('01146e87-15b8-48b4-a3d4-313a6515d8ea','元夕','葉茵','宋','宋诗','song-poetry','','[]','一簇蓮燈亦可觀，隔牆簫鼓二更殘。',32,'全唐诗/poet.song.211000.json','["一簇蓮燈亦可觀，隔牆簫鼓二更殘。", "平生未識繁華事，旋借宣和國史看。"]'),
('0fac16c7-b21d-4022-8d57-8a44ceb92040','省墓','葉茵','宋','宋诗','song-poetry','','[]','隴上松杉手自移，至今苔蘚半寒枝。',32,'全唐诗/poet.song.211000.json','["隴上松杉手自移，至今苔蘚半寒枝。", "夢中不記重泉隔，猶學兒童戲綵時。"]'),
('69630814-b664-4892-936c-31dfd6b951d7','梅','葉茵','宋','宋诗','song-poetry','','[]','霜月相摩漏二更，書窗伴我一枝橫。',32,'全唐诗/poet.song.211000.json','["霜月相摩漏二更，書窗伴我一枝橫。", "自矜前輩持清白，妬紫妖紅總後生。"]'),
('85850cee-75f8-4d97-bc3b-0fd2e7ba1466','虎柙','葉茵','宋','宋诗','song-poetry','','[]','生長古林丘，擒來鐵繫囚。',48,'全唐诗/poet.song.211000.json','["生長古林丘，擒來鐵繫囚。", "休憐文變豹，尚覺氣吞牛。", "檻穽終難脫，咆哮亦可休。", "山中藜藿少，君合早爲謀。"]'),
('8cec2e1f-f3b9-45ec-8149-11c3651c55bc','崇道叔慶七十','葉茵','宋','宋诗','song-poetry','','[]','寄意南豐一瓣香，願公耆艾熾而昌。',64,'全唐诗/poet.song.211000.json','["寄意南豐一瓣香，願公耆艾熾而昌。", "歷經七甲鬢浮綠，带錫萬釘眉映黄。", "疑是函關逢老子，巋然魯國有靈光。", "陰功更說燕山桂，留與時人作義方。"]'),
('895c8387-493b-4a6e-96b2-cc64c98ee388','柳','葉茵','宋','宋诗','song-poetry','','[]','態度脂韋不自持，對人無柰小腰肢。',64,'全唐诗/poet.song.211000.json','["態度脂韋不自持，對人無柰小腰肢。", "好於彭澤歸來日，瘦似章臺別去時。", "隠隠輪蹄端不惡，深深亭榭最相宜。", "流鶯百囀春光老，擬折柔條寄所思。"]'),
('18343462-ff35-46cc-bdfc-fb66971a9b95','可山寫梅','葉茵','宋','宋诗','song-poetry','','[]','放出東風手段，寫成江路枝梢。',28,'全唐诗/poet.song.211000.json','["放出東風手段，寫成江路枝梢。", "君復無聲句法，要與廣平解嘲。"]'),
('4046b2c8-26d7-4486-8c93-b40775970fdb','信步','葉茵','宋','宋诗','song-poetry','','[]','九十日春未老，兩三番醉如泥。',28,'全唐诗/poet.song.211000.json','["九十日春未老，兩三番醉如泥。", "行遍菜畦麥隴，未饒十里蘇堤。"]'),
('7fe8bfb1-b93f-49d9-a8af-3865deff62a7','嚴子陵祠','葉茵','宋','宋诗','song-poetry','','[]','橫足齁齁夢御牀，祗將故舊視君王。',64,'全唐诗/poet.song.211000.json','["橫足齁齁夢御牀，祗將故舊視君王。", "意嫌漢室乾坤小，歸占嚴江日月長。", "獨繭絲頭忘寵辱，生芻庭上閲興亡。", "留題多是功名士，也爲留題姓字香。"]'),
('eae5c960-982a-4e9e-b3aa-dd46a586aff2','參選有感','葉茵','宋','宋诗','song-poetry','','[]','元是江湖蕭散客，誰將幽夢落南柯。',64,'全唐诗/poet.song.211000.json','["元是江湖蕭散客，誰將幽夢落南柯。", "十年不調幸然好，一著纔差悟處多。", "肯使北山馳鶴信，且隨西舍唱漁歌。", "野人自喜無彈繳，却恐金章羨綠蓑。"]'),
('e5592819-e353-4d69-933b-72d28aaad85f','春晚二首  其一','葉茵','宋','宋诗','song-poetry','','[]','閉戶蠶新浴，開簾燕早歸。',24,'全唐诗/poet.song.211000.json','["閉戶蠶新浴，開簾燕早歸。", "何曾春欲去，自是物華非。"]'),
('06a44699-b49c-40eb-8e4a-5d9814caa20d','春晚二首  其二','葉茵','宋','宋诗','song-poetry','','[]','胡蝶夢中意，杜鵑聲外愁。',24,'全唐诗/poet.song.211000.json','["胡蝶夢中意，杜鵑聲外愁。", "問春春不語，柳絮暗汀洲。"]'),
('2e345aff-cff0-48f6-a81b-fa3938e95b96','詩僧','葉茵','宋','宋诗','song-poetry','','[]','同住西州一水濱，東州勝處始逢君。',32,'全唐诗/poet.song.211000.json','["同住西州一水濱，東州勝處始逢君。", "詩成又逐行雲去，後日相思祗看雲。"]'),
('fffcbf54-60ee-45b9-a369-4fbcbcbf5665','偶成','葉茵','宋','宋诗','song-poetry','','[]','留得春風趁馬蹄，日長無事綠楊隄。',32,'全唐诗/poet.song.211000.json','["留得春風趁馬蹄，日長無事綠楊隄。", "菜花籬落誰家酒，緩轡長歌過小溪。"]'),
('d139c7b7-f057-4ea3-b997-79e35fb83af0','西湖','葉茵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湘桃深處五陵家，隄柳陰中百寶車。',32,'全唐诗/poet.song.211000.json','["湘桃深處五陵家，隄柳陰中百寶車。", "多是問桃尋柳去，近來山下少梅花。"]'),
('b8a234af-beb0-4c8a-a569-66ed36feaa84','憶友','葉茵','宋','宋诗','song-poetry','','[]','蕭蕭簷角雨，冉冉雨中舟。',48,'全唐诗/poet.song.211000.json','["蕭蕭簷角雨，冉冉雨中舟。", "年老難於別，春寒重却愁。", "風窗亂書葉，塵壁暗燈篝。", "夜半無來鴈，披衣對小樓。"]'),
('ec13c7c4-9eb7-47e8-8302-e10172705e22','次韻','葉茵','宋','宋诗','song-poetry','','[]','疎窗小博山，窗外鳥關關。',48,'全唐诗/poet.song.211000.json','["疎窗小博山，窗外鳥關關。", "占得江湖隠，佐成天地閒。", "簷牙叢篠碧，牆隙兩鳩斑。", "癡坐不知晚，漁篷捲釣還。"]'),
('235fe29a-dc8f-4d02-a1d9-666fb7e653e2','次賦順適堂韻','葉茵','宋','宋诗','song-poetry','','[]','萬卷藏書抵萬金，翛然軒宇絕塵侵。',64,'全唐诗/poet.song.211000.json','["萬卷藏書抵萬金，翛然軒宇絕塵侵。", "順時不作榮枯想，適意元無勝負心。", "蒲石疎簾真道院，柏香浄几小叢林。", "四時剩有閒風月，醒裏尋題醉裏吟。"]'),
('a7d291b2-a415-4996-a779-550058d06eae','有所思','葉茵','宋','宋诗','song-poetry','','[]','仰天有所思，心遠目苦短。',24,'全唐诗/poet.song.211000.json','["仰天有所思，心遠目苦短。", "西風驅殘雲，千里月華滿。"]'),
('7a6b4b46-d7be-4f4f-b609-0b77ada54ad6','阿育王寺舍利塔','葉茵','宋','宋诗','song-poetry','','[]','粒粟懸懸左角鐘，幾年鎮壓梵王宮。',64,'全唐诗/poet.song.211000.json','["粒粟懸懸左角鐘，幾年鎮壓梵王宮。", "要知八萬四千所，元在尋常一念中。", "佛現紫金歸勝地，僧誇烏石墜虛空。", "毫光起處無人見，明月堂前玉几東。"]'),
('a52bcce7-b5fd-4ed3-9ed9-34e7e2b24653','山居','葉茵','宋','宋诗','song-poetry','','[]','朝踏山根雲，暮歸雲中扉。',36,'全唐诗/poet.song.211000.json','["朝踏山根雲，暮歸雲中扉。", "野鳥始驚避，今焉情依依。", "異哉海上鷗，猜疑未忘機。"]'),
('c88c2bfc-d1c2-4a78-afec-0380d65e571e','己酉生日敬次靖節先生擬挽歌辭三首  其一','葉茵','宋','宋诗','song-poetry','','[]','放浪宇宙間，世事笑局促。',84,'全唐诗/poet.song.211000.json','["放浪宇宙間，世事笑局促。", "駸駸影中人，不受時采錄。", "奄然長夜歸，齎志空山木。", "昔日堂上歡，今夕堂下哭。", "哭之欲其生，予亦不自覺。", "天道元無私，紛紛徒寵辱。", "素心惟坡僊，一死萬事足。"]'),
('208640ca-a0d7-4843-8796-71afe16909b1','己酉生日敬次靖節先生擬挽歌辭三首  其二','葉茵','宋','宋诗','song-poetry','','[]','自古皆有死，載歌酹清觴。',72,'全唐诗/poet.song.211000.json','["自古皆有死，載歌酹清觴。", "嗟予早失怙，艱阻亦備嘗。", "母兮歲六十，終古青松傍。", "陟岡慟伯氏，忘簪悲孟光。", "後波逐前波，同歸溟漠鄉。", "飄風相飛旐，轝鐸聲央央。"]'),
('42836e76-b6a9-43ef-bb9b-d84ff4267b71','己酉生日敬次靖節先生擬挽歌辭三首  其三','葉茵','宋','宋诗','song-poetry','','[]','重雲翳蒼柏，零露棲白蕭。',108,'全唐诗/poet.song.211000.json','["重雲翳蒼柏，零露棲白蕭。", "骨肉慕音容，慌惚哀空郊。", "肴核班几席，椒漿澆岧嶤。", "人歸天已沬，紙錢懸枯條。", "逝者如此耳，暮暮仍朝朝。", "暮暮仍朝朝，人兮柰若何。", "未死不能樂，既死空有家。", "僮僕幾恩怨，交朋幾悲歌。", "若人會斯語，屬和紛陽阿。"]'),
('5be9ae85-a9d2-462b-a266-0dabd5653b90','既次韻或非之作解嘲','葉茵','宋','宋诗','song-poetry','','[]','揆子初度日，撫杯擬歌辭。',84,'全唐诗/poet.song.211000.json','["揆子初度日，撫杯擬歌辭。", "衰齡踰五十，敢必登古希。", "自傳始遷固，誌銘傳牧之。", "諦觀子儼疏，直與浮世違。", "靖節百世師，汝無輕笑嗤。", "諱之寧免歿，不諱達者爲。", "假我以耆艾，年年續斯詩。"]'),
('b460f2d4-404d-4121-9ab3-abd8dde55db0','庚戌生日再擬去歲挽歌辭','葉茵','宋','宋诗','song-poetry','','[]','憶昨歲莫止，慷慨生死機。',108,'全唐诗/poet.song.211000.json','["憶昨歲莫止，慷慨生死機。", "擬韻追先哲，持爲自壽詩。", "成篇示叔季，心然口交非。", "詎知不一霜，季兮先露晞。", "興思發永歎，載言涕肆頤。", "萬化同于盡，彭鏗空厖眉。", "日月不我與，去去氣力衰。", "且進尊中醁，勿作兒女悲。", "殷勤晉鼎心，趨前舞萊衣。"]'),
('3cae4522-04c5-4967-bfac-14e663676bed','少陵騎蹇馿圖','葉茵','宋','宋诗','song-poetry','','[]','帽破衣寬骨相寒，爲花日日醉吟鞍。',32,'全唐诗/poet.song.211000.json','["帽破衣寬骨相寒，爲花日日醉吟鞍。", "時人祗道題風月，後世將詩作史看。"]'),
('0b3fa6e0-514e-4f1f-9de1-edbb1066953c','孟浩然歸南山圖','葉茵','宋','宋诗','song-poetry','','[]','笑指南山躍馬歸，明知舉似棄才詩。',32,'全唐诗/poet.song.211000.json','["笑指南山躍馬歸，明知舉似棄才詩。", "亭前千古標芳姓，未可窮通論一時。"]'),
('c7b44371-9a73-4f15-8ef5-94fbfd35c7bc','李白詩百篇圖','葉茵','宋','宋诗','song-poetry','','[]','長安市上醉如泥，旁若無人且賦詩。',32,'全唐诗/poet.song.211000.json','["長安市上醉如泥，旁若無人且賦詩。", "誰識隠然爲計國，沈香亭畔脫鞾時。"]'),
('8c2c19b9-37ec-4871-a7ed-765ea6548c85','岑參醉落魄圖','葉茵','宋','宋诗','song-poetry','','[]','醉裏沈思世道危，不堪著眼只攢眉。',32,'全唐诗/poet.song.211000.json','["醉裏沈思世道危，不堪著眼只攢眉。", "空留忠憤聲名在，不見招歸舊日詩。"]'),
('f4e8f375-99f6-4b14-8532-abcde951e1ba','枕簟入林僻茶瓜留客遲十韻  其一','葉茵','宋','宋诗','song-poetry','','[]','人人苦炎歊，於我覺太甚。',24,'全唐诗/poet.song.211000.json','["人人苦炎歊，於我覺太甚。", "北戶其清凉，萬事付一枕。"]'),
('a844ee45-322f-4302-9100-fa316afaab43','枕簟入林僻茶瓜留客遲十韻  其二','葉茵','宋','宋诗','song-poetry','','[]','叩門真丈夫，一揖棄拘檢。',24,'全唐诗/poet.song.211000.json','["叩門真丈夫，一揖棄拘檢。", "人物晉風流，班坐黄玉簟。"]'),
('fde0db5f-fd35-45e6-b7fb-bb6c3c5660ef','枕簟入林僻茶瓜留客遲十韻  其三','葉茵','宋','宋诗','song-poetry','','[]','譚壘爭塵清，詩壇傳令急。',24,'全唐诗/poet.song.211000.json','["譚壘爭塵清，詩壇傳令急。", "今日有公事，俗駕不可入。"]'),
('09c00484-4359-4273-b291-198aa682cf18','枕簟入林僻茶瓜留客遲十韻  其四','葉茵','宋','宋诗','song-poetry','','[]','牆外水泠泠，水邊木陰陰。',24,'全唐诗/poet.song.211000.json','["牆外水泠泠，水邊木陰陰。", "相遇聊自適，茲辰猶竹林。"]'),
('fbef594a-91bf-4592-95ff-1bee4ef67aca','枕簟入林僻茶瓜留客遲十韻  其五','葉茵','宋','宋诗','song-poetry','','[]','同爲山澤臞，半分漁樵席。',24,'全唐诗/poet.song.211000.json','["同爲山澤臞，半分漁樵席。", "我不踐斯境，誰肯賞茲僻。"]'),
('3be03c31-1848-4180-81c6-5fa30b3dbd2c','枕簟入林僻茶瓜留客遲十韻  其六','葉茵','宋','宋诗','song-poetry','','[]','意到景自到，榮榮窗下花。',24,'全唐诗/poet.song.211000.json','["意到景自到，榮榮窗下花。", "一張彭澤琴，一甌陽羨茶。"]'),
('74c56ec0-775f-476f-b352-4716bf161c95','枕簟入林僻茶瓜留客遲十韻  其七','葉茵','宋','宋诗','song-poetry','','[]','有酒斟酌之，歡然成諠譁。',24,'全唐诗/poet.song.211000.json','["有酒斟酌之，歡然成諠譁。", "何必五侯鯖，李綠兮香瓜。"]'),
('352e2bad-385e-4fa4-89b9-bf47e26509e8','枕簟入林僻茶瓜留客遲十韻  其八','葉茵','宋','宋诗','song-poetry','','[]','一會良不易，載言翻令愁。',24,'全唐诗/poet.song.211000.json','["一會良不易，載言翻令愁。", "清風有時度，白日不可留。"]'),
('b9bb0acd-d7fe-4276-bf6c-bb722a61474b','枕簟入林僻茶瓜留客遲十韻  其九','葉茵','宋','宋诗','song-poetry','','[]','君顔猶少年，我髮不勝幘。',24,'全唐诗/poet.song.211000.json','["君顔猶少年，我髮不勝幘。", "百歲壘一丘，主翁驚是客。"]'),
('14800675-1f48-47b0-80d9-b65eeae8ed18','枕簟入林僻茶瓜留客遲十韻  其一○','葉茵','宋','宋诗','song-poetry','','[]','數面成骨肉，子歸將何之。',24,'全唐诗/poet.song.211000.json','["數面成骨肉，子歸將何之。", "長嘯盼天外，雲意俱遲遲。"]'),
('86cbac0c-2f79-4fad-8113-3cfe622d8d40','酒邊次徐靈淵韻','葉茵','宋','宋诗','song-poetry','','["\u592a\u6e56"]','柳外綠陰重，綠陰生遠風。',48,'全唐诗/poet.song.211000.json','["柳外綠陰重，綠陰生遠風。", "溫凉三月後，醒醉百年中。", "桑禿吳蠶熟，林幽蜀鳥空。", "不祈朝市夢，高卧太湖東。"]'),
('af65516a-9f02-463b-bcfb-dfe938fb2e06','過舊相府','葉茵','宋','宋诗','song-poetry','','[]','寂寞相公宅，枯楊枕綠波。',48,'全唐诗/poet.song.211000.json','["寂寞相公宅，枯楊枕綠波。", "老兵猶自語，貴客舊曾過。", "壁暗蛛生網，門空爵可羅。", "問他桃與李，何處得春多。"]'),
('d137521f-cef1-44f7-888b-323d28faceeb','南塘偶成','葉茵','宋','宋诗','song-poetry','','[]','靜向南塘驗物情，東風又綠柳邊汀。',64,'全唐诗/poet.song.211000.json','["靜向南塘驗物情，東風又綠柳邊汀。", "梅花密點殘棋局，蝸篆斜題小硯屏。", "浮世虛無春後雪，故人零落曉來星。", "逢時且進杯中醁，休學懷沙賦獨醒。"]'),
('5dc1b6d1-36b1-4f9e-ba59-2e2f80a2711c','僧房夜坐','葉茵','宋','宋诗','song-poetry','','[]','四十二間廊底客，不知春向柳邊深。',64,'全唐诗/poet.song.211000.json','["四十二間廊底客，不知春向柳邊深。", "三旬禁足持僧戒，終日看書養道心。", "露草带雲眠野鹿，風枝摇月唳幽禽。", "一塵不到爐煙靜，自向空寮續近吟。"]'),
('945053c2-35eb-4e7a-9066-43e0b2cea93e','旅邸','葉茵','宋','宋诗','song-poetry','','[]','湫隘囂塵不可居，卜諸清曠亦蘧廬。',64,'全唐诗/poet.song.211000.json','["湫隘囂塵不可居，卜諸清曠亦蘧廬。", "雖無傍水梅依竹，喜有對樓人讀書。", "工雀一枝聊爾耳，戰蝸兩角竟何如。", "西風漸勁未歸去，空說張翰憶膾魚。"]'),
('4bad1388-5d7e-4b40-be21-84458b46de89','記顔','葉茵','宋','宋诗','song-poetry','','[]','五十一年前素昧，相逢元是鏡中人。',32,'全唐诗/poet.song.211000.json','["五十一年前素昧，相逢元是鏡中人。", "他時鶴髮雞皮樣，却道今番畫未真。"]'),
('e6ea0008-dbf0-43a3-a0b7-9684d882076a','身後寄顔','葉茵','宋','宋诗','song-poetry','','[]','生前喜作死規模，强把冠裳束幻軀。',32,'全唐诗/poet.song.211000.json','["生前喜作死規模，强把冠裳束幻軀。", "兒輩對人拋好語，吾家南極老人圖。"]'),
('011a0d09-9bff-48be-bb24-aa2f303a2046','次韻','葉茵','宋','宋诗','song-poetry','','[]','燕入虛簷教子飛，風簾不捲和新詩。',32,'全唐诗/poet.song.211000.json','["燕入虛簷教子飛，風簾不捲和新詩。", "綠陰滿逕蜻蜓小，正是梅黄欲雨時。"]'),
('2d461282-638a-49c8-8c4b-1e5fb0820d03','春事','葉茵','宋','宋诗','song-poetry','','[]','春事又如此，猶人欲老時。',48,'全唐诗/poet.song.211000.json','["春事又如此，猶人欲老時。", "綠稠煙外樹，白緊鬢邊絲。", "天道有還日，吾年無返期。", "從今安適境，莫放酒杯遲。"]'),
('51508141-28e7-4063-94d4-d7e2c02e8623','晚春','葉茵','宋','宋诗','song-poetry','','[]','遊事一番了，愁多鎖晝長。',48,'全唐诗/poet.song.211000.json','["遊事一番了，愁多鎖晝長。", "因思來歲賞，未必少年狂。", "野鳥學蠻語，岸花浮楚香。", "魚應知我者，圉圉到池塘。"]'),
('61f80875-8cbf-4f28-b94c-a05971c17806','琉璃砲燈中魚','葉茵','宋','宋诗','song-poetry','','[]','頭角未崢嶸，潛宮號水晶。',48,'全唐诗/poet.song.211000.json','["頭角未崢嶸，潛宮號水晶。", "遊時雖逼窄，樂處在圓明。", "有火疑燒尾，無波可動情。", "一朝開混沌，變化趁雷轟。"]'),
('49a087ed-7d2b-4bb3-99b7-8a44f7823b30','贈陳芸居','葉茵','宋','宋诗','song-poetry','','[]','氣貌老成聞見熟，江湖指作定南鍼。',64,'全唐诗/poet.song.211000.json','["氣貌老成聞見熟，江湖指作定南鍼。", "得書愛與世人讀，選句長教野客吟。", "富貴天街紛耳目，清閒地位當山林。", "料君閲遍興亡事，對坐蕭然一片心。"]'),
('1a183c4e-0e39-4f67-a95a-cc480cba35d4','伯氏墓下','葉茵','宋','宋诗','song-poetry','','[]','敬長于今我獨亡，轉頭驚見十飛霜。',64,'全唐诗/poet.song.211000.json','["敬長于今我獨亡，轉頭驚見十飛霜。", "心乎愛矣兄如在，陟彼岡兮木已蒼。", "直喜克家猶有子，回思療疾苦無方。", "伏波不忍離墳墓，淚灑歸舟重感傷。"]'),
('bd4dfaf9-dba2-4fef-a2ba-c1d8b9abd73c','次遊十洲之一亭韻','葉茵','宋','宋诗','song-poetry','','[]','抵掌論文酒易酣，岸巾風外鬢䰐鬖。',64,'全唐诗/poet.song.211000.json','["抵掌論文酒易酣，岸巾風外鬢䰐鬖。", "十洲所有今之一，七步而成爾乃三。", "橋壓平隄波捲綠，煙封遠沚草舒藍。", "閒邊得侶評佳境，留與他時作美談。"]'),
('b4ae017c-2383-4d1b-9a4d-4b22404e6b3b','漁村','葉茵','宋','宋诗','song-poetry','','[]','古柳溪頭枕斷槎，橫篙挂網幾漁家。',32,'全唐诗/poet.song.211000.json','["古柳溪頭枕斷槎，橫篙挂網幾漁家。", "得魚去換紅蒸米，呼子來挑薺菜花。"]'),
('cdf6cd41-80a1-49c5-b608-747f43518b1f','蠶婦歎','葉茵','宋','宋诗','song-poetry','','[]','浴蠶纔罷餧蠶忙，朝暮蓬頭去採桑。',32,'全唐诗/poet.song.211000.json','["浴蠶纔罷餧蠶忙，朝暮蓬頭去採桑。", "辛苦得絲了租稅，終年祗著布衣裳。"]'),
('ef49abe1-86b3-412d-90ea-b93d600b5e00','機女歎','葉茵','宋','宋诗','song-poetry','','[]','機聲吚軋到天明，萬縷千絲織得成。',32,'全唐诗/poet.song.211000.json','["機聲吚軋到天明，萬縷千絲織得成。", "售與綺羅人不顧，看紗嫌重絹嫌輕。"]'),
('6caaf7b8-417a-41f9-ac79-c5babc73ad68','廢墓有感','葉茵','宋','宋诗','song-poetry','','[]','軒冕委塵埃，今人爲古哀。',48,'全唐诗/poet.song.211000.json','["軒冕委塵埃，今人爲古哀。", "百年丘隴廢，幾箇子孫來。", "蔓草栖朝露，窮猿泣夜臺。", "世間類如此，當樂且銜杯。"]'),
('a6949bfa-123b-440a-a483-deb62b5a8232','掃榻','葉茵','宋','宋诗','song-poetry','','[]','掃榻卧終日，香銷百念除。',48,'全唐诗/poet.song.211000.json','["掃榻卧終日，香銷百念除。", "不愁渾厭酒，無事剩鈔書。", "粉淺庭前筍，青齊雨後蔬。", "自嫌猶有累，添水種金魚。"]'),
('7bdbf73c-1274-49f1-acd7-e36e246261c5','風雨','葉茵','宋','宋诗','song-poetry','','[]','昨夜東風急，疎窗薦雨入。',84,'全唐诗/poet.song.211000.json','["昨夜東風急，疎窗薦雨入。", "溪南梅正花，狼藉隨塵沙。", "皓皓多易汙，不得全春華。", "春華能有幾，紛紛入桃李。", "時哉小興衰，人生猶物理。", "明發簷沈聲，鳥雀喧新晴。", "老農脫襏襫，一犁原上耕。"]'),
('bed7161c-95e8-4ebf-957e-ee5fe03f369c','投所知','葉茵','宋','宋诗','song-poetry','','[]','中流砥柱一宗臣，長把丹衷動玉宸。',64,'全唐诗/poet.song.211000.json','["中流砥柱一宗臣，長把丹衷動玉宸。", "三十四番如此疏，百千載後更無人。", "堂留薇藥誰知己，路長蕭茅謾得春。", "自是不曾輕出處，到頭著著爲斯民。"]'),
('1c095baa-b3e1-4b4f-a0d5-1fb72b94a509','虎丘','葉茵','宋','宋诗','song-poetry','','[]','心境空時喜地偏，杖藜來勘點頭禪。',64,'全唐诗/poet.song.211000.json','["心境空時喜地偏，杖藜來勘點頭禪。", "重門鎖住海心石，一劍截開冰底天。", "誰記珣珉曾院宇，尚傳吳越共山川。", "闌風剩月知人意，塔影松聲落坐邊。"]'),
('dfbc3e91-1ea8-4349-9b6e-8a3a2865f27e','遊園','葉茵','宋','宋诗','song-poetry','','[]','碧琅玕裏幾亭臺，萬朵芙蕖照水開。',32,'全唐诗/poet.song.211000.json','["碧琅玕裏幾亭臺，萬朵芙蕖照水開。", "可醉可吟尤可卧，主人無暇客長來。"]'),
('f81fcb12-c3e2-47f5-8ecc-de0d452eb4b5','即事','葉茵','宋','宋诗','song-poetry','','[]','去去晴雲送客舟，客舟剛把去雲留。',32,'全唐诗/poet.song.211000.json','["去去晴雲送客舟，客舟剛把去雲留。", "雲心不定客心亂，一陣飛花兩岸愁。"]'),
('b7818529-82fa-4193-997d-14671c900af3','村居','葉茵','宋','宋诗','song-poetry','','[]','數舍茅茨簇水涯，傍簷一樹早梅花。',32,'全唐诗/poet.song.211000.json','["數舍茅茨簇水涯，傍簷一樹早梅花。", "年豐便覺村居好，竹裏新添賣酒家。"]'),
('93b3210b-1ed3-48d8-b337-edb2da56ae26','半塘寺','葉茵','宋','宋诗','song-poetry','','[]','寺枕彩雲橋，殘碑紀晉朝。',48,'全唐诗/poet.song.211000.json','["寺枕彩雲橋，殘碑紀晉朝。", "地平垂塔影，林古鎮塘腰。", "夜月松千阜，春風柳萬條。", "景多僧住少，近覺有塵囂。"]'),
('e8ea5e11-90bd-4fae-94cf-dc781869ea8c','勳業','葉茵','宋','宋诗','song-poetry','','[]','勳業占漁蓑，因閒學種荷。',48,'全唐诗/poet.song.211000.json','["勳業占漁蓑，因閒學種荷。", "春秋幾燕壘，人世一雞窠。", "雨急溪聲壯，堂寬野趣多。", "狂歌狂且醉，還感醉時歌。"]'),
('fac3f845-d061-480f-8f5c-0a00dcca07c9','夜坐','葉茵','宋','宋诗','song-poetry','','[]','秋院穉凉生，看書睡未能。',48,'全唐诗/poet.song.211000.json','["秋院穉凉生，看書睡未能。", "扇閒螢撲袂，窗破鼠窺燈。", "晚境物華異，清宵道氣增。", "鄰家猶不寐，席地話豐登。"]'),
('37c0c560-d843-4b5e-b0c0-cbc6ad868cd3','偶題','葉茵','宋','宋诗','song-poetry','','[]','曲肱玩味聖賢書，識破人間總畏途。',64,'全唐诗/poet.song.211000.json','["曲肱玩味聖賢書，識破人間總畏途。", "盛欲對君言所以，又應誚我愛之乎。", "百年役役鴈來去，一夢昏昏鹿有無。", "堪笑季鷹猶左計，求歸何必待蓴鱸。"]'),
('52ecc67f-f160-40d2-9022-ecbbc655fc0c','偶成','葉茵','宋','宋诗','song-poetry','','[]','醉敲牛角過前村，此世應無利祿昏。',64,'全唐诗/poet.song.211000.json','["醉敲牛角過前村，此世應無利祿昏。", "有水可漁田可稼，即松而徑竹而門。", "賓朋連屬琴書樂，亭榭參差鳥雀喧。", "不假山靈回俗駕，會心同是一乾坤。"]'),
('22391586-a8ad-4493-a888-e3fd2c14bfd3','讀騷','葉茵','宋','宋诗','song-poetry','','[]','舉世昏昏醉未醒，獨醒寂寞楚江濱。',32,'全唐诗/poet.song.211000.json','["舉世昏昏醉未醒，獨醒寂寞楚江濱。", "後人愛把離騷讀，不道離騷誤後人。"]'),
('32a8333d-8213-4ced-889a-8dbbb4f46046','偶成','葉茵','宋','宋诗','song-poetry','','[]','人間總利名，此地此心清。',48,'全唐诗/poet.song.211000.json','["人間總利名，此地此心清。", "雨架筆多潤，風櫺琴自聲。", "虛堂回古味，逆境見真情。", "脫帽尋蘄簟，酣眠小太平。"]'),
('938cbf1b-8e97-41ea-9cf1-94ad20de9a57','浮世','葉茵','宋','宋诗','song-poetry','','[]','浮世即浮家，書車與釣車。',48,'全唐诗/poet.song.211000.json','["浮世即浮家，書車與釣車。", "夢中行熟境，塵外立生涯。", "籬落千絲柳，池塘兩部蛙。", "兒曹問農事，䆉稏隔田花。"]'),
('f03c1039-1e54-4dec-a9d7-43bda52c65aa','出城','葉茵','宋','宋诗','song-poetry','','[]','清曉出江城，波平覺棹輕。',48,'全唐诗/poet.song.211000.json','["清曉出江城，波平覺棹輕。", "煙荷學人老，風柳作秋聲。", "歲稔時無事，心和物有情。", "客來慵與語，苦苦問功名。"]'),
('16ffb01f-f501-4feb-b065-1eccd8999dd9','題水竹弟壽山覺菴','葉茵','宋','宋诗','song-poetry','','[]','照鄰營墓牧之銘，一理融明古亦今。',64,'全唐诗/poet.song.211000.json','["照鄰營墓牧之銘，一理融明古亦今。", "政爲後先同此覺，不將生死動其心。", "天教棠棣分春色，地接松楸合晝陰。", "自謂老身强健在，時時來和壽藏吟。"]'),
('f44da483-b4fb-44c8-a886-d9c2dfba36e4','酒邊次韻','葉茵','宋','宋诗','song-poetry','','[]','天末星流小似螢，因將時事語家庭。',64,'全唐诗/poet.song.211000.json','["天末星流小似螢，因將時事語家庭。", "久晴未厭田多雨，衆醉難教我獨醒。", "梅下有人編野史，竹間猶子課羲經。", "晚年喜不爲身累，閉戶何求阮眼青。"]'),
('cb5a6179-450e-404e-af41-e8f01aeb9f9d','荔枝','葉茵','宋','宋诗','song-poetry','','[]','縐紅紗護水晶團，驛騎飛來露未乾。',32,'全唐诗/poet.song.211000.json','["縐紅紗護水晶團，驛騎飛來露未乾。", "胡羯垂涎猶不悟，馬嵬山底夢長安。"]'),
('81bae00f-140f-4716-ac6f-9f66940cfa2d','橄欖','葉茵','宋','宋诗','song-poetry','','[]','落盡紅鹽子更青，餘甘風韻未爲珍。',32,'全唐诗/poet.song.211000.json','["落盡紅鹽子更青，餘甘風韻未爲珍。", "從來獨有茶知己，勘破生生一點仁。"]'),
('8d2f1476-383d-4563-b9ef-9cb3b4129d12','偶成','葉茵','宋','宋诗','song-poetry','','[]','江湖千萬頃，小艇熟煙波。',48,'全唐诗/poet.song.211000.json','["江湖千萬頃，小艇熟煙波。", "無夢世情薄，有吟春思多。", "百年空反覆，兩鬢暗消磨。", "釣叟同吾志，鳴榔柳外過。"]'),
('7f918760-b4a7-403c-aa7d-6c33243e7fb9','元夕','葉茵','宋','宋诗','song-poetry','','[]','夢想傳柑宴，村醪可試沽。',48,'全唐诗/poet.song.211000.json','["夢想傳柑宴，村醪可試沽。", "謾酬元夕爾，不復去年吾。", "舊事思清汴，幽情卜紫姑。", "六分春已一，秉燭步通衢。"]'),
('ed0ccb0b-673d-4aa9-aab9-649218f0fb79','野堂即事','葉茵','宋','宋诗','song-poetry','','[]','纖塵不到芰荷邊，好向闌干繫小船。',64,'全唐诗/poet.song.211000.json','["纖塵不到芰荷邊，好向闌干繫小船。", "得句未工吟競病，有書可讀笑便眠。", "老於膠擾寧中聖，暫爾蕭閒即半僊。", "人境兩忘天地寂，一聲柳外咽新蟬。"]'),
('87eb0111-9cba-430b-87ee-f1e64b632508','詩僧歸儒','葉茵','宋','宋诗','song-poetry','','[]','厭作人間粥飯僧，等閒來續義銛燈。',64,'全唐诗/poet.song.211000.json','["厭作人間粥飯僧，等閒來續義銛燈。", "近吟氣味無蔬筍，舊學工夫尚葛藤。", "花下飛鞭身灑落，風前扶帽髮鬅鬙。", "浪僊素不修書問，有愧昌黎詫可朋。"]'),
('1eb21289-e479-43f3-9498-3b582caaa6cf','打坐','葉茵','宋','宋诗','song-poetry','','[]','一卷黄庭日未移，跏趺坐處篆香遲。',32,'全唐诗/poet.song.211000.json','["一卷黄庭日未移，跏趺坐處篆香遲。", "兒曹問我新官職，順適堂中老住持。"]'),
('141600b4-1cff-4938-99ab-04bc0ca9d947','春去','葉茵','宋','宋诗','song-poetry','','[]','一片飛花落酒缸，風光漸覺遠書窗。',32,'全唐诗/poet.song.211000.json','["一片飛花落酒缸，風光漸覺遠書窗。", "草深兩部青蛙閙，芹濕重簷紫燕雙。"]'),
('61547169-ab07-4b14-ad02-e923fae8c068','小垂虹橋','葉茵','宋','宋诗','song-poetry','','[]','馮夷掣開潛蛟鎖，御雲飛過松江左。',80,'全唐诗/poet.song.211000.json','["馮夷掣開潛蛟鎖，御雲飛過松江左。", "懸腰展鬣眠東湖，生綃描作垂虹圖。", "隠君騎背占空闊，百尺闌干景軒豁。", "有亭翼然芙蕖開，風朝月夕尤佳哉。", "柳邊何曾官船來，回視驛橋多塵埃。"]'),
('6c20945b-b9d5-4244-a9f5-2a053446572b','愛香亭','葉茵','宋','宋诗','song-poetry','','[]','有君子兮居滄波，芝蘭之室未足多。',64,'全唐诗/poet.song.211000.json','["有君子兮居滄波，芝蘭之室未足多。", "爲香終日成癡絕，不著此亭如香何。", "光風霽月盪心目，幸甚吳儂沾賸馥。", "茲時消得爲衣裳，對翁更把離騷讀。"]'),
('669fe7fa-d3f8-400e-94c1-792db612b69c','偶成','葉茵','宋','宋诗','song-poetry','','[]','世事如今不可知，相逢茶罷且吟詩。',64,'全唐诗/poet.song.211000.json','["世事如今不可知，相逢茶罷且吟詩。", "無風古鼎香煙直，未午空庭樹影遲。", "袖手好看棋勝敗，論心休問酒醇醨。", "謀居恰與松江近，斫膾羹蓴漸及時。"]'),
('dc76fee1-4afa-4d3f-bd28-b0f406d701cd','舫齋','葉茵','宋','宋诗','song-poetry','','[]','居家巧作浮家樣，此即人生不繫舟。',64,'全唐诗/poet.song.211000.json','["居家巧作浮家樣，此即人生不繫舟。", "政恐風波起平地，直教砥柱屹中流。", "浪花影動重簾月，潮汛聲喧萬葉秋。", "夢裏不知容膝計，翻身栩栩逐輕鷗。"]'),
('d627ecfd-53f3-4a1e-8480-4a4277afc607','苕溪行','葉茵','宋','宋诗','song-poetry','','[]','吳松江頭田舍翁，年年苕溪摇飛篷。',176,'全唐诗/poet.song.211000.json','["吳松江頭田舍翁，年年苕溪摇飛篷。", "沿溪楊柳舊相識，問翁何事猶西東。", "心欲無言淚如洗，松楸正在西山裏。", "余生五十五番春，七十爲期春夢耳。", "追思疇昔謀親塋，鴈行差差三弟兄。", "伯兮季兮不可作，老來隻影嗟零丁。", "手種青杉踰百尺，藤花薜蔓籠臺石。", "一年一到一徘徊，此後徘徊幾朝夕。", "九泉屬望天潛知，寸草難報陽春暉。", "教子一經答先志，買山傍墓終焉計。", "讀書可大吾門閭，沒世可從先大夫。"]'),
('b4024dc2-1ba4-4f48-86e3-48513e849fa0','次韻','葉茵','宋','宋诗','song-poetry','','[]','童去鶴歸遲，青山皓首期。',48,'全唐诗/poet.song.211000.json','["童去鶴歸遲，青山皓首期。", "池塘圓草夢，家世受梅知。", "拂石和雲卧，分魚換米炊。", "人生裁足耳，舍子更其誰。"]'),
('dc9709e8-8f51-4720-8057-914f280a9e9c','次撫松韻','葉茵','宋','宋诗','song-poetry','','[]','昂藏蒼髯翁，違世號獨立。',72,'全唐诗/poet.song.211000.json','["昂藏蒼髯翁，違世號獨立。", "女蘿千丈絲，依倚忘岌岌。", "有客眠疎陰，感慨百世人。", "不悟女蘿累，甘爲女蘿親。", "猗歟山下蘭，清芬傳楚澤。", "野蔓不可干，此道何曾息。"]'),
('c3028d8b-32cf-4cb0-8577-adff60131e46','晚年闢地爲圃僭用老坡和靖節歸田園居六韻  其一','葉茵','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖三萬頃，湖中東西山。',120,'全唐诗/poet.song.211000.json','["太湖三萬頃，湖中東西山。", "謀隠媿不早，欲往嗟衰年。", "道南地夷曠，半占龜魚淵。", "斷岸連疎村，浮雲棲平田。", "得此願可酬，不啻湖山間。", "瞻彼閔子巷，卜居千載前。", "猶存六七舍，古柳生青煙。", "鄰曲來無時，爲予喜欲顛。", "疇知在塵境，中有風月閒。", "吾將老此鄉，草木俱欣然。"]'),
('661ab882-36f2-48c8-9a25-961f7dcf92d0','晚年闢地爲圃僭用老坡和靖節歸田園居六韻  其二','葉茵','宋','宋诗','song-poetry','','[]','已受鱸鄉招，柴車異塵鞅。',72,'全唐诗/poet.song.211000.json','["已受鱸鄉招，柴車異塵鞅。", "方春融融時，紅紫形夢想。", "勝遊計自今，樂事何曾往。", "迎意引壺觴，班荆集少長。", "容膝地有餘，意不在袤廣。", "牧豎良知心，長歌振林莽。"]'),
('fe51b281-475e-4358-ad5b-f1250d31ec7e','晚年闢地爲圃僭用老坡和靖節歸田園居六韻  其三','葉茵','宋','宋诗','song-poetry','','[]','蠶姑饋新蛹，籬落桑柘稀。',48,'全唐诗/poet.song.211000.json','["蠶姑饋新蛹，籬落桑柘稀。", "一繭視萬事，浮生同于歸。", "水淺凉可濯，荷深香可衣。", "載言老圃計，勇决無依違。"]'),
('8a931fd2-5566-4b39-b087-97c0e9dc4dc5','晚年闢地爲圃僭用老坡和靖節歸田園居六韻  其四','葉茵','宋','宋诗','song-poetry','','[]','疏牖炷柏子，日與琴書娛。',96,'全唐诗/poet.song.211000.json','["疏牖炷柏子，日與琴書娛。", "已復迴商飈，凉意浮郊墟。", "自成松菊趣，不雜軒冕居。", "悠悠鳥脫罟，局局兔守株。", "試叩塞上翁，得喪爲何如。", "元亮抱至道，詩發道之餘。", "利名莫能束，精神遊太虛。", "冥想田園歸，其樂無時無。"]'),
('25e98a6b-a912-4907-a449-6a43e6d88d52','晚年闢地爲圃僭用老坡和靖節歸田園居六韻  其五','葉茵','宋','宋诗','song-poetry','','[]','控馿灞橋坳，縱棹剡溪曲。',60,'全唐诗/poet.song.211000.json','["控馿灞橋坳，縱棹剡溪曲。", "繽紛天上花，拍拍春意足。", "能追茲辰歡，獨許蘇玉局。", "憧憧市朝人，繼晷猶秉燭。", "野翁太無營，借暖待晴旭。"]'),
('b6c9ad1c-e4f1-4bf7-847f-09377462c674','晚年闢地爲圃僭用老坡和靖節歸田園居六韻  其六','葉茵','宋','宋诗','song-poetry','','[]','結廬田疇間，稔步東西陌。',84,'全唐诗/poet.song.211000.json','["結廬田疇間，稔步東西陌。", "時哉休且休，聊以適吾適。", "汗漫游難逢，崦嵫日易夕。", "篠影延戶深，苔暈補階隙。", "而有蛙蚓居，口腹猶役役。", "顧予安一閒，頂踵蒙帝績。", "發爲四時吟，吟中自規益。"]'),
('7278379c-1620-4ccf-8087-e0721cce5fb3','鱸鄉道院','葉茵','宋','宋诗','song-poetry','','[]','步兵舊游地，野人今結廬。',24,'全唐诗/poet.song.211000.json','["步兵舊游地，野人今結廬。", "千載同一調，志隠不志魚。"]'),
('6b187d87-4cbb-404b-ac98-467186b86dda','光風霽月','葉茵','宋','宋诗','song-poetry','','[]','濂溪有此天，天外得此景。',24,'全唐诗/poet.song.211000.json','["濂溪有此天，天外得此景。", "景中一衰翁，融入吟哦境。"]'),
('e2c8d235-08bd-48f2-aeda-12c7ea14cff6','耕釣境','葉茵','宋','宋诗','song-poetry','','[]','一犁足春雨，一絲摇晴風。',24,'全唐诗/poet.song.211000.json','["一犁足春雨，一絲摇晴風。", "樂此至樂地，其惟蓑笠翁。"]'),
('adb6a41c-9c9d-43ec-a080-ca63e6be6d3d','春詠','葉茵','宋','宋诗','song-poetry','','[]','舍瑟聲不傳，詠歸聲在道。',24,'全唐诗/poet.song.211000.json','["舍瑟聲不傳，詠歸聲在道。", "風乎野水濱，夕陽轉芳草。"]'),
('23b64e52-5762-4560-9de3-efaca9e9f833','見天地心','葉茵','宋','宋诗','song-poetry','','[]','百卉伏窮陰，一枝倚春色。',24,'全唐诗/poet.song.211000.json','["百卉伏窮陰，一枝倚春色。", "因易探真機，生意何曾息。"]'),
('5d16a083-6c0d-4d5d-ab86-311a24cef409','存方寸地','葉茵','宋','宋诗','song-poetry','','[]','客問燕山地，燕山地不多。',24,'全唐诗/poet.song.211000.json','["客問燕山地，燕山地不多。", "祗因解培植，桂子綠婆娑。"]'),
('08311f6a-191a-4e07-b632-833c517ca14a','翠波','葉茵','宋','宋诗','song-poetry','','[]','蕭疎拂行雲，清陰籠遠汀。',24,'全唐诗/poet.song.211000.json','["蕭疎拂行雲，清陰籠遠汀。", "水色元無色，相逢眼自青。"]'),
('ec508649-58d2-4460-968d-8aa0363100ea','皆春','葉茵','宋','宋诗','song-poetry','','[]','一氣融萬象，大哉造化仁。',24,'全唐诗/poet.song.211000.json','["一氣融萬象，大哉造化仁。", "自耕還自鑿，熙熙康衢民。"]'),
('9d59243a-8234-428b-a16b-7a0d46125edc','塵外','葉茵','宋','宋诗','song-poetry','','[]','自有此山扃，疑與浮世隔。',24,'全唐诗/poet.song.211000.json','["自有此山扃，疑與浮世隔。", "清風襲我裳，竹下有來客。"]'),
('60dfb52e-7093-4b3c-99bd-c401d2a8dae7','雲思','葉茵','宋','宋诗','song-poetry','','[]','交柯靉蒼寒，不礙青霄路。',24,'全唐诗/poet.song.211000.json','["交柯靉蒼寒，不礙青霄路。", "油然隠者心，一聲孤鶴度。"]'),
('1ecddef5-7ef9-4847-87b7-a4e9e58ca3a3','道院','葉茵','宋','宋诗','song-poetry','','[]','園林慳十畝，天賜老生涯。',48,'全唐诗/poet.song.211000.json','["園林慳十畝，天賜老生涯。", "雪境吟終夜，春時醉一家。", "籬疎簪菊種，石古絡藤花。", "莫有同盟者，多煎穀雨茶。"]'),
('ccc1a035-bfe2-44ad-8ebd-9370060ef8e7','舟中即事','葉茵','宋','宋诗','song-poetry','','[]','草舍密還稀，編籬枕釣磯。',48,'全唐诗/poet.song.211000.json','["草舍密還稀，編籬枕釣磯。", "鴨羣迎棹去，牛背曬衣歸。", "風緊浪千疊，村深柳四圍。", "倚檣無與語，數鴈失斜暉。"]'),
('13a20c04-122a-47f0-82db-c278e91662d2','新春','葉茵','宋','宋诗','song-poetry','','[]','老來分外喜新春，春事關心世事輕。',64,'全唐诗/poet.song.211000.json','["老來分外喜新春，春事關心世事輕。", "棋肯輸時方是著，路疑險處不須行。", "雨催農業鳩夫婦，風带邊聲鴈弟兄。", "辦得斗園鄰屋角，剩栽芝朮了餘生。"]'),
('26caf2de-0047-425b-aeec-e40a431a4f9f','嚴子陵','葉茵','宋','宋诗','song-poetry','','[]','怕被劉郎認故人，披裘釣澤隠餘生。',32,'全唐诗/poet.song.211000.json','["怕被劉郎認故人，披裘釣澤隠餘生。", "無端伸足龍牀上，多却嚴陵一姓名。"]'),
('5588b3c2-bd47-4347-99e4-c42e5e07ba1f','陶淵明','葉茵','宋','宋诗','song-poetry','','[]','喚得歸來是督郵，東籬千古占風流。',32,'全唐诗/poet.song.211000.json','["喚得歸來是督郵，東籬千古占風流。", "白衣未至秋蕭索，曾記公田種秫不。"]'),
('84fd2af9-2087-41f2-ab52-4a28784ef200','賈浪僊','葉茵','宋','宋诗','song-poetry','','[]','舉世知心獨有韓，爲何無髮强加冠。',32,'全唐诗/poet.song.211000.json','["舉世知心獨有韓，爲何無髮强加冠。", "若人了得推敲事，僧服儒衣一樣看。"]'),
('30d5e77c-7d0e-4bc9-ae08-1efe6fc27efc','孟東野','葉茵','宋','宋诗','song-poetry','','[]','出仕因詩忤長官，布衣時節更孤寒。',32,'全唐诗/poet.song.211000.json','["出仕因詩忤長官，布衣時節更孤寒。", "長安得意春風裏，百歲都來一日歡。"]'),
('0907f48a-0610-4ec4-bdd6-60cdbdc2e787','次韻','葉茵','宋','宋诗','song-poetry','','[]','舉世一枰棋，誰能著著奇。',48,'全唐诗/poet.song.211000.json','["舉世一枰棋，誰能著著奇。", "懶皆安樂法，醉即太平時。", "梅雨飛不斷，茶煙凝欲垂。", "吟詩爲無事，多事又因詩。"]'),
('ec08ee22-4247-4ebc-aefa-93d8b913cf52','天童山','葉茵','宋','宋诗','song-poetry','','[]','著足萬松關，東州第一山。',48,'全唐诗/poet.song.211000.json','["著足萬松關，東州第一山。", "聽泉窮地脈，歷棧近天顔。", "奎畫疎煙外，鐘聲遠樹間。", "衲翁曾有約，分我片時閒。"]'),
('cad7962e-0ab7-4c5e-9a62-40c2d277ed21','次守歲韻','葉茵','宋','宋诗','song-poetry','','[]','爆竹散千災，從今事事諧。',48,'全唐诗/poet.song.211000.json','["爆竹散千災，從今事事諧。", "五辛空䬦飣，六甲已安排。", "井貯屠蘇藥，庭輝榾柮柴。", "謾教添一歲，依舊好情懷。"]'),
('abea4872-8374-45f1-930e-d301aa1d24c4','道院偶成二首  其一','葉茵','宋','宋诗','song-poetry','','[]','水生遠岸拍蒲芽，春色駸駸染物華。',64,'全唐诗/poet.song.211000.json','["水生遠岸拍蒲芽，春色駸駸染物華。", "伎𠐒一詩安老草，眵昏兩眼眩空花。", "樓分古柳煙光薄，橋倚青帘日影斜。", "此樂未知誰可共，隔籬獨許釣魚家。"]'),
('c8b7ced8-784f-4ccc-b1ee-d6b5ab4c6aff','道院偶成二首  其二','葉茵','宋','宋诗','song-poetry','','[]','柳長柔絲草長芽，隨時委化答年華。',64,'全唐诗/poet.song.211000.json','["柳長柔絲草長芽，隨時委化答年華。", "呼來便了能酤酒，抱去添丁共看花。", "憂世中宵心耿耿，題春半壁字斜斜。", "江湖風月今猶昔，能學龜蒙有幾家。"]'),
('d563edc8-8ada-4561-a069-adcbae136068','次韻','葉茵','宋','宋诗','song-poetry','','[]','鬢邊驚雪點，腰下欠金圍。',48,'全唐诗/poet.song.211000.json','["鬢邊驚雪點，腰下欠金圍。", "已絕功名想，甘爲耕釣歸。", "浮生醒亦醉，往事是耶非。", "獨有樓前景，年年霞鶩飛。"]'),
('716760d8-4357-4b84-b043-20cd6f4616c6','二十里雲亭','葉茵','宋','宋诗','song-poetry','','[]','蔽空青不斷，杉徑影中行。',48,'全唐诗/poet.song.211000.json','["蔽空青不斷，杉徑影中行。", "僧指夜無月，客嫌春少晴。", "卧龍安舊窟，倦翼亂歸程。", "吟到長虹背，人間天上驚。"]'),
('1e5c5f56-2ab3-440f-be1e-c1b48e000534','田父吟五首  其一','葉茵','宋','宋诗','song-poetry','','[]','桃花深映水邊莊，夫婦相携笑語香。',32,'全唐诗/poet.song.211000.json','["桃花深映水邊莊，夫婦相携笑語香。", "耕耨有糧蠶有種，丁男戽水女條桑。"]'),
('52a2cec2-b453-4b22-98dd-2be9de1d0941','田父吟五首  其二','葉茵','宋','宋诗','song-poetry','','[]','家家柳色染輕黄，柳外歸鴉噪夕陽。',32,'全唐诗/poet.song.211000.json','["家家柳色染輕黄，柳外歸鴉噪夕陽。", "屋角有煙青不斷，粞兒飯熟淡齏香。"]'),
('96e90723-7887-4a2a-8103-bdf63e0c1088','田父吟五首  其三','葉茵','宋','宋诗','song-poetry','','[]','羣來野雀遶林梢，三五人家住水坳。',32,'全唐诗/poet.song.211000.json','["羣來野雀遶林梢，三五人家住水坳。", "翁媼語人年歲好，屋山添得一層茅。"]'),
('d465c658-35e8-423b-a8a9-0be0f2f44618','田父吟五首  其四','葉茵','宋','宋诗','song-poetry','','[]','未曉催車水滿溝，男兒鬼面婦蓬頭。',32,'全唐诗/poet.song.211000.json','["未曉催車水滿溝，男兒鬼面婦蓬頭。", "但求一熟償逋債，留得糠粞便不憂。"]'),
('ade4ddcc-d065-422b-9a23-50ec3da8d65c','田父吟五首  其五','葉茵','宋','宋诗','song-poetry','','[]','往來雞酒樂村村，一稔難忘大造恩。',32,'全唐诗/poet.song.211000.json','["往來雞酒樂村村，一稔難忘大造恩。", "糶穀可酬婚嫁願，今年好事屬柴門。"]'),
('31400f23-86c8-4698-b264-4a1df914158a','僧舍小泊','葉茵','宋','宋诗','song-poetry','','[]','屏息小胡牀，心魔已受降。',48,'全唐诗/poet.song.211000.json','["屏息小胡牀，心魔已受降。", "香留煙出戶，雲過雨來窗。", "自許參禪觀，誰能折慢幢。", "山童求說偈，竹影落寒江。"]'),
('b629e4a8-6e2b-4b1a-bfa6-ddaf9a36ddf2','雪','葉茵','宋','宋诗','song-poetry','','[]','春意滿庭除，紅塵半點無。',48,'全唐诗/poet.song.211000.json','["春意滿庭除，紅塵半點無。", "山川同變化，天地一模糊。", "石友聳冰骨，松公掀壽鬚。", "相望王子宅，不見夜篷孤。"]'),
('b8208081-e89b-4de5-b536-e8fcb6ff6b84','梅','葉茵','宋','宋诗','song-poetry','','[]','溪橋一樹玉精神，香色中間集大成。',64,'全唐诗/poet.song.211000.json','["溪橋一樹玉精神，香色中間集大成。", "疎影逼真前處士，羣花推重老先生。", "春回隴首人千里，月到窗前夢五更。", "甚欲折來還不忍，歲寒留取看崢嶸。"]'),
('5045bcec-bd26-4d9d-bc75-47ac5bc9b86c','次韻二首  其一','葉茵','宋','宋诗','song-poetry','','[]','幾載江湖兄弟心，老夫吟了聽君吟。',64,'全唐诗/poet.song.211000.json','["幾載江湖兄弟心，老夫吟了聽君吟。", "休論聚散時難易，要識推敲意淺深。", "晝靜牀頭便竹簡，風清牆角度松琴。", "山靈應是馳山檄，知向孤山何處尋。"]'),
('26b40a11-7a95-4a9b-ab01-3338069dce96','次韻二首  其二','葉茵','宋','宋诗','song-poetry','','[]','古貌如君更古心，艤舟來伴故人吟。',64,'全唐诗/poet.song.211000.json','["古貌如君更古心，艤舟來伴故人吟。", "十分酒醉憂時切，一點燈昏語夜深。", "半似畫圖經雨壁，不成宮徵亂風琴。", "箇中好辦栽梅計，勝友從教載月尋。"]'),
('4f592bf1-4fbe-4e15-aa81-0354e3a7d1eb','次得雨韻','葉茵','宋','宋诗','song-poetry','','[]','畎畝思國事，箋天淚成流。',72,'全唐诗/poet.song.211000.json','["畎畝思國事，箋天淚成流。", "鮮風鼓中夜，涷雨喧西疇。", "一飽將如願，卒歲應莫愁。", "料得廊廟心，猶懷溝壑憂。", "香燈答帝力，籉笠懸車頭。", "白首逢三登，酣歌娛春秋。"]'),
('c92f4773-5666-46f2-afde-c9e4099b67e4','次吳菊潭八月十四夜韻二首  其一','葉茵','宋','宋诗','song-poetry','','[]','來夕九秋半，月同心迹清。',48,'全唐诗/poet.song.211000.json','["來夕九秋半，月同心迹清。", "已知千里共，祇欠一分明。", "流水往來影，幽人今古情。", "撞鐘先得句，塵世不須驚。"]'),
('eba80e50-1aef-4e82-99e1-b9a259a1d043','次吳菊潭八月十四夜韻二首  其二','葉茵','宋','宋诗','song-poetry','','[]','月過市無聲，令人毛髮清。',48,'全唐诗/poet.song.211000.json','["月過市無聲，令人毛髮清。", "連村三鼓急，隔水一燈明。", "琢句醉時語，簪花老後情。", "凭欄發長嘯，不管卧龍驚。"]'),
('c96ebd97-bbff-4f46-a685-67457ea3c5d2','又','葉茵','宋','宋诗','song-poetry','','[]','昨雨轉今晴，晴新越樣清。',48,'全唐诗/poet.song.211000.json','["昨雨轉今晴，晴新越樣清。", "恐孤秋半賞，爲補夜來明。", "檢點有斜影，看承無異情。", "微吟樵唱句，猶恐鬼神驚。"]'),
('87ad51ff-7b0d-43cf-9134-1a32eb74a36f','喜義莊成','葉茵','宋','宋诗','song-poetry','','[]','以義名莊遺後昆，隠然文正典刑存。',64,'全唐诗/poet.song.211000.json','["以義名莊遺後昆，隠然文正典刑存。", "當知疎遠諸親族，同是高曾下子孫。", "先世家風傳不墜，廢祠香燼喜重溫。", "更能培植詩書種，忠孝他年萃一門。"]'),
('8596eb99-eca4-454d-acdb-fce6ecd8635c','多景樓','葉茵','宋','宋诗','song-poetry','','[]','北望中原慘莫煙，樓頭風物故依然。',64,'全唐诗/poet.song.211000.json','["北望中原慘莫煙，樓頭風物故依然。", "後人拍得闌干碎，往日輕教眼界偏。", "水撼金焦聲亦怒，雲連楚泗勢猶全。", "壯懷且付生前酒，千古英雄冢道邊。"]'),
('1874bb89-1ce8-4a88-b2ef-ae93e3532370','旅況','葉茵','宋','宋诗','song-poetry','','[]','未慣秋情緒，客中方覺難。',48,'全唐诗/poet.song.211000.json','["未慣秋情緒，客中方覺難。", "酒慳疏舊識，衣薄怯新寒。", "雨過浮雲濕，風來病葉乾。", "倚樓搔短鬢，一鴈掠闌干。"]'),
('101e6ec3-c5fe-473c-80f2-09afbb63761e','讀梅雪村詩','葉茵','宋','宋诗','song-poetry','','[]','雪村吟有稿，名峻斗牛低。',48,'全唐诗/poet.song.211000.json','["雪村吟有稿，名峻斗牛低。", "聲調唐之上，精神江以西。", "愛君憂國意，臨水傍山題。", "何代無風雅，人心自鶩鷄。"]'),
('af7db8db-ca19-4456-b5aa-df618e73fb8a','北窗','葉茵','宋','宋诗','song-poetry','','[]','八面玲瓏靜向陰，靜中時現定中身。',64,'全唐诗/poet.song.211000.json','["八面玲瓏靜向陰，靜中時現定中身。", "解傳佛祖從前意，便是羲皇向上人。", "背日一簷渾不暑，依山百卉若爲春。", "未逢惠遠相招致，厭殺浮生有劫塵。"]'),
('f8fcb02c-64b0-44fc-8318-946f67c5d6c4','桂謝','葉茵','宋','宋诗','song-poetry','','[]','廣寒世界放新晴，景物蕭疎八月深。',64,'全唐诗/poet.song.211000.json','["廣寒世界放新晴，景物蕭疎八月深。", "窗外方疑天雨粟，風前已見地流金。", "舉留清致爲詩助，收拾餘香付酒斟。", "但得僊根耐霜雪，不妨携囝步繁陰。"]'),
('bfe9ac9b-50a6-4ae7-9027-4a398ae82545','次禊帖韻','葉茵','宋','宋诗','song-poetry','','[]','梅花舊刻字將磨，勘辨其如病眼何。',64,'全唐诗/poet.song.211000.json','["梅花舊刻字將磨，勘辨其如病眼何。", "千載鼠鬚遺墨少，一時贋本誤人多。", "肯將金谷序文比，因想山陰氣候和。", "最喜孤居山下姥，慕名特特爲烹鵝。"]'),
('26d94b34-4e0b-4eb8-a057-f5c547f0d543','寄社友','葉茵','宋','宋诗','song-poetry','','[]','近來何事倦於吟，豈是因吟誤却身。',32,'全唐诗/poet.song.211000.json','["近來何事倦於吟，豈是因吟誤却身。", "此道自來多冷淡，郊寒島瘦少陵貧。"]'),
('eff953d6-e809-48de-b7d4-fd9f340d9e56','買魚','葉茵','宋','宋诗','song-poetry','','[]','柳線穿來網上魚，寬償所直辦朝厨。',32,'全唐诗/poet.song.211000.json','["柳線穿來網上魚，寬償所直辦朝厨。", "烹鮮不及爲親養，一笑分羹問二雛。"]'),
('e16fb1d8-18ad-41ed-b987-b1caecce3965','石佛','葉茵','宋','宋诗','song-poetry','','[]','一段無情作有情，如來相貌十分真。',32,'全唐诗/poet.song.211000.json','["一段無情作有情，如來相貌十分真。", "不因人世皆塵土，誰識山頭不壞身。"]'),
('0280bc1a-e4c9-4792-b88c-fe6556206663','僧舍偶成','葉茵','宋','宋诗','song-poetry','','[]','枝頭紅白亂飄零，又是風光入柳汀。',64,'全唐诗/poet.song.211000.json','["枝頭紅白亂飄零，又是風光入柳汀。", "自笑半生成草草，不知雙鬢已星星。", "貪吟爲有詩磨勘，戒飲從教酒勒停。", "旋學禪牀諸衲子，蒙頭相對一函經。"]'),
('624d6c2f-d60d-468f-989a-1d102fc3a04f','謝韓菊山道院詩','葉茵','宋','宋诗','song-poetry','','[]','正傳國子先生印，遠訪松陵隠士廬。',64,'全唐诗/poet.song.211000.json','["正傳國子先生印，遠訪松陵隠士廬。", "二十四篇風月句，幾千萬卷聖賢書。", "地偏自覺因人重，日涉從教與世疎。", "已戒園丁多種菊，重來對菊膾鱸魚。"]'),
('a1d9aa67-ae80-4cf3-ac0b-b993db0abc06','晚秋即事','葉茵','宋','宋诗','song-poetry','','[]','曳筇獨獨倚柴扉，翠潑西山漾落暉。',32,'全唐诗/poet.song.211000.json','["曳筇獨獨倚柴扉，翠潑西山漾落暉。", "衲子頂雲隨鴈遠，牧童腰笛挽牛歸。"]'),
('361d6770-ab2a-4a4f-87bc-9f93e05e9b19','晚梅','葉茵','宋','宋诗','song-poetry','','[]','錦樣桃花占曉晴，桃邊梅樹尚寒英。',32,'全唐诗/poet.song.211000.json','["錦樣桃花占曉晴，桃邊梅樹尚寒英。", "莫羞老大無顔色，自是前賢畏後生。"]'),
('07714dbf-a02b-4999-a7b5-fab30d866fae','友人見借放翁絕筆','葉茵','宋','宋诗','song-poetry','','[]','放翁今已矣，猶有未刊詩。',48,'全唐诗/poet.song.211000.json','["放翁今已矣，猶有未刊詩。", "閲稿無三豕，還書欠一鴟。", "聽兒弦誦罷，留客笑談時。", "發越吟邊思，心香答所知。"]'),
('e66e09f7-8f24-4268-8eeb-5a172cc9b6d3','水天一色亭上即事  其一','葉茵','宋','宋诗','song-poetry','','[]','芰荷深處小壺天，時見征帆破晚煙。',64,'全唐诗/poet.song.211000.json','["芰荷深處小壺天，時見征帆破晚煙。", "非主非賓和氣裏，似晴似雨綠陰邊。", "凭闌笑語驚魚鳥，信步遊行廢管絃。", "剩喜利名塵不到，持竿柳下問漁船。"]'),
('f665fbbe-26ca-4e2d-ae0f-23bfd1ff7052','水天一色亭上即事  其二','葉茵','宋','宋诗','song-poetry','','[]','得得尋幽到水天，開樽洗勺動庖煙。',64,'全唐诗/poet.song.211000.json','["得得尋幽到水天，開樽洗勺動庖煙。", "敗歡紅袖翻棋局，慣客烏衣拂坐邊。", "好景自應分半席，雅歌政不欠繁絃。", "黄昏未忍輕歸去，長笛一聲何處船。"]'),
('e7e25d09-4f58-4c40-9451-4f1ba104dfdc','遇風','葉茵','宋','宋诗','song-poetry','','[]','捲地沙塵撲面來，歸舟不進去帆飛。',32,'全唐诗/poet.song.211000.json','["捲地沙塵撲面來，歸舟不進去帆飛。", "世間何事無遲速，逆者由來順者機。"]'),
('a13afdf8-db8f-45b9-b4c3-a33f7e703ff8','次台州巾子山任翻韻','葉茵','宋','宋诗','song-poetry','','[]','天留勝處占清凉，山挾波光薄我裳。',32,'全唐诗/poet.song.211000.json','["天留勝處占清凉，山挾波光薄我裳。", "看遍塵寰興廢事，竹陰千古一禪房。"]'),
('971f7f17-7077-42a9-a9e7-7808a69b4c63','舟次','葉茵','宋','宋诗','song-poetry','','[]','輕舟小駐綠楊隄，載得閒雲過別溪。',32,'全唐诗/poet.song.211000.json','["輕舟小駐綠楊隄，載得閒雲過別溪。", "雲本無心天欲暮，一聲何處杜鵑啼。"]'),
('2c416fab-376f-4218-b091-8ca8b123eb1f','壽水竹弟','葉茵','宋','宋诗','song-poetry','','[]','人生真樂在家山，況有名園五畝寬。',64,'全唐诗/poet.song.211000.json','["人生真樂在家山，況有名園五畝寬。", "眼底不隨花富貴，水邊長報竹平安。", "養心澹泊千詩稿，種德蕃滋九畹蘭。", "以此壽君君必壽，年年新月照杯盤。"]'),
('eca5f051-2197-459e-bd36-2369ed78dd8a','秋夜','葉茵','宋','宋诗','song-poetry','','[]','秋滿讀書林，篝燈報夜深。',48,'全唐诗/poet.song.211000.json','["秋滿讀書林，篝燈報夜深。", "肯閒詩有趣，爲拙仕無心。", "驚鵲擇枝宿，幽蟬抱葉吟。", "未能游夢境，何處搗衣砧。"]');
